-- Poems batch 176
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('873cbb84-2c15-4f3a-b147-a3d575ec1c02','答叔剛見貽','孫應時','宋','宋诗','song-poetry','','[]','浪復辭家客鳳城，小樓春晝寫蘭亭。',64,'全唐诗/poet.song.172000.json','["浪復辭家客鳳城，小樓春晝寫蘭亭。", "從教佩印榮蘇子，豈爲鉏金動管寧。", "尚有故人同一笑，何妨時俗忌偏醒。", "君知濯濯東風柳，早晚飛花變綠萍。"]'),
('437a520b-2bcf-4538-8963-bf45922565f7','又答韵','孫應時','宋','宋诗','song-poetry','','[]','連陰漠漠鎖春寒，閒檢新年曆日看。',64,'全唐诗/poet.song.172000.json','["連陰漠漠鎖春寒，閒檢新年曆日看。", "節裏人言太幽獨，牀頭書喜報平安。", "山林决計應宜早，藜莧謀生未苦難。", "歸對妻孥真大笑，鮎魚元不解緣竿。"]'),
('2b94547c-d653-4711-b9d4-1d02bd465591','范叔剛以詩送豆粥次韵答之','孫應時','宋','宋诗','song-poetry','','[]','平生畫餠復炊沙，空有饑腸不受嗟。',64,'全唐诗/poet.song.172000.json','["平生畫餠復炊沙，空有饑腸不受嗟。", "多謝殷勤餉時節，頓忘憔悴客京華。", "賣書未卜來同往，厚意何時報有加。", "爲說癡人不堪飽，更思春酌對簷花。"]'),
('97c55188-2c0f-4df8-bf05-d21ba6fe8432','再答沙字韵','孫應時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','羊裘篛笠慣煙沙，强走塵埃合自嗟。',64,'全唐诗/poet.song.172000.json','["羊裘篛笠慣煙沙，强走塵埃合自嗟。", "幸有蠹魚供老醜，何勞汗馬戰紛華。", "情親過我談無底，語妙多君點不加。", "晴日西湖重載酒，梅梢應及未飄花。"]'),
('143f1962-3509-4ffc-988f-ace8135555bb','三用沙字韵簡叔剛','孫應時','宋','宋诗','song-poetry','','[]','雄心八駿騁流沙，猛氣千人廢咄嗟。',64,'全唐诗/poet.song.172000.json','["雄心八駿騁流沙，猛氣千人廢咄嗟。", "總有畫圖堪歎息，應無大藥駐容華。", "田園終勝爲形役，餐飯聊須努力加。", "此語非君誰舉似，夜闌清坐落燈花。"]'),
('fc758f5b-2883-4ac4-97a7-ed808f878ac2','避難至海陵從先流寓兄弟之招仍邂逅故人馮元禮二首之一','孫應時','宋','宋诗','song-poetry','','[]','脫身兵火欲何之，不料茲焉過所期。',64,'全唐诗/poet.song.172000.json','["脫身兵火欲何之，不料茲焉過所期。", "軒檻如僧縈橘柚，鄉關似夢識蒿藜。", "弟兄朋友談平昔，盜賊羌戎問幾時。", "共約更明王道正，或能一語到天墀。"]'),
('224dd336-1ef8-45d2-9a50-35c8c814d82e','答簡夫  其一','孫應時','宋','宋诗','song-poetry','','[]','不怪年來萬事非，聊須把酒賦新詩。',64,'全唐诗/poet.song.172000.json','["不怪年來萬事非，聊須把酒賦新詩。", "乾坤正自無今昔，草木何妨有變衰。", "白髮我甘投老去，紅顔君惜卧春時。", "古人不朽終何事，此段工夫可浪施。"]'),
('d2eecd23-505c-44e0-88ca-7e32af935a24','答簡夫  其二','孫應時','宋','宋诗','song-poetry','','[]','拂拭瑶琴聽我歌，湯湯三歎又峩峩。',64,'全唐诗/poet.song.172000.json','["拂拭瑶琴聽我歌，湯湯三歎又峩峩。", "了知世道從來久，長覺人心苦太多。", "便踏早朝陪鳳輦，更憂春夢隔鯨波。", "此生付與天公竟，鐵杵成針取次磨。"]'),
('b7964422-b6f9-4b2d-9e63-eb18b033cf1b','李簡夫知易用其父韵見貽且示和陶一編併和二章答之  其一','孫應時','宋','宋诗','song-poetry','','[]','晚矣歸來悟昨非，喜君先我和陶詩。',64,'全唐诗/poet.song.172000.json','["晚矣歸來悟昨非，喜君先我和陶詩。", "何嫌潦倒心長在，故想呻吟氣不衰。", "春日鶑啼花發處，秋空雲靜月明時。", "箇中差勝長安客，俯仰無寧似戚施。"]'),
('33fa1a55-1b43-4b06-a834-07c0e9a53d82','李簡夫知易用其父韵見貽且示和陶一編併和二章答之  其二','孫應時','宋','宋诗','song-poetry','','[]','閒中筆墨故相宜，遣興由來不厭詩。',64,'全唐诗/poet.song.172000.json','["閒中筆墨故相宜，遣興由來不厭詩。", "日仰慈顔長自愛，年方强仕莫言衰。", "新來定得安心法，此事還勝未病時。", "肯共切磋須我輩，獨無瓊玖報先施。"]'),
('787e354c-680d-425a-8a00-6c17e4255f19','師守之官枉駕過龍鵠省先公墓而去二詩送之  其一','孫應時','宋','宋诗','song-poetry','','[]','不向衡門把一杯，山中話別且徘徊。',64,'全唐诗/poet.song.172000.json','["不向衡門把一杯，山中話別且徘徊。", "嵐侵征帽晨疑雨，葉擁寒爐夜撥灰。", "路入西州空馬策，詩尋東閣正官第。", "感君得得同來意，回首行臺檄屢催。"]'),
('d9d2a6e2-de98-4ddf-bd0e-41a8172850c9','師守之官枉駕過龍鵠省先公墓而去二詩送之  其二','孫應時','宋','宋诗','song-poetry','','[]','遠道勤君屐齒迂，寄聲從此問何如。',64,'全唐诗/poet.song.172000.json','["遠道勤君屐齒迂，寄聲從此問何如。", "歸鴻不與斜陽盡，離恨還將落葉書。", "吏橫要須先縛虎，民勞切記莫驚魚。", "扶藜目送雙旌發，愁絕誰憐澗上居。"]'),
('7ae69a39-568c-4533-a01c-a6a996eadefb','寄別袁和叔','孫應時','宋','宋诗','song-poetry','','[]','風帆曉影動行裝，月淡芙蕖浦溆香。',64,'全唐诗/poet.song.172000.json','["風帆曉影動行裝，月淡芙蕖浦溆香。", "正想雙親開色笑，不須千里歎凄凉。", "隨行書卷生涯在，省事官曹氣味長。", "便爲君山問今古，一樽清嘯滿江鄉。"]'),
('7bb0d31e-bf19-4b49-bd6e-397b79df0598','遂安同官蔣主簿滿秩歸宜興相見杭都以詩別之','孫應時','宋','宋诗','song-poetry','','[]','溪閣小亭樂有餘，分携萬里意何如。',64,'全唐诗/poet.song.172000.json','["溪閣小亭樂有餘，分携萬里意何如。", "却憐倦鳥投林後，尚及棲鸞振翼初。", "髮白相看無可奈，眼青如舊未應疎。", "熟聞陽羨佳山水，會許扁舟問所居。"]'),
('23c9e397-0641-4c10-96a1-d538d198fbfe','寄江陰使君叔木叔','孫應時','宋','宋诗','song-poetry','','[]','一麾遥駐水雲間，聞說鈴齋盡日閒。',64,'全唐诗/poet.song.172000.json','["一麾遥駐水雲間，聞說鈴齋盡日閒。", "蝗似九江那敢近，珠於合浦定先還。", "天人影響從千古，賢哲功名正一斑。", "且續醉翁豐樂記，莫將風月負君山。"]'),
('aad33773-6b27-4ae4-b0d0-0a42ec109f59','寄史同叔開叔','孫應時','宋','宋诗','song-poetry','','[]','千頃東湖風月中，去年厭看藕花紅。',64,'全唐诗/poet.song.172000.json','["千頃東湖風月中，去年厭看藕花紅。", "可驚雲水將身遠，不得琴書與子同。", "四海人才尊一老，百年門戶到三公。", "傳家報國諸君事，心地勤收汗馬功。"]'),
('4a8cb2d4-3016-479f-b23d-046041034618','石莊臨大江望江陰君山懷淮陰尉用去年送行韵寄之','孫應時','宋','宋诗','song-poetry','','[]','日把文書揖上官，恐將心事負儒冠。',64,'全唐诗/poet.song.172000.json','["日把文書揖上官，恐將心事負儒冠。", "塵埃日月忙中度，學問工夫實處難。", "鶑谷已成經歲別，鷦巢且向一枝安。", "絕憐對眼江南北，不得君山並馬看。"]'),
('523304ce-ddb1-4c24-b6ad-b1026702fd24','和趙生唐卿師白韵遊橫溪','孫應時','宋','宋诗','song-poetry','','[]','野橋高竹轉修籬，問訊東風步屧隨。',64,'全唐诗/poet.song.172000.json','["野橋高竹轉修籬，問訊東風步屧隨。", "雨過天清水聲急，山長雲白鳥飛遲。", "從來丘壑多幽興，隨分風流到小詩。", "一榻煙霞須早計，莫教容易鬢成絲。"]'),
('e61aa17d-84c2-4d30-962d-62f9bb381abf','和曾舜卿少府','孫應時','宋','宋诗','song-poetry','','[]','心情老懶漫爲官，世路羊腸步步難。',64,'全唐诗/poet.song.172000.json','["心情老懶漫爲官，世路羊腸步步難。", "存我天真師櫟社，從渠官達夢槐安。", "晝眠竹簟風吹醒，夜釣羊裘雪洒乾。", "歸去元龍湖海士，白鷗盟在不應寒。"]'),
('326fce9e-aff4-4c5f-8cbd-b13dcb7e0060','和簡叔遊張園','孫應時','宋','宋诗','song-poetry','','[]','賦歸堂上憶春山，點筆題詩傍石欄。',64,'全唐诗/poet.song.172000.json','["賦歸堂上憶春山，點筆題詩傍石欄。", "老子如今已陳迹，故人誰與共追歡。", "青燈客舍一杯酒，細雨江城二月寒。", "多謝相過同太息，百年身世夢中看。"]'),
('b45f4564-4fd3-481e-ac6a-ab7205b68ea5','送袁和叔赴淮陰尉','孫應時','宋','宋诗','song-poetry','','[]','底事書生用一官，彊隨時樣著衣冠。',64,'全唐诗/poet.song.172000.json','["底事書生用一官，彊隨時樣著衣冠。", "千年蠹簡人情冷，百折羊腸世路難。", "未必功名欺老大，且憑書信報平安。", "秋風我亦淮東去，留取江山對眼看。"]'),
('300182b7-dde3-4adf-8b89-8e167ba05888','借韵跋林肅翁題詩','孫應時','宋','宋诗','song-poetry','','[]','昔冠南宮淡墨書，當年萬卷各名糊。',64,'全唐诗/poet.song.172000.json','["昔冠南宮淡墨書，當年萬卷各名糊。", "至今處子尚綽約，應笑老婆曾抹塗。", "詠慶雲圖如著色，和薰風句更從諛。", "行三十里余方悟，敢與楊脩校智愚。"]'),
('3a4d2c9f-a036-4e82-a8df-f24ae9d1c018','和項平父送別  其一','孫應時','宋','宋诗','song-poetry','','[]','逐逐衣冠謁府公，漸諳楚語異吳儂。',64,'全唐诗/poet.song.172000.json','["逐逐衣冠謁府公，漸諳楚語異吳儂。", "重江跋涉家何在，一飯辛勤計未工。", "自恐風塵成冗俗，人言山野欠疏通。", "夜長不寐思吾友，撥盡寒爐宿火紅。"]'),
('bed3bbcb-547c-4809-954a-67d5f8faf9ce','和項平父送別  其二','孫應時','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江風景舊聞知，雪裏經行亦大奇。',64,'全唐诗/poet.song.172000.json','["長江風景舊聞知，雪裏經行亦大奇。", "官舍荒凉乏松竹，邊城清晏少文移。", "有時懷古登臨久，自省無才職分卑。", "白日閉門還獨笑，讀書吾亦太營私。"]'),
('c3b0537b-dab3-4bd7-8e8a-21ea1ab8276d','和項平父送別  其三','孫應時','宋','宋诗','song-poetry','','[]','前途事業自登山，高下相懸進一關。',64,'全唐诗/poet.song.172000.json','["前途事業自登山，高下相懸進一關。", "莫倚陂陀能迤邐，可無尺寸怯躋攀。", "我來正作三年計，君別何當萬里還。", "辦取相逢須刮目，轉頭清鏡欲蒼顔。"]'),
('f06e1016-c865-4625-9f3c-d28c31f5a4ca','寄黄州錄事劉進之同年','孫應時','宋','宋诗','song-poetry','','[]','騎曹新上雪堂西，千里淮南望眼迷。',64,'全唐诗/poet.song.172000.json','["騎曹新上雪堂西，千里淮南望眼迷。", "正我尋雲並滄海，思君步月過黄泥。", "清時鼓角無驚夢，勝日樽罍有共携。", "人物風流對江浪，數將冰繭寄新題。"]'),
('a8b62b94-a215-40f3-adce-72445678739b','濡須道中','孫應時','宋','宋诗','song-poetry','','[]','睡足蓬窗江月明，濡須浦口片帆輕。',64,'全唐诗/poet.song.172000.json','["睡足蓬窗江月明，濡須浦口片帆輕。", "菰蒲兩岸長春水，楊柳一村啼曉鶑。", "休指山川問今古，且欣時節正蠶耕。", "白鷗容與滄波去，應識幽人萬里情。"]'),
('afb2497a-cf3f-4c2d-8db0-ab7d90159fe2','望建康諸山','孫應時','宋','宋诗','song-poetry','','[]','白沙城上望金陵，滿眼風煙草樹青。',64,'全唐诗/poet.song.172000.json','["白沙城上望金陵，滿眼風煙草樹青。", "山色千年圍故國，江流萬里赴滄溟。", "驚心采石瓜洲渡，搔首長干白下亭。", "一笑書生强多事，蕭蕭飛鴈落寒汀。"]'),
('30071e7e-5963-4ad9-a773-44ed088cde72','王子中使君家東澗脩竹','孫應時','宋','宋诗','song-poetry','','[]','一徑脩篁百畝深，倚天喬木更陰陰。',64,'全唐诗/poet.song.172000.json','["一徑脩篁百畝深，倚天喬木更陰陰。", "紅塵萬事不到眼，好景四時長會心。", "穩著亭臺添遠趣，透開風月自清音。", "使君晉宋家人物，消得閒中此醉吟。"]'),
('d21bf949-4bd3-408d-9f49-a90839ddae79','春日自警','孫應時','宋','宋诗','song-poetry','','[]','春風吹盡一川冰，野色山光弄晚晴。',64,'全唐诗/poet.song.172000.json','["春風吹盡一川冰，野色山光弄晚晴。", "節物榮枯能幾許，人生寒暑正堪驚。", "百圍松檜秋毫壯，千丈羅紈尺寸成。", "飽食安眠欲何用，徬徨終夜月華明。"]'),
('7cc2c296-9da4-469d-a178-96175c876d4c','和頂山前韵','孫應時','宋','宋诗','song-poetry','','[]','小山摇落故凄凉，想象登臨野興長。',64,'全唐诗/poet.song.172000.json','["小山摇落故凄凉，想象登臨野興長。", "萬里晴空初鴈入，一年好景又橙黄。", "極須痛飲償秋節，生怕疎鐘報夕陽。", "搔首故園歸未得，荒籬寒菊爲誰香。"]'),
('e25f20b0-915e-4c11-9fd0-593cf9efa706','和方與行韵','孫應時','宋','宋诗','song-poetry','','[]','千里家山且寄音，小窗孤坐息深深。',64,'全唐诗/poet.song.172000.json','["千里家山且寄音，小窗孤坐息深深。", "平生肯恃張儀舌，今日猶存趙武心。", "歲暮天寒休復問，夢回酒醒故難禁。", "梅梢春信知何似，驛使來時爲一尋。"]'),
('fafd2069-1ded-4761-8654-7bb7be89d7d0','與宋廏父昆弟唐升伯偕遊廬山','孫應時','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','征帆西過憶匆匆，咫尺匡廬悵望中。',64,'全唐诗/poet.song.172000.json','["征帆西過憶匆匆，咫尺匡廬悵望中。", "天意留爲今日計，春遊恰與故人同。", "酒醒月落行侵曉，雲斷風來翠滿空。", "識取廬山真面目，會來栽杏作仙翁。"]'),
('41308c3b-c63a-42fa-b4a0-5e51b965b13d','遣興','孫應時','宋','宋诗','song-poetry','','[]','乾坤納納幾郵亭，一舸飄然水上萍。',64,'全唐诗/poet.song.172000.json','["乾坤納納幾郵亭，一舸飄然水上萍。", "短髮判隨秋草白，雙眸剛爲好山青。", "新詩滿軸頻舒卷，薄酒盈樽自醉醒。", "世上功名亦何事，誰能愁損歎漂零。"]'),
('5f8f4d54-b5ba-42e1-90a6-744776b761e8','夜泊','孫應時','宋','宋诗','song-poetry','','[]','病暑迎秋苦恨遲，秋來喚起楚人悲。',64,'全唐诗/poet.song.172000.json','["病暑迎秋苦恨遲，秋來喚起楚人悲。", "一江風雨無眠夜，萬里關山獨往時。", "奉檄不知翻遠別，倚門應已念歸期。", "荻花楓葉添情緒，看得明朝兩鬢絲。"]'),
('927c34ef-b261-46be-887c-940d03051362','陪章荆州九日登高讌示坐中呈二帥','孫應時','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','龍山東畔細腰宮，荆蜀元戎一笑同。',64,'全唐诗/poet.song.172000.json','["龍山東畔細腰宮，荆蜀元戎一笑同。", "正復樓臺看戲馬，何妨絲管送飛鴻。", "紅萸黄菊年華裏，落木長江晚思中。", "下客無才敵嘲弄，聊須整帽向西風。"]'),
('2cfb031b-426e-4388-b90f-818d1a5108ed','章荆州再招宴渚宮重湖','孫應時','宋','宋诗','song-poetry','','[]','平生絳帳馬荆州，肯念天涯萬里舟。',64,'全唐诗/poet.song.172000.json','["平生絳帳馬荆州，肯念天涯萬里舟。", "百丈便從沙岸發，聯鑣還作渚宮游。", "芙蓉滿意留連客，橙橘隨時斷送秋。", "不惜重湖重一醉，明朝巴峽暮猿愁。"]'),
('2e82b9bf-0d88-477a-9012-d0118242c201','答任檢法  其一','孫應時','宋','宋诗','song-poetry','','[]','壯意當年隘九州，天涯今日倦孤游。',64,'全唐诗/poet.song.172000.json','["壯意當年隘九州，天涯今日倦孤游。", "空江水落魚龍夜，故國雲深鴻雁秋。", "惜把山川對幽獨，蹔須談笑作風流。", "知心歎絕任夫子，肯和巴歌爲解愁。"]'),
('c26ada42-5d17-483d-b22c-55f768784405','答任檢法  其二','孫應時','宋','宋诗','song-poetry','','[]','幕下清風十六州，德人胸次有天游。',64,'全唐诗/poet.song.172000.json','["幕下清風十六州，德人胸次有天游。", "偏將好句招詩社，不起爭心效弈秋。", "我拙蕢桴鳴土鼓，君賢玉瓚映黄流。", "蒼蒼雲海相期急，未用煩紆擬四愁。"]'),
('bdbbde89-4a9b-4ce0-8a76-2cd4252cb677','答任檢法  其三','孫應時','宋','宋诗','song-poetry','','[]','文字潮州更柳州，興來八表共神游。',64,'全唐诗/poet.song.172000.json','["文字潮州更柳州，興來八表共神游。", "驊騮隴阪長鳴日，鷹隼霜天得意秋。", "鼎鼎百年均昨夢，紛紛一世幾名流。", "爲君傾倒平生話，不作人間兒女愁。"]'),
('d3d2f6ab-13be-45aa-bf5c-c5933bfe8a6e','制司請都大會食','孫應時','宋','宋诗','song-poetry','','[]','繡衣人物冠諸臺，玉帳元戎萬里來。',64,'全唐诗/poet.song.172000.json','["繡衣人物冠諸臺，玉帳元戎萬里來。", "同爲西川增氣象，何妨北海試尊罍。", "休辭臈酒十分醉，要喚春風一夜回。", "天上德星何處聚，應從井絡向三台。"]'),
('6eeb9a19-e159-409e-90d7-19d47e4ef5c6','三游洞之外俯瞰峽江酷似釣臺','孫應時','宋','宋诗','song-poetry','','[]','木落天清嵐翠開，緩將脚力試崔嵬。',64,'全唐诗/poet.song.172000.json','["木落天清嵐翠開，緩將脚力試崔嵬。", "千年洞府煙霞外，一壑水聲風雨來。", "客路山川生白髮，古人名字剝蒼苔。", "平生感慨忘言地，俯見滄江憶釣臺。"]'),
('c04eca3f-e473-49a1-a9dc-2d2d12e9678f','冷副端與諸人九日登高有詩次韵  其一','孫應時','宋','宋诗','song-poetry','','[]','日薄天清山翠濃，西來萬里有清風。',64,'全唐诗/poet.song.172000.json','["日薄天清山翠濃，西來萬里有清風。", "十分秋色囂塵外，千古佳辰感慨中。", "雲隠蜃樓東海碧，江涵雁字夕陽紅。", "詩翁不負登高興，消得觥船一棹空。"]'),
('98c3e087-f016-45b4-94b7-d988acddfefa','冷副端與諸人九日登高有詩次韵  其二','孫應時','宋','宋诗','song-poetry','','[]','彭澤歸心似酒濃，蓴鱸嗟已負秋風。',64,'全唐诗/poet.song.172000.json','["彭澤歸心似酒濃，蓴鱸嗟已負秋風。", "文書雁鶩喧呼裏，尊俎江山夢寐中。", "採菊誰搴三徑綠，賜萸休想一枝紅。", "朝來快讀詩仙句，猶得塵衿一洗空。"]'),
('b74e6968-ac02-4518-af5e-5308b3aefcc4','雪中次甄雲卿監簿韵','孫應時','宋','宋诗','song-poetry','','[]','屋頭棲鵲夜深驚，羽衛瓊仙下紫清。',64,'全唐诗/poet.song.172000.json','["屋頭棲鵲夜深驚，羽衛瓊仙下紫清。", "羣玉殿開香未暖，六花陣合戰無聲。", "難教小草呈新翠，可恨疎梅半落英。", "卧病袁安自愁絕，履穿誰與問先生。"]'),
('b661ac3b-af17-4817-8fe9-c8c276c0de78','和甄雲卿詩  其一','孫應時','宋','宋诗','song-poetry','','[]','旰食延英責太平，小臣憂國思茫冥。',64,'全唐诗/poet.song.172000.json','["旰食延英責太平，小臣憂國思茫冥。", "千秋鑑在開元錄，十漸書留貞觀屏。", "莫笑戇愚如汲黯，無寧齷齪似陶青。", "何時再見東都會，萬國衣冠拱帝庭。"]'),
('d70f7ddd-ad29-4c57-9eb9-96df2461dd15','和甄雲卿詩  其二','孫應時','宋','宋诗','song-poetry','','[]','誰貪上黨誤長平，白日塵沙萬里冥。',64,'全唐诗/poet.song.172000.json','["誰貪上黨誤長平，白日塵沙萬里冥。", "死骨不應讎未雪，哀歌長覺氣如屏。", "經生未減公孫董，邊將何如去病青。", "安得君侯提八陣，春風犁徧漠南庭。"]'),
('2e8c5f29-4e2e-4909-847c-213782432fcb','寄高司戶','孫應時','宋','宋诗','song-poetry','','[]','一官何用落邊州，索漠風煙兩見秋。',64,'全唐诗/poet.song.172000.json','["一官何用落邊州，索漠風煙兩見秋。", "猶喜逢君結詩社，如何別我向糟丘。", "高懷誰與論醒醉，傑句能無憶唱酬。", "萬里雲開對明月，相思清興滿南樓。"]'),
('2423d8c7-caa1-4d68-8cdb-00e0f77189d4','送別袁公四詩  其一','孫應時','宋','宋诗','song-poetry','','[]','幾年靜鎮絕喧囂，百吏承風服教條。',64,'全唐诗/poet.song.172000.json','["幾年靜鎮絕喧囂，百吏承風服教條。", "惠養疲羸深保障，搜延英俊盛旌招。", "憂先儲粟千倉滿，威讋邊烽萬里消。", "已揭成規在藩屏，政須人望押班朝。"]'),
('231bec57-ff79-4b22-a53f-4bd58f19a1d3','送別袁公四詩  其二','孫應時','宋','宋诗','song-poetry','','[]','露門勸學首羣公，石室還來復古風。',64,'全唐诗/poet.song.172000.json','["露門勸學首羣公，石室還來復古風。", "垂世文章崔蔡右，濟時勳業管蕭中。", "持平願取乘舟勢，納約先看補衮功。", "力鞏皇圖知有道，先生心事與天通。"]'),
('23cbbc3d-2bc6-4e40-8ce2-739183b925a3','送別袁公四詩  其三','孫應時','宋','宋诗','song-poetry','','[]','絕代風流士駿奔，感公封植到孤根。',64,'全唐诗/poet.song.172000.json','["絕代風流士駿奔，感公封植到孤根。", "雲章假寵騰天路，寶畫分輝照蓽門。", "末學有心期卒業，不材無地可酬恩。", "從今禮數千官隔，知復何時奉一樽。"]'),
('d503e58b-5d6e-42aa-9f81-24fc6ff8dca1','送別袁公四詩  其四','孫應時','宋','宋诗','song-poetry','','[]','南風一夜漲痕吹，江岫排空送衮衣。',64,'全唐诗/poet.song.172000.json','["南風一夜漲痕吹，江岫排空送衮衣。", "萬里直愁知己遠，百年長恨此公稀。", "眼看蜀柂沙邊起，心逐吳雲峽外飛。", "流水高山有殊遇，此生何地不瞻依。"]'),
('e386f1c2-723e-495b-aff4-753858bf068c','爰亞夫自涪陵以小舟追路相送及予於櫪木觀下同至萬州遊岑公洞其歸也作七言送之','孫應時','宋','宋诗','song-poetry','','[]','不辭一舸下三州，送我能爲信宿留。',64,'全唐诗/poet.song.172000.json','["不辭一舸下三州，送我能爲信宿留。", "腹有琅玕元自潤，氣兼熊豹不妨遒。", "清尊近對江雲濕，烏帽高尋洞卉秋。", "莫負武夷當日語，幾披尺素淚橫流。"]'),
('c76a3053-f491-4c31-9a10-985fdfe09f1f','和真長送別','孫應時','宋','宋诗','song-poetry','','[]','吳市當年梅子真，不堪萬里久辭親。',64,'全唐诗/poet.song.172000.json','["吳市當年梅子真，不堪萬里久辭親。", "故無分寸酬知己，尚有平生不負人。", "錦里風光餘別恨，鏡湖雲水送閒身。", "感君戀戀勤相記，歲暮長途知苦辛。"]'),
('4401dd91-6251-498d-be19-1ab7cbe5244d','著作李季章得閬守去國以書道別追寄四韵','孫應時','宋','宋诗','song-poetry','','[]','不將塵土望清華，珍重高情久更加。',64,'全唐诗/poet.song.172000.json','["不將塵土望清華，珍重高情久更加。", "肯把書來話心曲，又從今去各天涯。", "一麾可是君恩薄，百丈休憐江路賒。", "歸見故人應一笑，爲傳消息報梅花。"]'),
('f208b542-0c58-45d2-9450-8ada6cac7d91','和曾舜卿','孫應時','宋','宋诗','song-poetry','','[]','晚風吹散雨垂垂，一榻蕭然枕獨欹。',64,'全唐诗/poet.song.172000.json','["晚風吹散雨垂垂，一榻蕭然枕獨欹。", "秋燕悄如當去客，夜蟲還是可憐時。", "我懷松菊歸難早，君趁蒓鱸喜可知。", "已歎曲高如白雪，更煩墨妙寫烏絲。"]'),
('a0f98e1a-d0df-442f-a6a9-b9c4efd74856','和簡叔','孫應時','宋','宋诗','song-poetry','','[]','乳燕鳴鳩惱醉眠，起臨芳草思芊綿。',64,'全唐诗/poet.song.172000.json','["乳燕鳴鳩惱醉眠，起臨芳草思芊綿。", "花殘柳暗春歸日，雲薄風輕雨後天。", "酒戶已緣愁頓減，詩壇寧復勇爭先。", "只因歸老漁樵舍，不夢佳人玳瑁筵。"]'),
('a7bbc1dc-b514-4d9e-b0c1-3c4477839923','和答胡用之','孫應時','宋','宋诗','song-poetry','','[]','浪喜功名少壯時，髮今種種更奚爲。',64,'全唐诗/poet.song.172000.json','["浪喜功名少壯時，髮今種種更奚爲。", "窮通信我心如鐵，謗譽從渠口勝碑。", "息駕便應追靖節，弄絃寧復待鍾期。", "燭湖孤嶼烟波上，他日重過細說詩。"]'),
('db4e47c4-b011-412a-a5c6-b1d18bc27883','和答吳斗南賞木芙蓉見懷','孫應時','宋','宋诗','song-poetry','','[]','曾向荆州一笑同，淋漓江漢酒千鍾。',64,'全唐诗/poet.song.172000.json','["曾向荆州一笑同，淋漓江漢酒千鍾。", "夾城雲蓋迎珠履，滿眼霜花照玉容。", "萬里壯遊前日事，十年此會幾時重。", "憶君席上多新作，醉筆如飛紙不供。"]'),
('3766d35a-51b0-4323-9f98-6fb2b9ba10b4','和答吳斗南見寄解其自疑之意','孫應時','宋','宋诗','song-poetry','','[]','白狗黄牛繫纜時，東歸應念我西悲。',64,'全唐诗/poet.song.172000.json','["白狗黄牛繫纜時，東歸應念我西悲。", "置之偶爾何須道，去矣飄然故一奇。", "末路人情隨手別，丈夫心事有天知。", "君看子濯平生友，可把逢蒙待庾斯。"]'),
('312a485c-ec0a-4210-9f1a-56efc4359940','和答葉無咎','孫應時','宋','宋诗','song-poetry','','[]','百年一夢欲誰何，底事容心强揣摩。',64,'全唐诗/poet.song.172000.json','["百年一夢欲誰何，底事容心强揣摩。", "便續淵明歸去引，不題工部醉時歌。", "故山已恐鶴相怨，陋巷何妨雀可羅。", "多謝詩仙喚愁醒，簿書叢裏少婆娑。"]'),
('9930ba47-3eea-4974-b144-3359367edfaa','再和','孫應時','宋','宋诗','song-poetry','','[]','此生只合飲無何，懶讀丹經學按摩。',64,'全唐诗/poet.song.172000.json','["此生只合飲無何，懶讀丹經學按摩。", "得失塞翁無定在，濁清漁父有遺歌。", "蛟龍快意生雲雨，魚鳥全身避網羅。", "萬事忘言君會否，月明來共舞婆娑。"]'),
('19d29b4a-1cdb-4034-9311-e6c7c050a790','和次山見寄','孫應時','宋','宋诗','song-poetry','','[]','啼鴂匆匆又一春，別來知我更思君。',64,'全唐诗/poet.song.172000.json','["啼鴂匆匆又一春，別來知我更思君。", "畧無天氣花時雨，長遣人愁日暮雲。", "手自愛彈招隠曲，心知不作送窮文。", "秋風魚蟹松江上，重約論詩醉夜分。"]'),
('9f3b7839-cf97-4736-b9a0-cbd9dade9e05','和吳斗南','孫應時','宋','宋诗','song-poetry','','[]','高帆欲發意遲遲，回首飛雲耿夢思。',64,'全唐诗/poet.song.172000.json','["高帆欲發意遲遲，回首飛雲耿夢思。", "風壤江山吳蜀道，功名人物漢唐碑。", "無憑久厭書生語，有意聊觀天下奇。", "已决明年徑歸隠，好凉還得共驅馳。"]'),
('2d82b741-1178-44c2-8484-00bce68adf81','出沌復見江山和斗南','孫應時','宋','宋诗','song-poetry','','[]','底事江山照眼新，爲從雲夢別經旬。',64,'全唐诗/poet.song.172000.json','["底事江山照眼新，爲從雲夢別經旬。", "行吟沌口三家市，笑作天涯萬里人。", "清夜論心真得友，白雲迴首奈思親。", "船頭又報荆州近，魚雁書來未易頻。"]'),
('db310f68-7148-40b4-9e0a-bf93a31eee92','和師文','孫應時','宋','宋诗','song-poetry','','[]','筆端陶謝不枝梧，朝食千龍信手屠。',64,'全唐诗/poet.song.172000.json','["筆端陶謝不枝梧，朝食千龍信手屠。", "天與詩人清氣骨，家傳前輩學工夫。", "從渠擾擾一丘貉，看我昂昂千里駒。", "已喜朝廷似元祐，去依日月上天衢。"]'),
('a41b7d9b-7240-40d8-9c0e-881a8be19c55','漢州房公湖','孫應時','宋','宋诗','song-poetry','','[]','陰陰老木匝平湖，想見房公用意初。',64,'全唐诗/poet.song.172000.json','["陰陰老木匝平湖，想見房公用意初。", "眼底園池那有此，胸中丘壑故須渠。", "風流正自能傳世，成敗應難盡信書。", "萬里茲遊銷客恨，不辭一賞醉春餘。"]'),
('1ef36e0a-a968-4fd1-9fda-2a9a3bcff42b','遊凌雲峰答陳同年韵','孫應時','宋','宋诗','song-poetry','','[]','行行欲盡劍南州，滿意凌雲九頂游。',64,'全唐诗/poet.song.172000.json','["行行欲盡劍南州，滿意凌雲九頂游。", "樽俎樓臺一長嘯，江山風月幾清秋。", "古人勝賞分明在，灘水悲鳴日夜流。", "萬里重來渺難必，扁舟去住總成愁。"]'),
('1e6c8370-c0c5-4bd9-a58f-ceb055d39220','再答陳同年游字韵紀龍巖之集','孫應時','宋','宋诗','song-poetry','','[]','凌雲勝槩壓西州，又作龍泓盡日游。',64,'全唐诗/poet.song.172000.json','["凌雲勝槩壓西州，又作龍泓盡日游。", "數樹寒梅香較晚，一坡修竹意藏秋。", "酒間健筆能千字，胸次圓機綜九流。", "人境雙清定難得，相從何處有羈愁。"]'),
('c8f68d02-64bf-4a90-9a2b-caaaeb66aca4','發嘉州答張倅用前韵','孫應時','宋','宋诗','song-poetry','','[]','主人今代岑嘉州，倦客當年馬少游。',64,'全唐诗/poet.song.172000.json','["主人今代岑嘉州，倦客當年馬少游。", "即是孤帆行萬里，空懷一日過三秋。", "酒邊風味春生坐，筆底詞源峽倒流。", "浪有梅花煩驛使，轉頭陳迹遣人愁。"]'),
('8960197f-2b2a-40d3-9df8-b98a5f754e01','益昌夜泊','孫應時','宋','宋诗','song-poetry','','[]','孤舟了不夢邯鄲，起凭闌干煙水閒。',64,'全唐诗/poet.song.172000.json','["孤舟了不夢邯鄲，起凭闌干煙水閒。", "五夜清風鳴鼓角，一天佳月悄江山。", "客身憔悴衣塵黑，世路崎嶇鬢髮斑。", "未决乘流便東下，明朝且復劍門關。"]'),
('b8e6135d-327c-47c2-b241-b34cbcbe64d6','自興州浮嘉陵還益昌','孫應時','宋','宋诗','song-poetry','','[]','夜促清觴醉武興，曉飛輕舸下嘉陵。',64,'全唐诗/poet.song.172000.json','["夜促清觴醉武興，曉飛輕舸下嘉陵。", "平生海上漁樵子，此日天涯雲水僧。", "萬里身心縈老母，一年書札負交朋。", "秋風已定蓴鱸約，俛仰茲游記昔曾。"]'),
('2c47d34a-9ebd-455e-9caf-805199d4ba92','還成都','孫應時','宋','宋诗','song-poetry','','[]','匹馬關山不自憐，歸來巾几更蕭然。',64,'全唐诗/poet.song.172000.json','["匹馬關山不自憐，歸來巾几更蕭然。", "劍門南北等爲客，木偶東西聊聽天。", "未省繁華寬旅思，可將犇走負流年。", "夜凉早夢秋風起，催上山陰萬里船。"]'),
('49715d9d-0499-473a-8271-8923de54d2e5','題籌筆驛武侯祠','孫應時','宋','宋诗','song-poetry','','[]','北出當年此運籌，悠然欹卧與神謀。',64,'全唐诗/poet.song.172000.json','["北出當年此運籌，悠然欹卧與神謀。", "三軍節制馴貔虎，千里餱糧捷馬牛。", "漢業興亡惟我在，蜀山重複遣人愁。", "驛前風景應如舊，江水無情日夜流。"]'),
('3fe33fb7-aa4c-4deb-a283-8af2b35af590','又謁武侯祠','孫應時','宋','宋诗','song-poetry','','[]','城南風景故堪憐，勝日經行意灑然。',64,'全唐诗/poet.song.172000.json','["城南風景故堪憐，勝日經行意灑然。", "江上竹寒偏却暑，廟前柏老尚參天。", "堂堂不朽能千古，鼎鼎何能漫百年。", "醉裏狂歌心浩蕩，爲君一吸倒觥船。"]'),
('ab0663ad-62d2-4e8d-89d6-710e41b8ffdd','辭武侯廟','孫應時','宋','宋诗','song-poetry','','[]','三分遺論久難明，獨有河汾與杜陵。',64,'全唐诗/poet.song.172000.json','["三分遺論久難明，獨有河汾與杜陵。", "工拙人休計曹馬，興亡天亦恨桓靈。", "大星忍向中宵落，老柏空餘千載青。", "再拜征途重迴首，雪風吹斷淚成冰。"]'),
('b77044ad-ff24-4e7e-a639-346cbb865bed','倦游書事','孫應時','宋','宋诗','song-poetry','','[]','隻影千山復萬山，兩年愁著鬢毛班。',64,'全唐诗/poet.song.172000.json','["隻影千山復萬山，兩年愁著鬢毛班。", "壯心未答吳鈎贈，素節聊全趙璧還。", "劍棧風煙通紫塞，峽天雲雪带烏蠻。", "逢人若問渾慵答，閉目搘頤一夢間。"]'),
('e600df82-a0e7-48c4-99a3-6bd2a260dbfc','江上作','孫應時','宋','宋诗','song-poetry','','[]','不羞燭影照蒼波，獨向江頭步綠莎。',64,'全唐诗/poet.song.172000.json','["不羞燭影照蒼波，獨向江頭步綠莎。", "歷歷風煙行地闊，冥冥雲海得天多。", "沙晴百網收漁市，山晚千帆殷棹歌。", "約取清秋弄明月，一尊重欲酹東坡。"]'),
('b9da6a2d-9a6c-425a-96f9-cadb64754fa4','答劍門朱宰和益昌夜泊韵','孫應時','宋','宋诗','song-poetry','','[]','好辭絕妙過邯鄲，開卷清風起坐間。',64,'全唐诗/poet.song.172000.json','["好辭絕妙過邯鄲，開卷清風起坐間。", "想見襟懷濯冰雪，如聞吟嘯滿雲山。", "離亭劍閣千峰碧，歸夢萊衣五彩斑。", "尊酒相逢更何許，秋帆迴首下牢關。"]'),
('932470dd-2feb-485e-a92f-5201c7049f6b','答俞履道見贈','孫應時','宋','宋诗','song-poetry','','[]','黄塵車馬日紛囂，萬事春冰過眼消。',64,'全唐诗/poet.song.172000.json','["黄塵車馬日紛囂，萬事春冰過眼消。", "頼有諸公扶正氣，猶令千載見英標。", "多君吐論心奇壯，顧我凋年齒動摇。", "好待明堂採梁棟，勿誇翹楚向薪樵。"]'),
('f4f12561-69a3-4225-845f-c8529320ec47','答成都虞子韶鈐幹寄書信兼示近作','孫應時','宋','宋诗','song-poetry','','[]','珍重西來雙鯉魚，更傳佳句起愁予。',64,'全唐诗/poet.song.172000.json','["珍重西來雙鯉魚，更傳佳句起愁予。", "相思已是五年別，多媿先無一字書。", "欲話錦城疑是夢，誰憐霜鬢不禁梳。", "青氈黄閤君侯事，早擬相逢倘下車。"]'),
('66b13c63-bd91-4f70-9d1f-f30a0f2c72c9','和答趙生師白見寄  其一','孫應時','宋','宋诗','song-poetry','','[]','休論吾昔與吾今，窗下婆娑有學林。',64,'全唐诗/poet.song.172000.json','["休論吾昔與吾今，窗下婆娑有學林。", "會意書非求甚解，無絃琴豈要知音。", "是中截斷談天口，何處尋來立雪心。", "永日春風鶑百囀，幽人踵息正深深。"]'),
('718c57f1-bec7-41c9-9384-cb4528e1a5e7','和答趙生師白見寄  其二','孫應時','宋','宋诗','song-poetry','','[]','田可躬耕溪可漁，此身屬我不關渠。',64,'全唐诗/poet.song.172000.json','["田可躬耕溪可漁，此身屬我不關渠。", "養生誰學嵇中散，避謗吾非陸敬輿。", "風月滿懷高士傳，江山到眼故人書。", "相思千里無多恨，珍重清詩玉不如。"]'),
('ee3bbee6-393f-4629-9742-8295205b3b54','和胡仲方撫幹白瑞香及黄櫞韵','孫應時','宋','宋诗','song-poetry','','[]','翠錦熏籠白玉花，幾年廬阜飽煙霞。',64,'全唐诗/poet.song.172000.json','["翠錦熏籠白玉花，幾年廬阜飽煙霞。", "定知姑射同肌骨，何必離騷借齒牙。", "心事早陪三友約，國香今壓五侯家。", "主人封植無多費，賸乞盧仝七椀茶。"]'),
('6147223b-91ce-434d-9283-8f5b05a222f8','聞南軒張先生下世感惋有作  其一','孫應時','宋','宋诗','song-poetry','','[]','玉山已失舊端明，何事令人骨屢驚。',64,'全唐诗/poet.song.172000.json','["玉山已失舊端明，何事令人骨屢驚。", "拆石有聲傳建業，隕星無處弔南荆。", "春風未作山川暖，江水何心日夜傾。", "淚落中宵腸萬結，眇然湖海寄吾生。"]'),
('6e69626a-62f6-4a57-9a5c-533d4f344cab','聞南軒張先生下世感惋有作  其二','孫應時','宋','宋诗','song-poetry','','[]','中原天意定何如，豈謂人才不素儲。',64,'全唐诗/poet.song.172000.json','["中原天意定何如，豈謂人才不素儲。", "前輩老成今殄瘁，丁年豪雋重蕭疎。", "武侯歲晚出師表，賈誼平生流涕書。", "社稷無疆恩澤厚，小臣何敢議盈虛。"]'),
('80722b1e-9c37-464d-80b7-baf4920d1517','偶題','孫應時','宋','宋诗','song-poetry','','[]','困雖有舌吾安用，貧到無錐樂更深。',64,'全唐诗/poet.song.172000.json','["困雖有舌吾安用，貧到無錐樂更深。", "百歲難逃少壯老，多思何益去來今。", "弈秋豈必長先手，畫史誰知獨苦心。", "一枕春宵方化蝶，三竿朝日又鳴禽。"]'),
('b24410f1-e6f8-4e01-ace2-6e1f65bc870c','偶成','孫應時','宋','宋诗','song-poetry','','[]','小齋隨分有琴書，此外蕭然一物無。',64,'全唐诗/poet.song.172000.json','["小齋隨分有琴書，此外蕭然一物無。", "地僻最饒閒意味，日長還得睡工夫。", "四時風月吾心友，千里雲山古畫圖。", "天賜綵衣娛鶴髮，簞瓢足矣更何須。"]'),
('6b60c926-7078-4748-b0b7-0a0a2a58a1ee','山菴感舊','孫應時','宋','宋诗','song-poetry','','[]','短橋橫澗有精廬，儼立蒼髯六丈夫。',64,'全唐诗/poet.song.172000.json','["短橋橫澗有精廬，儼立蒼髯六丈夫。", "長憶兒時弄泉石，誰令學宦走江湖。", "泠風試作琴三疊，涼月還須酒一壺。", "杖屢無忘數來往，不妨樵路小崎嶇。"]'),
('eabc41f3-b867-4e72-afc5-ae454fba939f','姪孫詩','孫應時','宋','宋诗','song-poetry','','[]','壽母重孫始見渠，天教四世保同居。',64,'全唐诗/poet.song.172000.json','["壽母重孫始見渠，天教四世保同居。", "精神已是千金子，事業應須萬卷書。", "親戚滿前非落寞，杯盤隨分不蕭疎。", "晬盤先攬文房寶，他日無憂入異閭。"]'),
('ded7c5f1-f341-42ee-9102-571142e3a150','妻兄張伯高來訪橫河感舊與拜先君墓下有作次韵  其一','孫應時','宋','宋诗','song-poetry','','[]','衰年回首少年事，尚喜初心炯自如。',64,'全唐诗/poet.song.172000.json','["衰年回首少年事，尚喜初心炯自如。", "俗態可憐人厚薄，交情那問勢親疎。", "懶陪康樂登山屐，且醉淵明採菊廬。", "一笑相尋非易得，河渠執手更踟躕。"]'),
('62bfbd64-4ce5-46b0-976a-360ba4a70503','妻兄張伯高來訪橫河感舊與拜先君墓下有作次韵  其二','孫應時','宋','宋诗','song-poetry','','[]','蓽門生計只初年，喬嶽終難起一拳。',64,'全唐诗/poet.song.172000.json','["蓽門生計只初年，喬嶽終難起一拳。", "小檻清風黄卷裏，扁舟碧水白鷗前。", "同尋杖屨曾行處，肯謁松楸獨泫然。", "人事無窮今幾變，空山落日自孤煙。"]'),
('e0224793-930e-4f1c-a319-c0809b05eac9','母氏生日','孫應時','宋','宋诗','song-poetry','','[]','兩年萬里望飛雲，慚媿慈親費倚門。',64,'全唐诗/poet.song.172000.json','["兩年萬里望飛雲，慚媿慈親費倚門。", "好在蘭陔扶白髮，依然梅蘂照清樽。", "斑衣願保長稱壽，石窌仍看疊拜恩。", "更問何時足懷抱，詵詵玉雪弄重孫。"]'),
('cc32740b-638d-46af-b386-b4f60012f037','臘月初七日夜夢游山林間清甚賦詩半就覺而忘之追成八句','孫應時','宋','宋诗','song-poetry','','[]','杜門終歲少過從，一室蕭然百念空。',64,'全唐诗/poet.song.172000.json','["杜門終歲少過從，一室蕭然百念空。", "紙上陳言皆妙用，胸中餘味有新功。", "搘筇飽看千山月，欹枕閒聽萬竅風。", "麤飯濁醪能送日，蒼顔白髮任成翁。"]'),
('493e04b4-6116-4690-b6e3-2ff8fbf3cb35','夢蜀中一山寺曰龍塘有龍祠余似嘗屢游也題詩別之未足兩句而寤因足成之','孫應時','宋','宋诗','song-poetry','','[]','客遊幾度到龍塘，沙路縈紆草木香。',64,'全唐诗/poet.song.172000.json','["客遊幾度到龍塘，沙路縈紆草木香。", "雪後江山餘壯觀，秋來樓閣記新凉。", "百年此役何時再，萬里東歸託興長。", "風景留人重迴首，猶須好句與平章。"]'),
('5989b6a1-3f2b-4dfb-b15c-13df5ffa9b6f','余生日具杯酒爲母壽思壬子歲在荆州癸丑歲在成都諸公爲余作盛集而余意不適也','孫應時','宋','宋诗','song-poetry','','[]','兩年荆益度茲晨，羅綺傳觴苦勸人。',64,'全唐诗/poet.song.172000.json','["兩年荆益度茲晨，羅綺傳觴苦勸人。", "多謝諸公憐遠客，豈如一笑奉吾親。", "蓴鱸此日無餘恨，菽水從前得諱貧。", "快倒村醪供壽斚，也分湯餠及比鄰。"]'),
('0361dff7-c577-4b1e-a17b-aa61c6bf09d9','母氏生日陰晴晏溫夜後雖小雨或作或止而帖然不風諸老人皆不須設火若前一夕則甚雨次夕則雨且風寒真若有相之者感愧有作','孫應時','宋','宋诗','song-poetry','','[]','草草稱觴壽我親，每慚天意俯從人。',64,'全唐诗/poet.song.172000.json','["草草稱觴壽我親，每慚天意俯從人。", "連宵又似去年雨，淑景偏回此日春。", "富貴何如長得健，詩書元自不羞貧。", "秫田五畝猶堪釀，願作堯天百歲民。"]'),
('e67535b2-44d4-4519-bd63-82e96cf05d5f','上史魏公壽三首  其一','孫應時','宋','宋诗','song-poetry','','[]','清都絳闕拱慈皇，鶴駕雞鳴起未央。',64,'全唐诗/poet.song.172000.json','["清都絳闕拱慈皇，鶴駕雞鳴起未央。", "父子至情如一日，國家慶事冠前王。", "公功實作風雲舊，帝學于今日月光。", "天壽兩宮千萬歲，端留元老贊明昌。"]'),
('578f1bb0-6591-473f-9fb9-e985a003f829','上史魏公壽三首  其二','孫應時','宋','宋诗','song-poetry','','[]','中興大業要規模，公有初言久未孚。',64,'全唐诗/poet.song.172000.json','["中興大業要規模，公有初言久未孚。", "已喜乾坤深佑德，况逢歲月正懸弧。", "明時禮數尊三事，大老精神壓萬夫。", "軍國平章天下望，鷹揚年德正相符。"]'),
('20806d77-59cc-4da7-8719-42661839bb85','上史魏公壽三首  其三','孫應時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','中書考已敵汾陽，神氣清明骨更强。',64,'全唐诗/poet.song.172000.json','["中書考已敵汾陽，神氣清明骨更强。", "客倒壺觴弄風月，酒闌燈火事文章。", "傳家正有書千卷，積慶真成笏一床。", "看取西湖共長久，年年菊會答秋光。"]'),
('d89dc938-7de1-4adf-bf61-3c6fea539093','母氏生朝會同官','孫應時','宋','宋诗','song-poetry','','[]','樂回和氣作春溫，香裊祥雲映酒尊。',64,'全唐诗/poet.song.172000.json','["樂回和氣作春溫，香裊祥雲映酒尊。", "盛事同官皆有母，可人今歲喜生孫。", "一杯首奉吾親壽，百拜心知造物恩。", "看取朱顔長不老，年年賓客醉盈門。"]'),
('822a45e5-9112-4c26-bca5-bf7695b8deb9','泛東湖風浪作復止','孫應時','宋','宋诗','song-poetry','','[]','萬頃重湖東復東，意行得怕打頭風。',64,'全唐诗/poet.song.172000.json','["萬頃重湖東復東，意行得怕打頭風。", "故畦遺穗粼粼在，野水寒林處處通。", "鴻雁汀洲渺葭葦，牛羊籬落見兒童。", "衣冠塵土空頭白，慚愧扁舟把釣翁。"]'),
('65135dd4-5050-43ac-af82-2fef596aabea','五月末如鄞舟中戲作','孫應時','宋','宋诗','song-poetry','','[]','七年不聽丈亭潮，夢覺依然枕動摇。',64,'全唐诗/poet.song.172000.json','["七年不聽丈亭潮，夢覺依然枕動摇。", "趁得晨鐘上西渡，不妨野飯向高橋。", "今年天故饒梅雨，是處人言好稻苗。", "慚愧鄞山最青眼，回環翠色總相招。"]'),
('12c531d1-27eb-4e2d-82a6-50a0153fb75c','閏十月十日自鄞城同史子應如東湖宿月波寺','孫應時','宋','宋诗','song-poetry','','[]','不到東湖便十年，短篷還得泛霜天。',64,'全唐诗/poet.song.172000.json','["不到東湖便十年，短篷還得泛霜天。", "千林脫葉風如剪，萬里無雲月滿弦。", "照影婆娑吾老矣，可人瀟灑故依然。", "敲門款語僧窗夜，挑盡寒燈久不眠。"]'),
('c814f800-2cea-4c7d-a548-3d310ebd3c53','杭都旅舍臘日感事','孫應時','宋','宋诗','song-poetry','','[]','三年臘日常爲客，愁絕梅花獨自看。',64,'全唐诗/poet.song.172000.json','["三年臘日常爲客，愁絕梅花獨自看。", "萬里塵沙走西蜀，九衢風雪卧長安。", "生來可是儒冠誤，老去偏知世路難。", "安得長閒伴溪叟，醉歌時掣釣魚竿。"]'),
('c41e7fde-9d16-443e-b3c1-fd7b54503433','西湖','孫應時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十年身不到西湖，把酒臨風省故吾。',64,'全唐诗/poet.song.172000.json','["十年身不到西湖，把酒臨風省故吾。", "萬里山川發天巧，三朝宮苑富皇都。", "溪橋無處尋君復，詩帳令人憶大蘇。", "尚許蕭然塵外客，小舟終日卧冰壺。"]'),
('d38858d2-2f13-433f-a7a8-85233c681ae2','舟自震澤道吳興城外有感','孫應時','宋','宋诗','song-poetry','','[]','憶向苕溪泊酒船，寧知綠髮便華顛。',64,'全唐诗/poet.song.172000.json','["憶向苕溪泊酒船，寧知綠髮便華顛。", "只今行脚一萬里，重此驚心二十年。", "箬笠簑衣真我事，清風明月苦論錢。", "晚凉急櫂城南去，更復題詩作後緣。"]'),
('c4eccb57-ad5d-4d3d-afc1-6f04d0f94ba2','隨鳬巖瀑布','孫應時','宋','宋诗','song-poetry','','[]','高山流水去沉沉，迸落長屏百仞深。',64,'全唐诗/poet.song.172000.json','["高山流水去沉沉，迸落長屏百仞深。", "暗有衝風起崖腹，散成飛雨到潭心。", "梯空直下知無計，攀木旁窺戰不禁。", "好著孤亭巧相對，重來應得慰登臨。"]'),
('db9647bb-3061-4328-b7a4-a58237574576','崑山龔立道作棲閑堂取李太白題龔處士別墅詩曰龔子棲閑地都無人世喧故以爲名嘗託范叔剛求詩於予予許之閏八月十九日立道復自以書來爲成八句','孫應時','宋','宋诗','song-poetry','','[]','一丘一壑塵埃外，三沐三薰清浄身。',64,'全唐诗/poet.song.172000.json','["一丘一壑塵埃外，三沐三薰清浄身。", "別墅只今唐處士，高風當日漢君賓。", "打門未肯容驚夢，載酒誰能徑卜鄰。", "千里題詩寄心賞，多慚不是謫仙人。"]'),
('de5b337b-4bbc-4427-99f1-f71905833290','和答黄時舉貢士獻黄草布','孫應時','宋','宋诗','song-poetry','','[]','九陌塵中一笑看，肯隨風月到遥山。',64,'全唐诗/poet.song.172000.json','["九陌塵中一笑看，肯隨風月到遥山。", "應知枕石先秋冷，何羨槃氷及夏頒。", "古意紵衣仍縞带，襟期華髮更蒼顔。", "多君志力猶强健，不道人生行路難。"]'),
('31f4cc26-c6ba-4071-bac4-c769248cc5c4','挽徐季節先生  其一','孫應時','宋','宋诗','song-poetry','','[]','語言平談骨清癯，誰似黄山一老徐。',64,'全唐诗/poet.song.172000.json','["語言平談骨清癯，誰似黄山一老徐。", "眼底不知人富貴，腹中惟有古詩書。", "平生義薄雲天上，日暮家無儋石儲。", "試問台人君識否，此翁元不事名譽。"]'),
('7cc47fff-60d9-40e3-84f3-c4ca247bba90','挽徐季節先生  其二','孫應時','宋','宋诗','song-poetry','','[]','年過八十更精神，佚我房中自在身。',64,'全唐诗/poet.song.172000.json','["年過八十更精神，佚我房中自在身。", "檢點欺心無一髮，薰涵和氣似三春。", "莫疑見識驚流俗，自是淵源到古人。", "前輩彫零公又往，哀哀令我涕沾巾。"]'),
('8e5658ca-f545-4ca6-a92a-66d8cc54b599','閩憲克莊以故舊託文公五世孫明仲遠徵鄙文老退遺棄散逸荷伯宗用昭止善浩淵子勗至善及余表姪孫陳誼予兄子豐仲弟之婿賈熙用昭之從子大年等十餘人寒冬連旬日夜錄之得五十卷亦已勞矣賦此爲謝','孫應時','宋','宋诗','song-poetry','','[]','老去斯文付寂寥，寒枝枯甲一遺蜩。',64,'全唐诗/poet.song.172000.json','["老去斯文付寂寥，寒枝枯甲一遺蜩。", "虛言自歎真何補，好友相求不憚遥。", "敗篋塵埃煩數子，破窗風雨每連宵。", "詩成明日尋梅去，共看春風轉斗杓。"]'),
('9f27cd47-a1c0-4b42-a2ae-09937a1b0a7f','送趙清臣善湘明府民謠六韵','孫應時','宋','宋诗','song-poetry','','[]','秘圖山上古姚州，山色江光簇畫樓。',96,'全唐诗/poet.song.172000.json','["秘圖山上古姚州，山色江光簇畫樓。", "更鼓分明庭少事，桁楊閒冷獄無囚。", "民言總信清如水，天賜常教大有秋。", "人物襟懷何灑落，詞章翰墨更風流。", "朝廷久合登劉向，父老知難挽鄧侯。", "翠竇新泉探靜樂，公名長與此泉流。"]'),
('79594294-f18f-40c0-8f29-53096bb7b507','送趙簡叔滿秩歸閩','孫應時','宋','宋诗','song-poetry','','[]','四海從游總弟昆，年來誰復似王孫。',96,'全唐诗/poet.song.172000.json','["四海從游總弟昆，年來誰復似王孫。", "真情每向急難見，高義殊非薄俗論。", "入眼雲煙歸翰墨，滿懷風月寄琴樽。", "三年叢枳勞栖鳳，萬里天池合化鵾。", "官達於君何足道，心期令我已忘言。", "相思驛路梅花發，應倩清詩寫夢魂。"]'),
('e8f75b6b-59c0-4a5f-905b-72b008d6c665','簡叔自臨安之官鄂渚專書問訊多寄近作以詩謝之用前歲贈別韵','孫應時','宋','宋诗','song-poetry','','[]','與君異姓似諸昆，文采風流帝子孫。',96,'全唐诗/poet.song.172000.json','["與君異姓似諸昆，文采風流帝子孫。", "珍重征途猶問訊，殷勤詩卷遣重論。", "光寒牛斗韜龍劍，興逸江湖著瓠樽。", "混混人間誰虎鼠，冥冥物外獨鵬鯤。", "閒中日月無追恨，聖處工夫豈浪言。", "萬里此心長對面，莫尋別賦苦消魂。"]'),
('f798f54e-5cb6-4d1d-88f4-11891076a9dd','和李季章校書西湖即事三首  其一','孫應時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','風日都門外，樓臺十萬家。',24,'全唐诗/poet.song.172000.json','["風日都門外，樓臺十萬家。", "西湖春事足，不話洛陽花。"]'),
('63c0d1d2-1f95-430f-a1cb-33b64e4f925a','和李季章校書西湖即事三首  其二','孫應時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','舴艋填芳渚，鞦韆閙粉牆。',24,'全唐诗/poet.song.172000.json','["舴艋填芳渚，鞦韆閙粉牆。", "人爭桃李節，吾憶藕花涼。"]'),
('36bd22a0-7304-48be-bbf4-5ba0b3f5ac04','和李季章校書西湖即事三首  其三','孫應時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','匆匆清明了，能餘幾許春。',24,'全唐诗/poet.song.172000.json','["匆匆清明了，能餘幾許春。", "花開更風雨，腸斷惜春人。"]'),
('762b19da-6602-4a65-9853-43c53089ec54','雪夜歎','孫應時','宋','宋诗','song-poetry','','[]','折竹聲相聞，想見雪深尺。',24,'全唐诗/poet.song.172000.json','["折竹聲相聞，想見雪深尺。", "愁殺小臣心，橋山葬明日。"]'),
('2e294fc0-e6c5-47b3-8a97-8d7c023d1530','鐵笛亭','孫應時','宋','宋诗','song-poetry','','[]','鐵笛空山巔，悲裂蒼崖破。',24,'全唐诗/poet.song.172000.json','["鐵笛空山巔，悲裂蒼崖破。", "驚起山中人，指點飛僊過。"]'),
('3521eab2-6229-4dbc-9517-47cd0dde1f7f','石竈','孫應時','宋','宋诗','song-poetry','','[]','石竈滄潭上，烹茶定幾迴。',24,'全唐诗/poet.song.172000.json','["石竈滄潭上，烹茶定幾迴。", "舟人因記得，俗客未經來。"]'),
('a8f1dbcf-63e2-4325-a4e4-c0d371d4216e','題光福劉伯祥所藏東坡枯木及漁村落照圖  其一','孫應時','宋','宋诗','song-poetry','','[]','灑落胸中丘壑，崢嶸海外風霜。',28,'全唐诗/poet.song.172000.json','["灑落胸中丘壑，崢嶸海外風霜。", "幻出小山枯木，教成千載甘棠。"]'),
('b23d59bd-aef7-4841-9be3-e42e0097bf68','題光福劉伯祥所藏東坡枯木及漁村落照圖  其二','孫應時','宋','宋诗','song-poetry','','[]','夕陽雁影江天，明月蘆花醉眠。',28,'全唐诗/poet.song.172000.json','["夕陽雁影江天，明月蘆花醉眠。", "乞我煙波一葉，伴君西塞山邊。"]'),
('60edf1b6-4471-4692-aaa5-21891ef26bf4','十一月二十六夜夢與范石湖各賦梅花六言覺僅記其大意足成二絕  其一','孫應時','宋','宋诗','song-poetry','','[]','小齋遥夜孤坐，何處香來可人。',28,'全唐诗/poet.song.172000.json','["小齋遥夜孤坐，何處香來可人。", "起看一窗寒月，更憐瘦影相親。"]'),
('fc456e70-7e46-4f29-96a5-9bc5dd2b04ad','十一月二十六夜夢與范石湖各賦梅花六言覺僅記其大意足成二絕  其二','孫應時','宋','宋诗','song-poetry','','[]','江路月斜霜重，野橋風峭波寒。',28,'全唐诗/poet.song.172000.json','["江路月斜霜重，野橋風峭波寒。", "知負天公何事，十他冷淡相看。"]'),
('59e0a1ee-6dac-40b5-9345-5222a058e826','別越中諸生  其一','孫應時','宋','宋诗','song-poetry','','[]','三年一榻占清閒，門外蒼然是種山。',32,'全唐诗/poet.song.172000.json','["三年一榻占清閒，門外蒼然是種山。", "步月迎風行樂地，從今應入夢魂間。"]'),
('b5341aa0-042b-4511-8279-7ab1801c411b','別越中諸生  其二','孫應時','宋','宋诗','song-poetry','','[]','切磋長恨我空疎，甚喜同門各起予。',32,'全唐诗/poet.song.172000.json','["切磋長恨我空疎，甚喜同門各起予。", "贈別懶爲名利語，洗心深讀聖賢書。"]'),
('c0c8c640-2645-49a5-b935-da1412e05c2c','范氏致爽園用石湖韵  其一','孫應時','宋','宋诗','song-poetry','','[]','可人花木四時足，隨意園池百畝餘。',32,'全唐诗/poet.song.172000.json','["可人花木四時足，隨意園池百畝餘。", "但續岷山高士傳，不談天上故人書。"]'),
('f04b749d-1820-495d-a035-dbeebe114e16','范氏致爽園用石湖韵  其二','孫應時','宋','宋诗','song-poetry','','[]','山光突兀初寒外，竹色連娟細雨餘。',32,'全唐诗/poet.song.172000.json','["山光突兀初寒外，竹色連娟細雨餘。", "一段清奇徹肌骨，錦囊碎句懶能書。"]'),
('6b4e022f-d879-4c78-992f-f2caa0e3f708','黄巖新安鎮舟中和王主簿春霽遣興','孫應時','宋','宋诗','song-poetry','','[]','天惜花時雨易晴，鳥知人意喚春醒。',32,'全唐诗/poet.song.172000.json','["天惜花時雨易晴，鳥知人意喚春醒。", "歸舟兀兀新安路，溪北溪南水正生。"]'),
('312a5af1-21e6-4ce4-aa9f-6b44002e976a','春郊偶作','孫應時','宋','宋诗','song-poetry','','[]','春泥過雨屐聲慳，野水危橋欲度難。',32,'全唐诗/poet.song.172000.json','["春泥過雨屐聲慳，野水危橋欲度難。", "世路迷人腸斷處，黄昏天氣麥秋寒。"]'),
('cbdebe1e-82df-47f9-91a6-e33bae989bd9','閲書庫','孫應時','宋','宋诗','song-poetry','','[]','寒儒事業趁三餘，細字篝燈手自書。',32,'全唐诗/poet.song.172000.json','["寒儒事業趁三餘，細字篝燈手自書。", "眼底牙籤富連屋，妙年公子意何如。"]'),
('9b98ac6e-7372-443d-83a4-c9d7afa46dac','秋日遣興  其一','孫應時','宋','宋诗','song-poetry','','[]','門前白水映青山，草滿荒庭晝掩關。',32,'全唐诗/poet.song.172000.json','["門前白水映青山，草滿荒庭晝掩關。", "莫恨窮居窮到骨，平生未有此情閒。"]'),
('b440ae3b-b629-4ee1-ab67-fcd0268c66bb','秋日遣興  其二','孫應時','宋','宋诗','song-poetry','','[]','今年炎毒異他年，及此秋風意灑然。',32,'全唐诗/poet.song.172000.json','["今年炎毒異他年，及此秋風意灑然。", "身世還須幾寒暑，吾生何事不隨緣。"]'),
('b8812d2a-f688-413e-b2d6-07e7143d3424','秋日遣興  其三','孫應時','宋','宋诗','song-poetry','','[]','清秋佳月不尋常，何限歌樓醉夜長。',32,'全唐诗/poet.song.172000.json','["清秋佳月不尋常，何限歌樓醉夜長。", "要是超然塵外客，一杯差不負孤光。"]'),
('3b49382f-8e4e-436e-a37a-323268be2a1f','秋日遣興  其四','孫應時','宋','宋诗','song-poetry','','[]','故人强半隨流水，世事新來似弈棋。',32,'全唐诗/poet.song.172000.json','["故人强半隨流水，世事新來似弈棋。", "老我壯心消折盡，鏡中唯有鬢如絲。"]'),
('30eec2e5-feef-4e48-83ee-50a23c1bd972','秋日遣興  其五','孫應時','宋','宋诗','song-poetry','','[]','學書成癖故童心，頗復欣然得趣深。',32,'全唐诗/poet.song.172000.json','["學書成癖故童心，頗復欣然得趣深。", "一字千金亦安用，等閒容我度光陰。"]'),
('d338378f-2912-4c27-a149-96b146710145','秋日遣興  其六','孫應時','宋','宋诗','song-poetry','','[]','虛齋獨寢意偏清，夢斷秋窗月正明。',32,'全唐诗/poet.song.172000.json','["虛齋獨寢意偏清，夢斷秋窗月正明。", "匡坐偶然成導引，未須癡絕慕長生。"]'),
('f4302b8a-ebc7-4f4b-8aa8-3fff1652db7e','山庵即事','孫應時','宋','宋诗','song-poetry','','[]','田田荷葉作老色，楚楚菊叢生細香。',32,'全唐诗/poet.song.172000.json','["田田荷葉作老色，楚楚菊叢生細香。", "落日空山歸鳥盡，扶筇獨自到池塘。"]'),
('0c81e9b1-62db-4126-b092-02503fa9df54','胡元邁集句作宮詞二百首求題跋爲書兩章  其一','孫應時','宋','宋诗','song-poetry','','[]','五侯鯖具人間味，百衲衣裒天下工。',32,'全唐诗/poet.song.172000.json','["五侯鯖具人間味，百衲衣裒天下工。", "宮體故宜供帖子，玉堂何日喚詩翁。"]'),
('1ac49856-f339-4d0d-a552-ea6f73421187','胡元邁集句作宮詞二百首求題跋爲書兩章  其二','孫應時','宋','宋诗','song-poetry','','[]','不譏飛燕在昭陽，但託流鶑滿建章。',32,'全唐诗/poet.song.172000.json','["不譏飛燕在昭陽，但託流鶑滿建章。", "狗監若逢楊得意，何妨持此奉君王。"]'),
('0c3f8160-cd01-4d15-8fac-a0be741a54b0','書西溪僧壁  其一','孫應時','宋','宋诗','song-poetry','','[]','問訊前賢滄海邊，遥堤煙草故依然。',32,'全唐诗/poet.song.172000.json','["問訊前賢滄海邊，遥堤煙草故依然。", "誰言筦庫功名薄，已活淮民二百年。"]'),
('97326900-1b33-41be-ba74-bc2c22bc2a6a','書西溪僧壁  其二','孫應時','宋','宋诗','song-poetry','','[]','碧天如水水明霞，雁字橫風一一斜。',32,'全唐诗/poet.song.172000.json','["碧天如水水明霞，雁字橫風一一斜。", "袖手行吟不知晚，滿川霜月浸蘆花。"]'),
('96dfa1bd-e8c9-44bd-8dbd-02575fe447b7','書西溪僧壁  其三','孫應時','宋','宋诗','song-poetry','','[]','悠悠身世客心驚，十宿西溪夢未曾。',32,'全唐诗/poet.song.172000.json','["悠悠身世客心驚，十宿西溪夢未曾。", "笑把新詩留日月，碧紗黄堊聽山僧。"]'),
('eb319479-3987-48d4-b86e-d58ea8e22f18','詠史  其一','孫應時','宋','宋诗','song-poetry','','[]','絳帳何人拜馬融，已應羞面見兒童。',32,'全唐诗/poet.song.172000.json','["絳帳何人拜馬融，已應羞面見兒童。", "早知自照頭顱醜，枉用文章殺李公。"]'),
('36f974e9-9301-4768-85d8-bb08016acf15','詠史  其二','孫應時','宋','宋诗','song-poetry','','[]','咄咄歸來技已窮，函書翻欲媚桓公。',32,'全唐诗/poet.song.172000.json','["咄咄歸來技已窮，函書翻欲媚桓公。", "佳兒似此何須數，空使諸人恕乃翁。"]'),
('d7f5fa2f-420b-47f7-9d85-64ba7896ea0c','詠史  其三','孫應時','宋','宋诗','song-poetry','','[]','拊髀平生志八區，暮年家國付夷吾。',32,'全唐诗/poet.song.172000.json','["拊髀平生志八區，暮年家國付夷吾。", "誰言子女能相豢，可笑周郎淺丈夫。"]'),
('c2f21d9c-74fb-4c2f-b185-0066130df0f9','西溪僧舍晝卧','孫應時','宋','宋诗','song-poetry','','[]','燕子風微春晝長，獨携書卷卧禪房。',32,'全唐诗/poet.song.172000.json','["燕子風微春晝長，獨携書卷卧禪房。", "悠然一笑無人領，只有薔薇滿院香。"]'),
('a6b66432-b349-4243-8590-982805fba26e','奉和家大人將赴官舍留示及門之作  其一','孫應時','宋','宋诗','song-poetry','','[]','師訓勤誠數十年，此心端不愧高天。',32,'全唐诗/poet.song.172000.json','["師訓勤誠數十年，此心端不愧高天。", "諸君體我家嚴意，學殖毋爲鹵莽田。"]'),
('eb676c7e-4308-4e11-a654-c96b9d8c8f38','奉和家大人將赴官舍留示及門之作  其二','孫應時','宋','宋诗','song-poetry','','[]','大學成功在九年，根牢幹長到參天。',32,'全唐诗/poet.song.172000.json','["大學成功在九年，根牢幹長到參天。", "斯須廢棄終身困，稂莠從來易滿田。"]'),
('8be11692-fc01-42c5-90a3-a09f9dfff7f3','黄巖溪  其一','孫應時','宋','宋诗','song-poetry','','[]','杜鵑聲裏谷幽幽，綠水平溪日夜流。',32,'全唐诗/poet.song.172000.json','["杜鵑聲裏谷幽幽，綠水平溪日夜流。", "花落空山人不到，一川煙雨起春愁。"]'),
('2434debd-a882-4150-abe9-6b5ed1dae1e4','黄巖溪  其二','孫應時','宋','宋诗','song-poetry','','[]','蒼山萬疊鎖荒煙，百道清溪思悄然。',32,'全唐诗/poet.song.172000.json','["蒼山萬疊鎖荒煙，百道清溪思悄然。", "只有東風偏識路，馬蹄花發自年年。"]'),
('9ed4f521-26f5-457a-856e-463fe09a8776','入福昌寺','孫應時','宋','宋诗','song-poetry','','[]','風日蕭蕭林翠開，支筇古寺獨徘徊。',32,'全唐诗/poet.song.172000.json','["風日蕭蕭林翠開，支筇古寺獨徘徊。", "山中不怪無人識，十五年前一度來。"]'),
('e4b1dce7-73c3-4c64-bed1-51b33a061d86','次仲氏韵  其一','孫應時','宋','宋诗','song-poetry','','[]','麴生真得聖之清，風味超然一座傾。',32,'全唐诗/poet.song.172000.json','["麴生真得聖之清，風味超然一座傾。", "肯向春寒慰牢落，令人心事轉和平。"]'),
('5fd3f22e-4621-492c-8be0-61f3651917ae','次仲氏韵  其二','孫應時','宋','宋诗','song-poetry','','[]','枵腹貪書頗自强，年來得失正相當。',32,'全唐诗/poet.song.172000.json','["枵腹貪書頗自强，年來得失正相當。", "須知耳目塵埃盡，始見山林日月長。"]'),
('f87bffa6-946a-4bcb-86b3-0e841be8be50','次仲氏韵  其三','孫應時','宋','宋诗','song-poetry','','[]','故人驚我鬢絲多，一歎相逢可若何。',32,'全唐诗/poet.song.172000.json','["故人驚我鬢絲多，一歎相逢可若何。", "勳業向來無此夢，菱花何必遣重磨。"]'),
('b0972233-bf7a-47e7-84b9-e4533543dbb9','山行','孫應時','宋','宋诗','song-poetry','','[]','中年意與山林會，勝日身兼杖屨輕。',32,'全唐诗/poet.song.172000.json','["中年意與山林會，勝日身兼杖屨輕。", "正有百錢堪獨往，不將一賞負秋晴。"]'),
