('6df25961-e94b-445a-a7b5-64ed19cee74e','枕上口占','孫應時','宋','宋诗','song-poetry','','[]','喧喧鳬雁起寒汀，淡淡書窗半欲明。',32,'全唐诗/poet.song.172000.json','["喧喧鳬雁起寒汀，淡淡書窗半欲明。", "聽徹霜鐘發深思，對床欹枕有詩成。"]'),
('4baea9fa-14d2-494a-b9ca-41961ea95baf','次日湖上','孫應時','宋','宋诗','song-poetry','','[]','山南山北水平湖，屏障天開畫不如。',32,'全唐诗/poet.song.172000.json','["山南山北水平湖，屏障天開畫不如。", "好在風流王謝宅，扁舟來往未應疎。"]'),
('5c0817a4-0883-4436-b3c1-7493cc312394','送彭大老提舶泉南  其一','孫應時','宋','宋诗','song-poetry','','[]','先生學力定如山，應世無非意所安。',32,'全唐诗/poet.song.172000.json','["先生學力定如山，應世無非意所安。", "一語令人深味處，不言容易祇言難。"]'),
('8685106a-20c1-4b45-91fc-d6ee9fec4388','送彭大老提舶泉南  其二','孫應時','宋','宋诗','song-poetry','','[]','笑談終日任天真，和氣春風自襲人。',32,'全唐诗/poet.song.172000.json','["笑談終日任天真，和氣春風自襲人。", "畢竟胸中無適莫，不妨一世總相親。"]'),
('9d3a0c23-5c33-4249-a291-950594005a1f','送彭大老提舶泉南  其三','孫應時','宋','宋诗','song-poetry','','[]','人言西府厭編摩，歸卧方山意若何。',32,'全唐诗/poet.song.172000.json','["人言西府厭編摩，歸卧方山意若何。", "出處無心亦無累，寧知世上有風波。"]'),
('48c505f2-6d42-4ce4-b258-92583062091b','送彭大老提舶泉南  其四','孫應時','宋','宋诗','song-poetry','','[]','眼觀榮辱等虛空，强著衣冠與世同。',32,'全唐诗/poet.song.172000.json','["眼觀榮辱等虛空，强著衣冠與世同。", "長夏清風秋夜月，高懷應不忘山中。"]'),
('0bcbd4cc-af36-4ee8-98b4-1a676983532a','送彭大老提舶泉南  其五','孫應時','宋','宋诗','song-poetry','','[]','天然廉素匪沽名，秋入滄浪徹底清。',32,'全唐诗/poet.song.172000.json','["天然廉素匪沽名，秋入滄浪徹底清。", "蠻舶珍奇縱山積，歸囊應比去時輕。"]'),
('71ec4aac-4a97-4ddb-9a66-25363b9c31eb','送彭大老提舶泉南  其六','孫應時','宋','宋诗','song-poetry','','[]','一時人物到如今，人望先生日已深。',32,'全唐诗/poet.song.172000.json','["一時人物到如今，人望先生日已深。", "願以蒼生置懷抱，勿因空谷有遐心。"]'),
('0ba556fc-388e-4048-b7fa-9686f8a3f0bb','崑山龔立道昱有月石硯屏斗南君玉諸人皆有詩余亦賦一絕','孫應時','宋','宋诗','song-poetry','','[]','窗間明月鎮長在，此寶如今更有無。',32,'全唐诗/poet.song.172000.json','["窗間明月鎮長在，此寶如今更有無。", "看取光輝生筆硯，可無文字繼歐蘇。"]'),
('192a9f02-e201-4951-b6f5-4dba93c60dae','舉帆松江經縣治北','孫應時','宋','宋诗','song-poetry','','[]','楊柳煙中一塔孤，東風漫漫水平湖。',32,'全唐诗/poet.song.172000.json','["楊柳煙中一塔孤，東風漫漫水平湖。", "扁舟誰倚高樓望，畫入吳淞春晚圖。"]'),
('9b0b1e7e-4f64-4dd4-9e5f-613d907b0204','贈閭丘道人','孫應時','宋','宋诗','song-poetry','','[]','天下幾人能具眼，世間萬事可忘言。',32,'全唐诗/poet.song.172000.json','["天下幾人能具眼，世間萬事可忘言。", "猶將筆墨瀾翻說，多笑先生不憚煩。"]'),
('ea52feb9-067e-4f4e-8cd1-593e650d47a2','江北梅開殊晚和林實之別駕韵  其一','孫應時','宋','宋诗','song-poetry','','[]','水邊籬落影疎疎，一見風姿意豁如。',32,'全唐诗/poet.song.172000.json','["水邊籬落影疎疎，一見風姿意豁如。", "驛使莫嫌時節晚，少留春半作春初。"]'),
('f364d7aa-2d97-4d9b-b5fd-b3b995bfcc5d','江北梅開殊晚和林實之別駕韵  其二','孫應時','宋','宋诗','song-poetry','','[]','楚江橫月一枝明，想見江南半落英。',32,'全唐诗/poet.song.172000.json','["楚江橫月一枝明，想見江南半落英。", "等是春風有先後，不妨調鼎看功成。"]'),
('9fc21061-c6f4-4b5d-bd94-00e535b5c8d9','江北梅開殊晚和林實之別駕韵  其三','孫應時','宋','宋诗','song-poetry','','[]','地遠天寒飽雪霜，深林依舊十分香。',32,'全唐诗/poet.song.172000.json','["地遠天寒飽雪霜，深林依舊十分香。", "玉堂茅舍公休問，一種風流壓衆芳。"]'),
('00dabc95-bd56-49fa-b67e-c5c446091302','江北梅開殊晚和林實之別駕韵  其四','孫應時','宋','宋诗','song-poetry','','[]','清詩吟賞慰花神，喚起風情寂寞濱。',32,'全唐诗/poet.song.172000.json','["清詩吟賞慰花神，喚起風情寂寞濱。", "正是參軍舊題處，須公還作一家春。"]'),
('617f13d7-63ac-4e5c-abc7-bd986912a12f','江北梅開殊晚和林實之別駕韵  其五','孫應時','宋','宋诗','song-poetry','','[]','一笑無言桃李場，從教遥夜鬭寒香。',32,'全唐诗/poet.song.172000.json','["一笑無言桃李場，從教遥夜鬭寒香。", "紅梅何意敗家法，便欲從時作閙粧。"]'),
('8840ed38-855a-425a-82f7-5d890af23534','江北梅開殊晚和林實之別駕韵  其六','孫應時','宋','宋诗','song-poetry','','[]','許氏南園十里間，嗟跎勝賞怯春寒。',32,'全唐诗/poet.song.172000.json','["許氏南園十里間，嗟跎勝賞怯春寒。", "寄聲行客如迴首，莫把尋常醉眼看。"]'),
('7dec8254-811c-435d-a4cd-837d13d93c20','池口阻風雨  其一','孫應時','宋','宋诗','song-poetry','','[]','江頭三日繫扁舟，秋浦齊山欠一游。',32,'全唐诗/poet.song.172000.json','["江頭三日繫扁舟，秋浦齊山欠一游。", "已自無人念羈客，更禁風雨作春愁。"]'),
('be7e2530-47d8-4f0a-b99f-859ed8e94c37','池口阻風雨  其二','孫應時','宋','宋诗','song-poetry','','[]','一江風雨送春歸，漠漠汀洲白鷺飛。',32,'全唐诗/poet.song.172000.json','["一江風雨送春歸，漠漠汀洲白鷺飛。", "舟子相呼更添纜，水來新沒釣船磯。"]'),
('730f35cf-cc9a-48eb-b95c-ba34466c5b0e','巫山祠梳洗樓','孫應時','宋','宋诗','song-poetry','','[]','山川楚國六千里，雲雨陽臺十二峰。',32,'全唐诗/poet.song.172000.json','["山川楚國六千里，雲雨陽臺十二峰。", "神女可無哀郢意，强教梳洗爲誰容。"]'),
('2e72b58f-474a-4617-a1fd-d24fc7210d0d','巴東秋風亭懷寇公  其一','孫應時','宋','宋诗','song-poetry','','[]','秋風亭上思悠哉，想見鳴琴日日來。',32,'全唐诗/poet.song.172000.json','["秋風亭上思悠哉，想見鳴琴日日來。", "野水孤舟故如昨，爲公長嘯一徘徊。"]'),
('13f36c0d-d700-4ed3-8890-1b3c7b479144','巴東秋風亭懷寇公  其二','孫應時','宋','宋诗','song-poetry','','[]','袖手窮山一少年，何曾有楚到澶淵。',32,'全唐诗/poet.song.172000.json','["袖手窮山一少年，何曾有楚到澶淵。", "英雄正自無人識，蓋世功名却偶然。"]'),
('81c011e2-a9d5-4b40-964e-e414a0a505a2','和真長木犀  其一','孫應時','宋','宋诗','song-poetry','','[]','一從月窟移根到，不落人間第二香。',32,'全唐诗/poet.song.172000.json','["一從月窟移根到，不落人間第二香。", "商略江梅是兄弟，等閒休復鬭風光。"]'),
('8f808693-96b3-4dfa-a07d-db9f0ea3836f','和真長木犀  其二','孫應時','宋','宋诗','song-poetry','','[]','香傳萬里到蠶叢，依舊江南林下風。',32,'全唐诗/poet.song.172000.json','["香傳萬里到蠶叢，依舊江南林下風。", "憶著小山招隠句，不堪流落更相逢。"]'),
('933e6375-f797-4e5f-926d-24e9095e8438','和真長木犀  其三','孫應時','宋','宋诗','song-poetry','','[]','長憐花月不相謀，月滿花開得更休。',32,'全唐诗/poet.song.172000.json','["長憐花月不相謀，月滿花開得更休。", "待倚高樓吹鐵笛，爲君極意作吟秋。"]'),
('44017466-8a36-4983-9329-909220105bea','即事  其一','孫應時','宋','宋诗','song-poetry','','[]','凝雲淡淡山蒼蒼，天影下照生湖光。',32,'全唐诗/poet.song.172000.json','["凝雲淡淡山蒼蒼，天影下照生湖光。", "漁舟散入綠蘋去，劃破琉璃三四行。"]'),
('4149785a-d8f7-40ce-ad14-4e74d1458975','即事  其二','孫應時','宋','宋诗','song-poetry','','[]','江梅玉立故清妍，心友猗蘭弟水仙。',32,'全唐诗/poet.song.172000.json','["江梅玉立故清妍，心友猗蘭弟水仙。", "終日相看靜無語，一時風味也堪憐。"]'),
('f1dbcd39-6ad0-43f9-9d82-cae5482a5fe0','和鄭信卿  其一','孫應時','宋','宋诗','song-poetry','','[]','天與風情壓衆芳，雕欄翠幄奉君王。',32,'全唐诗/poet.song.172000.json','["天與風情壓衆芳，雕欄翠幄奉君王。", "猗蘭自欠傾城色，空作深林一味香。"]'),
('6a476c46-eca1-4b26-b031-8a0ca6b4f297','和鄭信卿  其二','孫應時','宋','宋诗','song-poetry','','[]','綺羅絲竹沸名園，想見春風玉樹前。',32,'全唐诗/poet.song.172000.json','["綺羅絲竹沸名園，想見春風玉樹前。", "況是天公饒一月，何妨行樂倍他年。"]'),
('c8eca926-f486-4be5-900e-1c96b705cb06','和鄭信卿  其三','孫應時','宋','宋诗','song-poetry','','[]','舞絮飛花別茂林，狂蜂亂蝶度繁陰。',32,'全唐诗/poet.song.172000.json','["舞絮飛花別茂林，狂蜂亂蝶度繁陰。", "乾坤不盡春長在，莫遣傷春意太深。"]'),
('9f06620c-2aba-4700-ab08-95c804de9deb','和陳及之  其一','孫應時','宋','宋诗','song-poetry','','[]','不妨客子歸路滑，且喜雨來天破慳。',32,'全唐诗/poet.song.172000.json','["不妨客子歸路滑，且喜雨來天破慳。", "劍南劍北好顔色，吾徒心事畧相關。"]'),
('a976d799-bfaa-4054-8990-08f9c5cc6c9d','和陳及之  其二','孫應時','宋','宋诗','song-poetry','','[]','詩無彫刻未爲癖，戰勝紛華聊自肥。',32,'全唐诗/poet.song.172000.json','["詩無彫刻未爲癖，戰勝紛華聊自肥。", "萬里歸期勞夢想，百年世事幾從違。"]'),
('9c693022-4ba0-428d-a143-cb455cf2b66a','和陳及之  其三','孫應時','宋','宋诗','song-poetry','','[]','蟠龍山頭行且歌，嘉陵江上重相過。',32,'全唐诗/poet.song.172000.json','["蟠龍山頭行且歌，嘉陵江上重相過。", "人生知音不易得，舉似諸人委悉麽。"]'),
('e9edecb0-d3d6-4e60-8d8f-ff5664af894f','和陳及之  其四','孫應時','宋','宋诗','song-poetry','','[]','江頭風雨暗行李，習氣難洗儒生酸。',32,'全唐诗/poet.song.172000.json','["江頭風雨暗行李，習氣難洗儒生酸。", "更欲從君細商畧，不道揮斤愁鼻端。"]'),
('1c5bbb0c-73a3-41ca-9643-ef8983ef615d','和陳及之  其五','孫應時','宋','宋诗','song-poetry','','[]','吾非斯人誰與羣，覆手翻手知交情。',32,'全唐诗/poet.song.172000.json','["吾非斯人誰與羣，覆手翻手知交情。", "天南海北有離合，此生此意無寒盟。"]'),
('68cf1420-aae8-45cd-ac07-6ac17b6ff255','再和  其一','孫應時','宋','宋诗','song-poetry','','[]','文章富貴自兩事，脫欲其全天定慳。',32,'全唐诗/poet.song.172000.json','["文章富貴自兩事，脫欲其全天定慳。", "平生蕭瑟也不惡，未妨詩賦動江關。"]'),
('3b648e2f-cd36-4f7a-b262-795061820f7b','再和  其二','孫應時','宋','宋诗','song-poetry','','[]','庭幃日聽烏鵲喜，里社相思雞鳬肥。',32,'全唐诗/poet.song.172000.json','["庭幃日聽烏鵲喜，里社相思雞鳬肥。", "獨身浪走一萬里，忽忽平生心事違。"]'),
('db7bb792-45f8-4004-bde5-48e3354e571c','再和  其三','孫應時','宋','宋诗','song-poetry','','[]','君詩音節中弦歌，報我英瑶百倍過。',32,'全唐诗/poet.song.172000.json','["君詩音節中弦歌，報我英瑶百倍過。", "江村老人衣鉢在，同參今更有人麽。"]'),
('c5b6dce5-208f-4a64-9ffc-ba84590b6dad','再和  其四','孫應時','宋','宋诗','song-poetry','','[]','欲望中原雙目斷，聽談往事幾心酸。',32,'全唐诗/poet.song.172000.json','["欲望中原雙目斷，聽談往事幾心酸。", "百年故家好人物，塵沙流落太無端。"]'),
('430b216b-a245-4ca2-b4a7-c09d01c59847','再和  其五','孫應時','宋','宋诗','song-poetry','','[]','衮衮諸公鴛鷺羣，年來看熟已忘情。',32,'全唐诗/poet.song.172000.json','["衮衮諸公鴛鷺羣，年來看熟已忘情。", "四明相尋風雨過，一丘一壑便慳盟。"]'),
('a278b988-f2f9-4bb6-942a-47d3837fbce4','和簡叔  其一','孫應時','宋','宋诗','song-poetry','','[]','綠陰庭戶自生香，燕子飛來話日長。',32,'全唐诗/poet.song.172000.json','["綠陰庭戶自生香，燕子飛來話日長。", "正有清風便午枕，更無塵夢到禪房。"]'),
('c8149fd4-f1aa-4adf-a29a-a091bff3420d','和簡叔  其二','孫應時','宋','宋诗','song-poetry','','[]','落日銜山山更青，閒雲斂盡綠煙橫。',32,'全唐诗/poet.song.172000.json','["落日銜山山更青，閒雲斂盡綠煙橫。", "危亭獨倚闌干遍，又聽疎鐘第一聲。"]'),
('28c0b7bf-e8b4-4fe7-8e17-7582326a3804','挽邢邦用  其一','孫應時','宋','宋诗','song-poetry','','[]','有美天姿粹且真，溫溫玉樹氣生春。',32,'全唐诗/poet.song.172000.json','["有美天姿粹且真，溫溫玉樹氣生春。", "從來孝友聞鄉曲，歎息如公有幾人。"]'),
('524e4e38-69c1-41b3-9f19-001e241a46cc','挽邢邦用  其二','孫應時','宋','宋诗','song-poetry','','[]','十載潛心學有方，韜藏曾不露鋒鋩。',32,'全唐诗/poet.song.172000.json','["十載潛心學有方，韜藏曾不露鋒鋩。", "前途萬里能脂轄，此志傷君死未忘。"]'),
('9f643224-2930-4af2-8230-87822ef64086','挽邢邦用  其三','孫應時','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','區區倉掾救荒移，實惠洋洋攝令時。',32,'全唐诗/poet.song.172000.json','["區區倉掾救荒移，實惠洋洋攝令時。", "更有棠陰在空圄，廬山遺愛未應衰。"]'),
('16e61e98-2bb0-440c-bfec-9d2aead832da','挽邢邦用  其四','孫應時','宋','宋诗','song-poetry','','[]','平生事業始分毫，楩梓終須百丈高。',32,'全唐诗/poet.song.172000.json','["平生事業始分毫，楩梓終須百丈高。", "正擬他時好梁棟，忍看摧折在蓬蒿。"]'),
('449a19d7-3021-4a1d-9670-881f10187801','挽邢邦用  其五','孫應時','宋','宋诗','song-poetry','','[]','傾蓋論交未一年，追懷三益淚潸然。',32,'全唐诗/poet.song.172000.json','["傾蓋論交未一年，追懷三益淚潸然。", "爲君提掖諸郎看，長已勝冠孟母賢。"]'),
('451597c4-f1f3-43e3-8e55-11279a25f5f2','眉州','孫應時','宋','宋诗','song-poetry','','[]','文華要是山川氣，看到眉州四海空。',32,'全唐诗/poet.song.172000.json','["文華要是山川氣，看到眉州四海空。", "尊者庵前雙石筍，令人真見兩蘇公。"]'),
('d62a275a-5ccc-4c63-80c0-0f7711222ed7','讀通鑑雜興  其一','孫應時','宋','宋诗','song-poetry','','[]','南山擊缶正烏烏，東市匆匆坐一書。',32,'全唐诗/poet.song.172000.json','["南山擊缶正烏烏，東市匆匆坐一書。", "說道中興無過事，太陽侵蝕總緣渠。"]'),
('28894355-b641-48fd-86b2-e1e93988c8c0','讀通鑑雜興  其二','孫應時','宋','宋诗','song-poetry','','[]','簿書流汗走君房，那得狂奴故意降。',32,'全唐诗/poet.song.172000.json','["簿書流汗走君房，那得狂奴故意降。", "努力諸公了臺閣，不煩魚雁到桐江。"]'),
('b7b00014-7e39-4583-b75b-a136a3205da5','讀通鑑雜興  其三','孫應時','宋','宋诗','song-poetry','','[]','清濁無心陳仲弓，圓機聊救漢諸公。',32,'全唐诗/poet.song.172000.json','["清濁無心陳仲弓，圓機聊救漢諸公。", "末流不料兒孫誤，千古黄初佐命功。"]'),
('f6af3dc7-c9c6-4bb2-ae14-7f013b89d222','讀通鑑雜興  其四','孫應時','宋','宋诗','song-poetry','','[]','柴門三叩畧從容，感激聊酬大耳公。',32,'全唐诗/poet.song.172000.json','["柴門三叩畧從容，感激聊酬大耳公。", "常日驅牛趁春雨，人前元不似英雄。"]'),
('e91c7995-17fa-48e8-a8d6-bf150c79cd00','讀通鑑雜興  其五','孫應時','宋','宋诗','song-poetry','','[]','渭上耕屯望一秋，鼓行那復更遲留。',32,'全唐诗/poet.song.172000.json','["渭上耕屯望一秋，鼓行那復更遲留。", "落星誤盡癡兒輩，長說宣王抗武侯。"]'),
('676a6364-2309-4522-a3d9-580f40568eee','讀通鑑雜興  其六','孫應時','宋','宋诗','song-poetry','','[]','建安社稷看文舉，正始風流倚太初。',32,'全唐诗/poet.song.172000.json','["建安社稷看文舉，正始風流倚太初。", "天地一身無處著，諸人休苦恨狂疎。"]'),
('51ce821b-dbce-42c1-b5bc-5cd1d1faf9bb','讀通鑑雜興  其七','孫應時','宋','宋诗','song-poetry','','[]','平生作意輕羊舅，歲晚何心佞羯奴。',32,'全唐诗/poet.song.172000.json','["平生作意輕羊舅，歲晚何心佞羯奴。", "爲問荆齊是三窟，此時容有宦情無。"]'),
('fa5c4657-ab7a-4847-bc63-4e11867ed896','讀通鑑雜興  其八','孫應時','宋','宋诗','song-poetry','','[]','莫怪新亭泣楚囚，王公原不辦中州。',32,'全唐诗/poet.song.172000.json','["莫怪新亭泣楚囚，王公原不辦中州。", "石頭門外千年恨，他日相思一涕流。"]'),
('0f98e0ef-820a-4c85-833c-ac268ab7fe56','題黄巖溪','孫應時','宋','宋诗','song-poetry','','[]','得雨溪聲壯，無風雲氣多。',48,'全唐诗/poet.song.172000.json','["得雨溪聲壯，無風雲氣多。", "山花依翠竹，灘石亂寒莎。", "樵父谷中出，牧兒牛背歌。", "逢人問塵世，擾擾意如何。"]'),
('bbe526a4-0a02-48dc-a374-28e3b9621edd','洞庭湖','孫應時','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','明湖納宇宙，春思滿樓臺。',48,'全唐诗/poet.song.172000.json','["明湖納宇宙，春思滿樓臺。", "沙鳥一行去，風帆千里來。", "平生眼今飽，落日首重迴。", "會趁江山約，還愁白髮催。"]'),
('386e1449-36ec-4345-9e15-d0ac185045cd','句','孫應時','宋','宋诗','song-poetry','','[]','牛車擔負愧高義，當知薄命非倪寬。',16,'全唐诗/poet.song.172000.json','["牛車擔負愧高義，當知薄命非倪寬。"]'),
('2407c6d8-432e-4cf2-ba4f-099cd6eca571','丁未仲夏賞月次雪齋韵','司馬道','宋','宋诗','song-poetry','','[]','邂逅成佳約，持杯喜月圓。',48,'全唐诗/poet.song.172000.json','["邂逅成佳約，持杯喜月圓。", "素華千頃凈，樂事兩家全。", "念舊驚同日，裁詩似先天。", "他鄉欣得此，後會肯重延。"]'),
('6ad6d696-a71f-443b-abe2-036ab6c151e3','襄陽歌','劉過','宋','宋诗','song-poetry','','[]','十年著脚走四方，胡不歸來兮襄陽。',152,'全唐诗/poet.song.172000.json','["十年著脚走四方，胡不歸來兮襄陽。", "襄陽真是用武國，上下吳蜀天中央。", "銅鞮坊裏弓作市，八邑田熟麥當糧。", "一條路入秦隴去，落日彷彿見太行。", "土風沉渾士奇傑，嗚嗚酒後歌聲發。", "歌曰人定兮勝天，半壁久無胡日月。", "買劍傾家貲，市馬託生死。", "科舉非不好，行都兮萬里。", "人言邊人盡粗材，卧龍高卧不肯來。", "杜甫詩成米芾寫，二三子亦英雄哉。"]'),
('a6e10e95-e075-48ea-9b4d-3ae7f199d98d','多景樓醉歌','劉過','宋','宋诗','song-poetry','','[]','君不見七十二子從夫子，儒雅强半魯國士。',119,'全唐诗/poet.song.172000.json','["君不見七十二子從夫子，儒雅强半魯國士。", "二十八宿佐中興，英雄多是僰陽人。", "丈夫生有四方志，東欲入海西入秦。", "安能齷齪守一隅，白頭章句浙與閩。", "醉遊太白呼峨岷，奇材劍客結楚荆。", "不隨舉子紙上學六韜，不學腐儒穿鑿注五經。", "天長路遠何時到，側身望兮涕霑巾。"]'),
('5ce81ba4-ff36-4804-8712-36ead4679733','紅酒歌呈京西漕劉郎中立義','劉過','宋','宋诗','song-poetry','','[]','桃花爲麯杏爲糵，酒醖仙方得新法。',192,'全唐诗/poet.song.172000.json','["桃花爲麯杏爲糵，酒醖仙方得新法。", "大槽迸裂猩血流，小槽夜雨真珠滴。", "峴山之北古襄陽，春風爛漫草花香。", "乘軺誰爲部使者，金閨通籍尚書郎。", "兒樣愛民真父母，十萬人家感恩厚。", "鵝兒不酌宜城黄，流霞造此江南酒。", "輪蹄日日行樂同，琥珀瀲灧琉璃鍾。", "珊瑚枝下貴公子，人面日色相爭紅。", "欄桿十二開簾幔，腰鼓轟雷奏仙樂。", "翠翹金鳳大隄倡，玉纖捧勸羅衣薄。", "人生百歲能幾何，海棠花開春較多。", "有貂可解換一斗，醉到天曉待作麽。"]'),
('17e37c29-c2fc-46ca-a887-10966193dd68','瓜州歌','劉過','宋','宋诗','song-poetry','','[]','今年城保寨，明年城瓜州。',168,'全唐诗/poet.song.172000.json','["今年城保寨，明年城瓜州。", "寇來不能禦，賊去欲自囚。", "偉哉淮南鎮，禹貢之揚州。", "念昔蕞爾虜，馬箠輕江流。", "翠華離金陵，人有李郭不。", "幸被帳下兒，一箭斃其酋。", "帝羓有遺臭，鮮血粘髑髏。", "敗軍慘無主，蛇豕散莫收。", "勢當截歸路，盡與俘馘休。", "甲兵洗黄河，境土盡白溝。", "天予棄不取，區區乃人謀。", "金帛輸東南，禮事昆夷優。", "參差女牆月，深夜照敵樓。", "泊船運河口，頗爲執事羞。"]'),
('8d5472be-69dd-430a-a5ec-e7e05732f244','盱眙行','劉過','宋','宋诗','song-poetry','','[]','車徐行，馬後馳，天寒遊子來盱眙。',144,'全唐诗/poet.song.172000.json','["車徐行，馬後馳，天寒遊子來盱眙。", "功名邂逅未可知，生身畢竟要何爲。", "既不起草黄金閨，又不侍宴白玉墀。", "何不夜投將軍飛，勸上征伐鞭四夷。", "滄海可填山可移，男兒志氣當如斯。", "安能生死困毛錐，八韵作賦五字詩。", "金牌郎君黄頭兒，有眼不忍重見之。", "志大才疎浩無期，逢人舉似人笑嬉。", "謂之癡人未必癡，喚作奇士何能奇。"]'),
('07aea054-572f-41bc-8b0e-86ee8bc9d1e7','從軍樂','劉過','宋','宋诗','song-poetry','','[]','蛟龍寶劍鸊鵜刀，黄金絡馬花盤袍。',144,'全唐诗/poet.song.172000.json','["蛟龍寶劍鸊鵜刀，黄金絡馬花盤袍。", "臂弓腰矢出門去，百戰未怕皋蘭鏖。", "酒酣縱獵自足快，詩成橫槊人稱豪。", "但期處死得其所，一死政自輕鴻毛。", "將軍三箭定天山，丞相五月入不毛。", "生前封侯死廟食，雲臺突兀秋山高。", "書生如魚蠹書冊，辛苦雕篆真徒勞。", "兒時鼓篋走京國，漸老一第猶未叨。", "自嗟賦命如紙薄，始信從軍古云樂。"]'),
('5b9e5519-6869-4144-b25d-8957917b6c58','登昇元閣故基','劉過','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','脚力倦矣曷少休，侵晨更作昇元遊。',435,'全唐诗/poet.song.172000.json','["脚力倦矣曷少休，侵晨更作昇元遊。", "眼中已不見二百四十尺突兀之高樓，但見炊煙萬竈宿貔貅。", "上有啼鴉噪鵲如泣訴，下有藤蔓老樹根據枝相虯。", "想其結締初，匠石巧與造物侔。", "桷榱枅栱不知幾大木，一木牽挽回萬牛。", "山川退聽左右受約束，日月烏兔早暮東西流。", "阿房之旗矗立矮如戟，臨春結綺望仙三閣俱下頭。", "盃埦塊潜培塿而已矣，蹄涔洞庭芥爲舟。", "拄撐霄漢彈壓大千界，下歷梁唐秦隋晉漢周。", "一朝世故有翻覆，禍結祝融回祿與鬰攸。", "灰飛障天烟焰熾，一火三月爛不收。", "遂使觚稜化草莽，丹雘成墟丘。", "吾聞至人侈儉初何心，有茅一把蓋頭便可留。", "何必窮極土木事妖怪，脧削赤子膏血斂以裒。", "是故子劉子，不仙不佛亦不侯。", "視鸞臺鳳閣爲蘧廬，百萬買宅亦夢幻泡影漚。", "江西豈無家，白沙翠竹泉石幽。", "茅簷曝日搔背癢，籬缺牆破手葺修。", "如以天地爲室廬，日月行住坐卧得自由。", "不爲朱門是，不作白屋羞。", "有時騎鯨千里遊汗漫，有時蛤蜊遽食龜殻秋。", "彼昇元閣者亟成而復壞，腸亦不能爲之斷，心亦不能爲之憂。", "造物何足云，此身自贅疣。", "譽堯毀桀未必公是非，丘跖兩窖蟻與螻。"]'),
('d0cb0374-1da0-4e28-9a23-968d8d7d95f6','大雪登越州城樓','劉過','宋','宋诗','song-poetry','','[]','北風吹雪天盡頭，蘇州未了來越州。',96,'全唐诗/poet.song.172000.json','["北風吹雪天盡頭，蘇州未了來越州。", "越人夜乘剡溪舟，烏喙還念棲山不。", "吳人載酒登虎丘，窈窕萬舞雜清謳。", "迤邐茂苑來長洲，不顧麋鹿蘇臺遊。", "我獨忍凍城上樓，欲擒元濟入蔡州。", "鐵騎突出風颼颼，越人驚倒吳人愁。"]'),
('8e73d575-0aaa-4802-81e8-ec54c4aa145b','望幸金陵','劉過','宋','宋诗','song-poetry','','["\u897f\u6e56"]','建業水大勝，武昌魚有味，江東雲不比渭北春天樹。',113,'全唐诗/poet.song.172000.json','["建業水大勝，武昌魚有味，江東雲不比渭北春天樹。", "春天門崒嵂，兩岸石壁立，石頭鍾阜龍虎東西分。", "椎牛釃酒家家準擬犒六軍，翠華不來冷落行宮門。", "泰華不易得，天下關中爲本根。", "懷哉金陵古帝藩，千船泊兮萬馬屯。", "西湖真水真山好，吾君亦豈忘中原。"]'),
('205b6a72-a3cc-4a40-96d6-98804da8707c','艤舟采石','劉過','宋','宋诗','song-poetry','','[]','我昔南遊武昌夏口之山川，赤壁弔古齊安邊。',134,'全唐诗/poet.song.172000.json','["我昔南遊武昌夏口之山川，赤壁弔古齊安邊。", "又嘗北抵鶴唳風聲地，八公山前望淝水。", "誰令艤舟牛渚磯，樓船蔽江憶當時。", "周郎未戰曹瞞走，謝安一笑苻堅危。", "黄雲如屯夜月白，箭痕刀痕滿枯骨。", "健兒飯飽飲馬來，意氣猶雄歌尚烈。", "只今采石還戍兵，諸將奄奄泉下人。", "飯囊盛飯酒甕酒，位去三衙稱好手。"]'),
('76e6e5e6-77fb-4547-ada9-7b543f838e52','題潤州多景樓','劉過','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','金山焦山相對起，挹盡東流大江水。',198,'全唐诗/poet.song.172000.json','["金山焦山相對起，挹盡東流大江水。", "一樓坐斷水中央，收拾淮南數千里。", "西風把酒閑來遊，木葉漸脫人間秋。", "煙塵茫茫路渺渺，神京不見雙淚流。", "君不見王勃才名今蓋世，當時未遇庸人爾。", "琴書落魄豫章城，滕王閣中悲帝子。", "又不見李白才思真天然，時人未省爲謫仙。", "一朝放浪金陵去，鳳凰臺上望長安。", "我今四海行將遍，東歷蘇杭西漢沔。", "第一江山最上頭，天下無人獨登覽。", "樓高思遠愁緒多，樓乎樓乎奈汝何。", "安得李白與王勃，名與此樓長突兀。"]'),
('bbbb5311-1b3c-4e2c-b711-0c943abba34f','清溪閣交胡仲芳韵','劉過','宋','宋诗','song-poetry','','[]','瓊樹枝新梅蕊迸，與君携手清溪問。',96,'全唐诗/poet.song.172000.json','["瓊樹枝新梅蕊迸，與君携手清溪問。", "舊時狎客歌舞場，何似詩人風雪逕。", "溪邊傑閣高崚層，左右華屋連飛甍。", "依稀王謝鳴珂里，彷彿秦箏雲母屏。", "古來繁華各衰歇，只有不磨惟璧月。", "小船何處載愁來，哀怨一聲吹笛裂。"]'),
('a045dc99-b764-4709-8247-711cd30055eb','呈陳總領五首  其一','劉過','宋','宋诗','song-poetry','','[]','旄頭欃槍銳衝擊，殺氣隆隆半天黑。',96,'全唐诗/poet.song.172000.json','["旄頭欃槍銳衝擊，殺氣隆隆半天黑。", "千家悲哀萬家哭，唐鄧征魂招不得。", "北斗移杓向西指，八月風高塞塵起。", "大軍忠義赴襄陽，飛鳥潜魚未知死。", "黔黎殷憂痛無策，願得空中降韓白。", "嗚呼何代無奇才，世間未有黄金臺。"]'),
('80786c32-36ae-4684-bbc1-a483f6d642c5','呈陳總領五首  其二','劉過','宋','宋诗','song-poetry','','[]','太宗造唐剗隋亂，仁義結民過炎漢。',80,'全唐诗/poet.song.172000.json','["太宗造唐剗隋亂，仁義結民過炎漢。", "胡雛負恩逆天紀，忠義回天四方起。", "嗟哉主將失紀律，百萬秦人半爲鬼。", "浮雲改變異今古，不謂前車眼中睹。", "嘗時潼關說歌舒，今日襄陽說皇甫。"]'),
('5e8dd39f-efad-4ab6-9ad4-0114f6884c78','呈陳總領五首  其三','劉過','宋','宋诗','song-poetry','','[]','先生文章擅經緯，戰法淵源如孔子。',80,'全唐诗/poet.song.172000.json','["先生文章擅經緯，戰法淵源如孔子。", "當時蜒獠沸溪洞，一掃蠻風凈如水。", "胸中氣壓萬人將，億萬貔貅資餽餉。", "漢家火德接天統，秘計奇謀堪任相。", "願公飛章告天子，敵疾如風走如鬼。"]'),
('9153b76f-765b-41b0-ac84-d733545d7e1a','呈陳總領五首  其四','劉過','宋','宋诗','song-poetry','','[]','商蚷馳河河可憑，精衛填海海可平。',96,'全唐诗/poet.song.172000.json','["商蚷馳河河可憑，精衛填海海可平。", "物情大忌不量力，立志亦復加專精。", "憶昨痛哭麗正門，白袍黑帽如遊魂。", "中書堂留草茅疏，不賜誅戮光宗恩。", "暮年志氣恥彫喪，廣長陽中吊名將。", "願持上方三寸鐵，細剖赤心告今上。"]'),
('90a3333d-5f93-45a8-923f-1c6c69cd0830','呈陳總領五首  其五','劉過','宋','宋诗','song-poetry','','[]','今上聰明過堯湯，師王忠純如魏王。',80,'全唐诗/poet.song.172000.json','["今上聰明過堯湯，師王忠純如魏王。", "君上戮力殄仇虜，六月戈甲飛冰霜。", "泗州已復漢正朔，議飾寢廟修洛陽。", "草茅螻蟻百無用，山林豈復中原夢。", "敬須洗眼候河清，讀公浯水中興頌。"]'),
('2c63f7d4-dea9-4224-84fd-bd0160a9e1ac','憶鄂渚','劉過','宋','宋诗','song-poetry','','[]','我離鄂渚已十年，吳兒越女空華鮮。',128,'全唐诗/poet.song.172000.json','["我離鄂渚已十年，吳兒越女空華鮮。", "不如上游古形勢，四十餘萬兵籌邊。", "中原地與荆襄近，烈士烈兮猛士猛。", "澤連雲夢寒打圍，城接武昌曉排陣。", "書生豈無一策奇，叩閽擊鼓天不知。", "却思仙人白玉笛，胡床醉倚南樓吹。", "貂蟬兜鍪兩岑寂，若耶溪傍還作客。", "空餘黄鶴舊題詩，醉筆顛狂驚李白。"]'),
('b920a198-1c23-4128-832f-14102b33ecf8','寄竹隠先生孫應時','劉過','宋','宋诗','song-poetry','','[]','蘇州酒滴如真珠，公能醉之酒百壺。',384,'全唐诗/poet.song.172000.json','["蘇州酒滴如真珠，公能醉之酒百壺。", "得閒政恐不來爾，來則倒屣相與俱。", "江山繞樓詩句好，奔走萬變同馳驅。", "大書小草各有能，雷雹震耀鶑花姝。", "當其半醉尚醒在，宛若處女未嫁夫。", "盃行到手湖海歇，翻覆雲雨來須臾。", "羲之屈使坐北面，命騷如役僕與奴。", "角巾斜飄鬢毛出，筆墨顛倒衫袖烏。", "回旋左右如有礙，歸路不記長鬚扶。", "賓儕指摘士竊笑，亦有好事描爲圖。", "或云先生鬰於用，浮沈欲以酒自娛。", "實非能飲姑好客，不時斗酒由人須。", "若予乃是真飲者，糟丘日日鄉無何。", "雖然人亦難意料，未可目以爲酒徒。", "相逢擺畧邊幅盡，胸次開豁無城郛。", "歛藏窮達付之酒，不以禮法自束拘。", "情歸一真舉無僞，滑稽玩世爲通儒。", "飲與不飲無不可，醉醒醒醉同一區。", "癡人之前莫說夢，夢中說夢愈闊迂。", "客來輒飲飲輒醉，此其所以爲竹湖。", "不然他人豈無酒，欲去此脚自懶趨。", "計公之客日百數，結束冠带紛座隅。", "欲言喉牙物如梗，中懷腹非外示愚。", "不如鄙性好誠實，退無取議進不諛。"]'),
('3ba8f6df-e693-41f1-8b7b-2485df5b1b88','明州觀大閲','劉過','宋','宋诗','song-poetry','','[]','書生燈窗困毛錐，說著刀劍何時持。',200,'全唐诗/poet.song.172000.json','["書生燈窗困毛錐，說著刀劍何時持。", "忽聞殷殷金鼓震，驚起塊坐筋骸衰。", "國朝右武重秋獮，列郡敢不張其威。", "萬家駢首遮道看，我亦役逐人後隨。", "武夫櫜鞬陳整整，虎豹拏攫旌旗麾。", "人言吳兒盡脆弱，身髮文斷勇未知。", "不見拔山昔項羽，何必燕趙士始奇。", "軍容燦燦生光輝，悲風慘淡殺氣怒，對此忽作邊頭思。", "熊羆不譁曉爭出，萬騎馳突寒打圍。", "紛紛血毛腥原野，箭竹正墮驚鴻飛。", "將軍仰笑兵軍賀，金帛填委深溝池。", "十年文窮坐百拙，感慨一賦從軍詩。"]'),
('00534b51-535b-4d78-b641-04378a73be60','嘉泰開樂日殿岩涇原郭季端邀遊鳳山自來美堂而上湖亭海觀梅坡石林無不歷覽最後登沖天樓下介亭觀騎射歌舞賦詩而歸','劉過','宋','宋诗','song-poetry','','[]','結束戰袍騎戰馬，冠軍將軍宛如畫。',192,'全唐诗/poet.song.172000.json','["結束戰袍騎戰馬，冠軍將軍宛如畫。", "前呵小駐來美堂，箭去弓鳴飛鳥下。", "青林路轉入岧嶢，湖亭海觀爭爲高。", "誰知鳳舞龍飛外，別有樓閣橫雲霄。", "回旋左右皆遊歷，人物江山兩英特。", "風流標致梅嶺梅，磊落胸襟石林石。", "側身更上天上行，好風吹下笑談聲。", "山神川后領要束，遁走虎豹藏蛟鯨。", "摩挲苔蘚題詩去，萬鼓聲中白題舞。", "衆賓捧酒壽主人，將軍自是擎天柱。", "看山看水時一來，錢塘吳越何小哉。", "指點中原百城在，功名逼人有機會。"]'),
('a6b5689a-7b7d-4669-8264-b1ce072cfa63','古詩','劉過','宋','宋诗','song-poetry','','["\u897f\u6e56"]','凉生几硯窗未糊，秋風射入如相呼。',355,'全唐诗/poet.song.172000.json','["凉生几硯窗未糊，秋風射入如相呼。", "床頭吳鈎作龍吼，便欲乘此擣穹廬。", "丈夫詩膽如斗大，摩挲笑與歌楚些。", "生平柔腸作鐵堅，挑盡寒燈擁襟坐。", "撞鐘打鼓天欲明，鴉未知曉鷄先驚。", "夜來有雨不須問，聽取窗前蕉葉聲。", "老僧慣閒定較可，山色朦朧半烟鎖。", "玉簪委地怕禁持，消息雨中彈指過。", "前回十日得一晴，遠山松檜如潑青。", "癡雲冉冉自辟易，半江滾滾金龍生。", "桂花畢竟終燥薄，强出嬋娟懶梳掠。", "正緣久不見雲生，事半功倍掃蕭索。", "人言快意難得時，世間樂事須生悲。", "轉頭潑墨天地黑，依然雨脚如絲垂。", "山翁豈識神龍志，特地霖淫阻遊意。", "不知金鴨香篆長，擁鼻猶可看文戲。", "重重疊疊添青蒼，誰謂濃翠遶叢篁。", "草木過濕有香意，衣籠篤褥篝籠湯。", "峭岩萬丈苔斑駁，日固甚佳雨不惡。", "晴明晦冥俱可觀，芻豢有時薦藜藿。", "愛山之癡如愛詩，或日或雨皆足奇。", "君不見若把西湖比西子，淡粧濃抹總相宜。"]'),
('6192126b-0c05-4ad8-b773-093adad308bf','上譙江州','劉過','宋','宋诗','song-poetry','','[]','丘公鎮金陵，辛老治京口。',124,'全唐诗/poet.song.172000.json','["丘公鎮金陵，辛老治京口。", "君王神武欲籌邊，九江更使何人守。", "九江太守今譙侯，譙侯德量容九州。", "詩書禮樂晉元帥，意度閒遠和而謀。", "清尊對客溫如玉，同上庾樓望西北。", "胡塵萬里氣壓之，客有白頭何碌碌。", "出門烟水空茫茫，西爲漢沔南衡湘。", "指點武昌在何許，買船又謁吳侯去。"]'),
('09988ef1-5eaf-4a30-9ddd-5e5bae9016c0','觀三疊泉','劉過','宋','宋诗','song-poetry','','[]','五老峰北嵯峩顛，龍泉三疊來自天。',168,'全唐诗/poet.song.172000.json','["五老峰北嵯峩顛，龍泉三疊來自天。", "只因開闢便有此，山雲蔽護經歲年。", "一朝何事失扃鐍，樵者得之人共傳。", "欲往從之人憚遠，險溪絕壑窮攀緣。", "初疑霜崩湧天谷，翻若雲奔不岩宿。", "散爲飛風颺輕煙，垂似銀絲貫珠玉。", "隨風變態難盡名，觀者洞駭心與目。", "清寒侵袂心益爽，清甘熨齒手屢掬，我欲攬之作玉虹。", "似開九丈錦屏風，有若插碧金芙蓉。", "笑騎揮斥凌太空，窮源直到天河東。"]'),
('1e0d03a5-4b1f-48ca-9218-b5945309ea65','贈許從道之子祖孫','劉過','宋','宋诗','song-poetry','','[]','祖孫今年幾年齒，兩髻紞紞垂到耳。',160,'全唐诗/poet.song.172000.json','["祖孫今年幾年齒，兩髻紞紞垂到耳。", "讀書要以六經先，次第漢唐十七史。", "老夫之見竊不然，別有一說爲舉似。", "方今孽胡日衰甚，河朔早暮風塵起。", "腐儒酸寒作何用，國家所欠奇偉士。", "丈夫立身兩字盡，臣子忠孝而已矣。", "吾觀汝相頭面闊，顔色粗厚黑而紫。", "汝翁七十鬢髮轉，汝父科第遲如此。", "與生生死蠹文字，土田官人村夫子。", "不如左彎右挾弓，肉食封侯差快耳。"]'),
('e81e6983-8dd7-4717-9ea3-7d2bc0e5c531','郭帥遺蕨羹','劉過','宋','宋诗','song-poetry','','[]','書生窮無食肉相，老不能官猶崛强。',104,'全唐诗/poet.song.172000.json','["書生窮無食肉相，老不能官猶崛强。", "一杯紫蕨江西羹，萬戶封侯猶未當。", "主人幕下三千士，談王說伯如蜂起。", "日日椎鮮與擊肥，厭飫腥羶飽而已。", "此生只願吃此羹，坐看將軍勛業成。", "金山乞取一片山，要看濈濈兒拳短，窮人便是知田漢。"]'),
('30a50a97-1fea-4cfd-a462-9d46372fa194','舟中','劉過','宋','宋诗','song-poetry','','[]','扁舟去時風怒惡，舟入深溪雪花落。',64,'全唐诗/poet.song.172000.json','["扁舟去時風怒惡，舟入深溪雪花落。", "我行無事有底忙，且向荻花深處著。", "鄰船乞火炮蛤蜊，樽中濁醪把一巵。", "陶陶萬事不復理，凍口且吐寒酸時。"]'),
('a2f18a1a-1867-4234-b027-09eb12c6f6bc','村墅','劉過','宋','宋诗','song-poetry','','[]','俗子有錢村亦樂，秋田米熟歌牛角。',96,'全唐诗/poet.song.172000.json','["俗子有錢村亦樂，秋田米熟歌牛角。", "三家村墅無官方，夜半呼盧笑聲謔。", "尋思我輩不如君，平生讀書徒苦辛。", "遭時喪亂未得志，長策短藁無由伸。", "不如賣劍買牛去，也學此翁村裏住。", "只愁夜半月明時，得意無人和詩句。"]'),
('f857993b-97a9-4424-a1b7-36401d23dd14','題一犁春雨圖後','劉過','宋','宋诗','song-poetry','','[]','阿耘無田食破硯，奉親日糴供朝飯。',96,'全唐诗/poet.song.172000.json','["阿耘無田食破硯，奉親日糴供朝飯。", "有田正恐拙把犂，何得更爲圖畫看。", "汝父名汝汝當知，有田無田未可期。", "有田不耕汝懶病，無田畫田真畫餠。", "畫田之外乃畫牛，捕捉風影何時休。", "頭上安頭入詩軸，全家不應猶食粥。"]'),
('d03e181e-cace-4876-8ffa-dfdf10300896','寄竹隠先生孫應時','劉過','宋','宋诗','song-poetry','','[]','竹湖人之英，劇縣勇自試。',288,'全唐诗/poet.song.172000.json','["竹湖人之英，劇縣勇自試。", "三年種桃李，遺愛及僮稚。", "咸欲父母之，謂吾公之子。", "獨有督郵嫌，見謂不事事。", "瑕疵催科細，欲以三尺治。", "八月羈僦樓，半年縻隠市。", "小窗天日晴，灑落自胸次。", "抖擻舊塵埃，楮札左右置。", "寄傲點畫間，揮染當遊戲。", "人賢世所希，嗜好人共貴。", "車馬閙填門，載酒日紛至。", "大書極豪放，小草亦姿媚。", "歛藏經綸業，進此第一義。", "玉板抄歌詩，石碑刻圖記。", "人家錦爲軸，高壁垂至地。", "襲藏較工拙，臨寫費同異。", "爭如老劉子，落魄一狂士。", "半生不讀書，頗能會其意。", "寒泉驥馬飲，平陸蛟龍起。", "得非久幽憤，於以發奇氣。", "故使鐘鼎疎，自足名一世。", "毛錐久見絕，一見尚能喜。", "酒邊袖予詩，不譽亦不忌。", "有時奪之去，箱篋餘故紙。"]'),
('ffd75933-c42c-4971-ae17-261b83995ac7','同許從道遊涵碧亭','劉過','宋','宋诗','song-poetry','','[]','犯暑日午來，坐到日落歸。',180,'全唐诗/poet.song.172000.json','["犯暑日午來，坐到日落歸。", "松桂叢團團，竹光凈暉暉。", "乳竇成濯纓，綠染身上衣。", "却傾所携酒，對酌老石磯。", "幽鳥當歌者，薦以首山薇。", "歛藏大千界，游戲麈尾揮。", "寺門長安道，結束駟馬肥。", "醉鄉訪腥葷，屏風肉紅圍。", "我亭不關鎖，何人款柴扉。", "掉臂樵擔行，藤蘿自烟霏。", "古所謂迂闊，若此二子稀。", "既非携娉婷，又乏玉鞍飛。", "不知有何好，林泉少焉依。", "境勝更著語，鬼神暗呵譏。", "但知笑他人，不覺自己非。"]'),
('3d3a9ea7-3868-4657-8087-d2bb891051e8','湖學別蘇召叟','劉過','宋','宋诗','song-poetry','','[]','失學老無成，寧不心自慊。',240,'全唐诗/poet.song.172000.json','["失學老無成，寧不心自慊。", "子卿生吾後，逸俊眼未見。", "委身入罏錘，顧此金百鍊。", "有如頑鈍質，豈可便磨剗。", "看君說經旨，不異瓴水建。", "小詩雖有技，風味亦不淺。", "我途未易窮，本自安眠飯。", "俯仰道德光，耳目自濡染。", "凉風忽秋思，一夜窗紙颭。", "平生湖海夢，高興動淮沔。", "追思狂踪跡，失處不可掩。", "醉搥黄鶴樓，一擲賭百萬。", "只今覺衰甚，四海遊已倦。", "所餘習氣在，未了一第欠。", "師友貴隆親，古學當自反。", "小夫事機械，心甚山川險。", "半生客吳粵，生死交情見。", "誰知塵土中，得君初識面。", "何時束裝來，草草衾裘辦。", "密邇戀軒誠，功名期歲晚。"]'),
('fa885b38-8f5f-4a4e-bdb4-3be3d39b221e','答曹元章','劉過','宋','宋诗','song-poetry','','[]','先生修廉隅，日日自驚畏。',48,'全唐诗/poet.song.172000.json','["先生修廉隅，日日自驚畏。", "老夫寄杯酒，狂亦非所諱。", "酸鹹雖不同，各自有正味。", "切莫對癡人，說夢其詞費。"]'),
('11dacf32-deaf-4019-bcfd-ca84a328c47b','古意席上爲徐子宜侍郎賦','劉過','宋','宋诗','song-poetry','','[]','桃李多芳妍，開落如春風。',144,'全唐诗/poet.song.172000.json','["桃李多芳妍，開落如春風。", "託身終自天，花不百日紅。", "殘月望朝日，各自相西東。", "爲君整儀容，照水不照鏡。", "爲君進甘旨，君視肉有堇。", "悲歌欲感君，聲若君不聞。", "金玉徒結君，君看若浮雲。", "父母長嘆息，謂兒好容德。", "脂澤固不妍，珠翠亦無色。", "娉婷艷陽春，自醜不自惜。", "君心河漢流，爲雨不復收。", "妾心東流水，赴海終不止。"]'),
('62ed141c-aaa5-41bf-9017-c3c2f101f7ad','懷古四首爲知己魏倅元長賦兼呈王永叔宗丞戴少望  其一','劉過','宋','宋诗','song-poetry','','[]','言理不可求，吾將訊蒼蒼。',96,'全唐诗/poet.song.172000.json','["言理不可求，吾將訊蒼蒼。", "草木被春華，松柏遭摧傷。", "才高未爲福，名大或不祥。", "煌煌太史公，逸氣橫八方。", "瑞麟出非時，巷伯終見戕。", "晏嬰不可作，鮑叔遥相望。", "發憤著春秋，掩奪日月光。", "文章誠可傳，毀辱庸何傷。"]'),
('3d1213a8-28dd-43ef-a42e-b416f1ef2578','懷古四首爲知己魏倅元長賦兼呈王永叔宗丞戴少望  其二','劉過','宋','宋诗','song-poetry','','[]','高高黄金臺，燕趙爭趨風。',84,'全唐诗/poet.song.172000.json','["高高黄金臺，燕趙爭趨風。", "後來得荆卿，恩禮盡鞠躬。", "丈夫易感激，况在窮厄中。", "縞衣登素車，函谷照已空。", "呂政當野死，燕丹無奇功。", "俠骨化爲鐵，血變海水紅。", "英憤氣不磨，今爲亙天虹。"]'),
('1be4f087-901d-4850-924f-94c18fa81055','懷古四首爲知己魏倅元長賦兼呈王永叔宗丞戴少望  其三','劉過','宋','宋诗','song-poetry','','[]','天地有大經，聖賢實先覺。',72,'全唐诗/poet.song.172000.json','["天地有大經，聖賢實先覺。", "一身萬世則，激厲爲忠樸。", "周勃真少文，汲黯信無學。", "巋然社稷臣，漢脈終有託。", "微臣有揚雄，百拜美新作。", "男兒無英標，焉用讀書博。"]'),
('43189ca3-dcf7-435e-8a63-7b22439a08f1','懷古四首爲知己魏倅元長賦兼呈王永叔宗丞戴少望  其四','劉過','宋','宋诗','song-poetry','','[]','嗣宗黨司馬，徒爾餔其糟。',84,'全唐诗/poet.song.172000.json','["嗣宗黨司馬，徒爾餔其糟。", "叔夜屹玉山，落落崑崙高。", "神仙之可求，蓬島何迢遥。", "湯武非聖人，况識師與昭。", "一死繼結纓，孤竹爭清標。", "蕩陰一杯血，綵鳳無凡毛。", "鴟鳶嗜腐鼠，竟絕終身交。"]'),
('95fac232-509b-4729-bb67-595b2ef9cb5c','雨寒寄姜堯章','劉過','宋','宋诗','song-poetry','','[]','一冬無此寒，十日不得出。',120,'全唐诗/poet.song.172000.json','["一冬無此寒，十日不得出。", "閉門坐如鈎，老去萬感入。", "冶遊亦餘事，况乃燈火畢。", "獨憐鏡湖春，一一各秀發。", "枝條掇芳蕤，慘悴變倉卒。", "凡草何足云，誰吊梅柳屈。", "東城有佳士，詞筆最華逸。", "持此往問之，雨濺袍袴濕。", "蠻箋定送似，來時詩意澀。", "醉裏作蛇鴉，行草倩蘇十。"]'),
('afc47f50-f704-438c-aa7d-35e3d2423c2a','海棠得無字','劉過','宋','宋诗','song-poetry','','[]','步障蜀州錦，重重碧羅襦。',120,'全唐诗/poet.song.172000.json','["步障蜀州錦，重重碧羅襦。", "嬌多不勝春，十五未嬪夫。", "我欲金屋之，貯以貢上都。", "窈窕飛世間，穠李侍綠珠。", "冶容致人疑，詎知非妖狐。", "雉扇開綠綺，君王麗華俱。", "後庭非無花，有寵爭得無。", "八姨淡手抹，試粧不施朱。", "不如玉環翠，睡起姿態殊。", "人言花傾國，况乃下蔡乎。"]'),
('c71a9197-36d5-419a-bac3-eccd9859b277','謁郭馬帥','劉過','宋','宋诗','song-poetry','','[]','千金買駿馬，百金市蛾眉。',288,'全唐诗/poet.song.172000.json','["千金買駿馬，百金市蛾眉。", "長安酒家樓，揮洒驚人詩。", "天子不得臣，公卿氣吞之。", "俯視兒女輩，自詭男子奇。", "誰知金陵都，五年重來茲。", "黑貂日以敝，塵埃鬢成絲。", "故人風雨散，知己今爲誰。", "郭侯山西英，而有熊豹姿。", "巍峩西忠廟，喬木人所思。", "垂芳到雲仍，大將奕世爲。", "兄弟各三衙，父子步武隨。", "萬戶侯冠軍，金印何纍纍。", "雖然平戎策，終鬰未得施。", "方今羣胡擾，似覺虜運衰。", "達靼軍其西，會以蒙國斯。", "蛇豕互吞噬，干戈極猖披。", "盜賊毛蝟起，歛民及刀錐。", "父老思漢官，壺漿傒王師。", "吾君自神武，妙算出籌帷。", "收攬天下才，尺寸不可遺。", "機會一日來，恢復此其時。", "况如郭侯者，禮賢正謙卑。", "使之會雲龍，列城歸指麾。", "安知古中原，不使同驅馳。"]'),
('d5ba1aa1-dabd-4321-a181-d8e15ce3cf9b','悲淮南','劉過','宋','宋诗','song-poetry','','[]','淮民窮到骨，忍復搥其肌。',144,'全唐诗/poet.song.172000.json','["淮民窮到骨，忍復搥其肌。", "不知鐵錢禁，作俑者爲誰。", "行商斷來路，清野多流離。", "主人日邊來，四牡驅以馳。", "或云易之是，或云收之宜。", "幾人困往返，遂逐文書移。", "救焚卒無策，燎火久益滋。", "緬懷征搉初，山海煮摘時。", "雖云便公家，亦復撓其私。", "今者縱虎豹，而使渴與饑。", "蕭蕭蘆葦林，日夜邊風吹。", "悲哉淮南民，持此將安之。"]'),
('799f6098-5081-4f3a-8986-66ccfa4a7c82','俞太古嘗叩閽上書有名天下予甚敬之相會於姑蘇將歸洞庭賦詩以壯其行','劉過','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','人樹俱不堪，歲月駒隙過。',120,'全唐诗/poet.song.172000.json','["人樹俱不堪，歲月駒隙過。", "老懷淚如洗，欲唱誰當和。", "洛陽今少年，弊事勞力破。", "精神經百鍊，鋒銳堅不挫。", "陶名滋惟舊，欹席快一坐。", "氣焰九霄虹，磊落萬玉貨。", "平生牀上下，樓輒讓子卧。", "諸公吮疽爾，不去良可唾。", "洞庭清風熟，肄業情勿惰。", "有詩寄來者，工拙吾能課。"]'),
('bc7027dd-6d44-4d2d-a261-267c6fa88e23','九日鄂渚登高楚觀分得能字','劉過','宋','宋诗','song-poetry','','[]','一山如龍來，起伏力不勝。',120,'全唐诗/poet.song.172000.json','["一山如龍來，起伏力不勝。", "老夫跨其脊，半空欲飛騰。", "尚念同遊人，一二東南朋。", "稅駕爲小留，木末朱欄凭。", "遠水天共闊，秋風響饑鷹。", "城郭千萬家，營壘相依憑。", "年年重陽節，高處盡可登。", "南樓與北榭，遊覽昔所曾。", "插花楚觀上，醉舞僅所能。", "驚倒地上人，白日看上昇。"]'),
('356254c7-a6e7-45d5-adbc-c97728cba7d5','讀書','劉過','宋','宋诗','song-poetry','','[]','重尋讀書盟，筆硯已荆棘。',48,'全唐诗/poet.song.172000.json','["重尋讀書盟，筆硯已荆棘。", "只堪把鉏在，趁此尚有力。", "世途風波惡，躬履見險側。", "敢云賣文活，一錢知不直。"]'),
('70938f63-996c-411d-b960-5adc2878ff24','思故人','劉過','宋','宋诗','song-poetry','','[]','朋從紛如雲，益覺索居甚。',48,'全唐诗/poet.song.172000.json','["朋從紛如雲，益覺索居甚。", "肺腸百憂集，午夜不安寢。", "長恐木石心，化作萋兮錦。", "日暮懷佳人，霜風悄寒凜。"]'),
('59ea9383-08f3-4346-967e-df1c82100550','歸耕','劉過','宋','宋诗','song-poetry','','[]','途窮百無成，或許營菟裘。',48,'全唐诗/poet.song.172000.json','["途窮百無成，或許營菟裘。", "依然大槐宮，蟻穴夢封侯。", "人生眠飯耳，物外亦贅疣。", "科名付諸公，老矣吾歸休。"]'),
('215f275c-9444-47aa-a45d-c7d70c9d5c1e','自嘆','劉過','宋','宋诗','song-poetry','','[]','羣公列屋居，官貴輒鼎台。',48,'全唐诗/poet.song.172000.json','["羣公列屋居，官貴輒鼎台。", "艷粧照珠翠，寒谷噓春回。", "書生窮蹇甚，一笑百禍胎。", "何時業債盡，面目還本來。"]'),
('ed41b139-ed81-495d-9923-318c968196ca','贈鄉人周從龍談命','劉過','宋','宋诗','song-poetry','','[]','廬陵儒萬人，頗亦出青紫。',60,'全唐诗/poet.song.172000.json','["廬陵儒萬人，頗亦出青紫。", "老子三不歸，未省鄉里士。", "暮年罕交遊，僅識子周子。", "風流屬當行，豈止談天爾。", "夜從青樓飲，一醉幾欲死。"]'),
('a1bd03f2-6188-40ee-9e55-0738e5f8578f','送程伯俞赴海陵蘇使君之招','劉過','宋','宋诗','song-poetry','','[]','紅裙族雕筵，一醉當鯨吸。',24,'全唐诗/poet.song.172000.json','["紅裙族雕筵，一醉當鯨吸。", "使君若問余，爲道貧徹骨。"]'),
('3688356e-1415-487d-a523-35fbe5aa26d1','代壽韓平原  其一','劉過','宋','宋诗','song-poetry','','[]','衣鉢登庸復舊氈，文王尚父趙平原。',64,'全唐诗/poet.song.172000.json','["衣鉢登庸復舊氈，文王尚父趙平原。", "自從慶曆到今日，只說開禧初改元。", "朝闢東齋廣東閣，夜看南極照南園。", "九霞觴舉先旬浹，却領千官壽帝垣。"]'),
('e0a8f7ac-a90e-4ded-af2a-1eb5b344825f','代壽韓平原  其二','劉過','宋','宋诗','song-poetry','','[]','際會風雲振古難，十年袖手且旁觀。',64,'全唐诗/poet.song.172000.json','["際會風雲振古難，十年袖手且旁觀。", "要令鄰敵尊裴度，必向東山起謝安。", "一品千齡靈壽杖，五公四世進賢冠。", "功成裂地封留了，却趁赤松盟未寒。"]'),
('6c1e5579-be0b-4482-8d10-2943c6f80996','代壽韓平原  其三','劉過','宋','宋诗','song-poetry','','[]','疇昔張旃過相時，相人爭覩漢官儀。',64,'全唐诗/poet.song.172000.json','["疇昔張旃過相時，相人爭覩漢官儀。", "未能劖刻燕然石，不忍摩挲晝錦碑。", "慷慨欲平千載恨，經營已嘆十年遲。", "要令閲古詩篇偉，好讀車攻復古詩。"]'),
('4c157e53-b80b-4cae-b107-ebb1f48e26af','代壽韓平原  其四','劉過','宋','宋诗','song-poetry','','[]','國付平章衆正開，凌煙錄盡到雲臺。',64,'全唐诗/poet.song.172000.json','["國付平章衆正開，凌煙錄盡到雲臺。", "鴛鴻充序皆桃李，羔雁成羣及草萊。", "强國斷無踰此策，隨車未必盡真材。", "更須妙斡垂綸手，看取靈鼇上手來。"]'),
('1ecfc097-919c-4b5c-ad36-ebb31b6f469c','代壽韓平原  其五','劉過','宋','宋诗','song-poetry','','[]','宇宙之間物物春，戚疎曾不間陶鈞。',64,'全唐诗/poet.song.172000.json','["宇宙之間物物春，戚疎曾不間陶鈞。", "裔分裴皞東西眷，誼篤嗣宗南北鄰。", "中令諸孫難遍識，栖筠俗子老堪親。", "試捐內舉拘攣迹，無異平原十九人。"]'),
('c58bc51a-bf7e-4b9d-84ad-126217a6dc85','壽建康太尉','劉過','宋','宋诗','song-poetry','','[]','萬里寒風一布袍，特將詩句謁英豪。',64,'全唐诗/poet.song.172000.json','["萬里寒風一布袍，特將詩句謁英豪。", "正當武曲臨凡世，恰值驪龍出海濤。", "五馬盡投千歲鶴，六軍急獻萬年桃。", "不因此日滄溟近，一釣那能得巨鼇。"]'),
('072f73aa-90f0-4231-abb1-fa74e470ad01','慶周益公新府','劉過','宋','宋诗','song-poetry','','[]','潭潭新府列名卿，玉带金魚喜氣橫。',64,'全唐诗/poet.song.172000.json','["潭潭新府列名卿，玉带金魚喜氣橫。", "能廣萬間庇寒士，定容駟馬向高閎。", "午橋莊上江山秀，獨樂園中花草榮。", "才作美哉輪奐頒，清臺又奏相星明。"]'),
('4b57169b-5afa-4a5d-b5e4-41a7037b8492','辭周益公','劉過','宋','宋诗','song-poetry','','[]','一曲歸歟浩浩歌，世間無地不風波。',64,'全唐诗/poet.song.172000.json','["一曲歸歟浩浩歌，世間無地不風波。", "人從貧賤識者少，事向艱難省處多。", "紫塞將軍秋佩印，玉堂學士夜鳴珂。", "太平宰相不收拾，老死山林無奈何。"]'),
('d5a900d9-8375-4d8a-b3d2-550038ab162b','代上譙太尉','劉過','宋','宋诗','song-poetry','','[]','叮嚀天語聽傳呼，吒咤雷霆壓萬夫。',64,'全唐诗/poet.song.172000.json','["叮嚀天語聽傳呼，吒咤雷霆壓萬夫。", "澤國使臨殊玉節，彤墀香近惹金爐。", "慶逢龍躍風雲闊，職有蟬聯父子俱。", "援手墜淵餘事耳，故人有子在泥途。"]'),
('671e88ea-dd41-46f9-897a-2936e7638151','謁易司諫  其一','劉過','宋','宋诗','song-poetry','','[]','已死姦諛老舐牛，非才詎可鎮西州。',64,'全唐诗/poet.song.172000.json','["已死姦諛老舐牛，非才詎可鎮西州。", "豺狼逐去羣狐懼，鷙鳥雖多一鶚秋。", "天下孤寒有生意，諸蕃元帥爲清修。", "太平更有當年事，未可廉纖只麽休。"]'),
('aa3550a0-fdc1-4ed4-915a-d9fa7fca908b','謁易司諫  其二','劉過','宋','宋诗','song-poetry','','[]','十載長安五往來，立談無語口慵開。',64,'全唐诗/poet.song.172000.json','["十載長安五往來，立談無語口慵開。", "懶看齷齪隨時士，誰是艱難濟世才。", "韋布豈無堪將相，廟堂未易賤蒿萊。", "上書欲謁平章去，光範門前肯自媒。"]'),
('6492ee43-9dc4-4f5e-83fb-68077c8b0c47','上金陵章侍郎  其一','劉過','宋','宋诗','song-poetry','','[]','龍虎東西兩踞盤，帝教彈壓此山川。',64,'全唐诗/poet.song.172000.json','["龍虎東西兩踞盤，帝教彈壓此山川。", "風行魏蜀三分國，浪靜江淮萬里天。", "半壁旌旗佳麗地，十州鼓角鬰葱邊。", "便當擊楫中流誓，莫使鞭爲祖逖先。"]'),
('c0ecdf6b-4a2a-4d2b-b0da-0be18c5430c7','上金陵章侍郎  其二','劉過','宋','宋诗','song-poetry','','[]','欲上雲霄虎豹關，失身一落市城間。',64,'全唐诗/poet.song.172000.json','["欲上雲霄虎豹關，失身一落市城間。", "經過魯肅捐時廩，想像謝安遊處山。", "去國夢魂愁切切，感時滴淚血斑斑。", "少陵却欲依嚴武，妻嫂輕人未敢還。"]'),
('a12fa457-9ac9-4b43-bd21-5e622a013e6b','上袁文昌知平江五首  其一','劉過','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','骨秀如仙孕武夷，故教手筆世宗師。',64,'全唐诗/poet.song.172000.json','["骨秀如仙孕武夷，故教手筆世宗師。", "隸分唐漢諸家字，句壓陳黄二子詩。", "茂苑雨晴花發處，洞庭霜重橘黄時。", "塵埃俗吏那能此，一段奇功自可知。"]'),
('2ce711d7-5a05-43da-b2fc-d3bb95ce4ddf','上袁文昌知平江五首  其二','劉過','宋','宋诗','song-poetry','','[]','車馬城中早上忙，子城內裏看星郎。',64,'全唐诗/poet.song.172000.json','["車馬城中早上忙，子城內裏看星郎。", "十州已茂圜扉草，一炷初凝畫戟香。", "銅剖虎符新雨露，玉持使節舊風霜。", "明年櫻笋成時候，不在烏臺即玉堂。"]'),
('def92b3d-199c-42dc-9fc6-4f2d44d8d2a7','上袁文昌知平江五首  其三','劉過','宋','宋诗','song-poetry','','[]','欲上姑蘇望虎丘，小邦寧有此風流。',64,'全唐诗/poet.song.172000.json','["欲上姑蘇望虎丘，小邦寧有此風流。", "山川形勢今三輔，人物英雄古列侯。", "華屋鱗鱗冠蓋里，畫橋曲曲管絃樓。", "金陵蜀郡俱疎遠，除却皇都第一州。"]'),
('d0e8f3c8-879f-4e15-bf60-d896f8e77d3a','上袁文昌知平江五首  其四','劉過','宋','宋诗','song-poetry','','[]','行盡淮南日日東，自携隻影入吳松。',64,'全唐诗/poet.song.172000.json','["行盡淮南日日東，自携隻影入吳松。", "人生五馬方知貴，客老諸侯嘆未逢。", "適意秋風寧爲鱠，驚心半夜忽聞鐘。", "十年無計離場屋，說著功名氣拂胸。"]'),
('e153c954-20b8-4f03-8546-b0d0409ded12','上袁文昌知平江五首  其五','劉過','宋','宋诗','song-poetry','','[]','已辦行都欲去船，箇中因得少留連。',64,'全唐诗/poet.song.172000.json','["已辦行都欲去船，箇中因得少留連。", "長安在望空悲日，刺史誰知別有天。", "鼓吹後車喧水際，旌旗前騎簇花邊。", "書生不願懸金印，只覓揚州騎鶴錢。"]'),
('e6d67e56-265c-42a6-8553-39fbc893092d','寄李侍郎','劉過','宋','宋诗','song-poetry','','[]','未照玉堂金炬蓮，地官董正職尤專。',64,'全唐诗/poet.song.172000.json','["未照玉堂金炬蓮，地官董正職尤專。", "常經要足邦中賦，勝算猶煩馬上鞭。", "黄閣少須持紫橐，黑頭早已繼青氈。", "方今講論肥民策，不數橫流地上錢。"]'),
('011b5700-302e-45cd-8df9-e020251c1201','寄湖州趙侍郎','劉過','宋','宋诗','song-poetry','','[]','桑柘村村烟樹濃，新秧刺水麥梳風。',64,'全唐诗/poet.song.172000.json','["桑柘村村烟樹濃，新秧刺水麥梳風。", "舟行苕霅雙溪上，人在蘇杭兩郡中。", "鼓角麗聲相旦暮，旌旗小隊間青紅。", "主人夙有神仙骨，合住水晶天上宮。"]'),
('68755d45-0fee-4e8e-a63a-45a505cfeea9','謁淮西帥','劉過','宋','宋诗','song-poetry','','[]','家住徐城未卜還，歸心正在杳冥間。',64,'全唐诗/poet.song.172000.json','["家住徐城未卜還，歸心正在杳冥間。", "東遊吳魏三千里，西入成都一萬山。", "解使愁腸能寸寸，空令淚眼已斑斑。", "此情不告英雄帥，說向兒曹總是閒。"]'),
('d5dd43ca-3073-43f0-b41c-60a826bee3f2','謁金陵武帥李奭時叩殿帥爲易憲章求書碑  其一','劉過','宋','宋诗','song-poetry','','[]','江南無此一雄藩，穩稱將軍小踞蟠。',64,'全唐诗/poet.song.172000.json','["江南無此一雄藩，穩稱將軍小踞蟠。", "韜畧世傳天下少，棣華鼎峙帥臣難。", "狂胡要使如灰滅，中國先須大器安。", "慘慘塵沙天欲雪，北風凜凜劍芒寒。"]'),
('ff263372-6320-45ce-a06b-6db9f6f8b575','謁金陵武帥李奭時叩殿帥爲易憲章求書碑  其二','劉過','宋','宋诗','song-poetry','','["\u897f\u6e56"]','搏虎屠龍兩未成，蕭然華髮一書生。',64,'全唐诗/poet.song.172000.json','["搏虎屠龍兩未成，蕭然華髮一書生。", "狂蹤潦倒初無定，老氣崢嶸自不平。", "借馬飽遊雲夢澤，歸舟小駐石頭城。", "磨崖已辦中興頌，洗眼西湖看北征。"]'),
('40115b9b-b09b-4dd1-9f8a-22bb25b08ed1','呈李漕  其一','劉過','宋','宋诗','song-poetry','','[]','默禱神仙政隠憂，天心人意已周流。',64,'全唐诗/poet.song.172000.json','["默禱神仙政隠憂，天心人意已周流。", "旱苗已槁七八月，甘雨如期十五州。", "風月冷吹雲夢晚，水花新浸武昌秋。", "異時白粲輸官處，知有豐年萬斛收。"]'),
('f8fdcca6-7fc1-4c0a-b86a-78ebf9e95ca5','呈李漕  其二','劉過','宋','宋诗','song-poetry','','[]','塵埃破帽倦騎馿，一雨窮途快有餘。',64,'全唐诗/poet.song.172000.json','["塵埃破帽倦騎馿，一雨窮途快有餘。", "盆盎自天傾屋瓦，龍蛇平地起階渠。", "冷侵絺綌覺太甚，聲滿梧桐殊不疎。", "口業未償詩有債，夜深燈大小窗虛。"]'),
('efc89b19-02f3-4421-b615-2886a1cebbb7','喜雨呈吳按察  其一','劉過','宋','宋诗','song-poetry','','[]','使君人物舊烏臺，天聽雖高力挽回。',64,'全唐诗/poet.song.172000.json','["使君人物舊烏臺，天聽雖高力挽回。", "湖水欲平江爲退，秋田未旱雨朱來。", "雲隨黄鶴遊何許，風滿南樓亦快哉。", "凉意入秋清可畫，月岩知有桂花開。"]'),
('fc8570b7-1ac4-45ed-9407-cf979310c6e3','喜雨呈吳按察  其二','劉過','宋','宋诗','song-poetry','','[]','黄鶴山前雨乍過，城南草市樂如何。',64,'全唐诗/poet.song.172000.json','["黄鶴山前雨乍過，城南草市樂如何。", "千金估客倡樓醉，一笛牧童牛背歌。", "江夏水生歸未得，武昌魚美價無多。", "掉船亦欲徜徉去，古井而今淡不波。"]'),
('a23550cb-8770-4a21-9723-797216489829','謁京口張守  其一','劉過','宋','宋诗','song-poetry','','[]','未識諸人名已侯，一麾應此滯徐州。',64,'全唐诗/poet.song.172000.json','["未識諸人名已侯，一麾應此滯徐州。", "誰知安石恐未免，欲借寇君何可留。", "遺愛與山同北固，平生作計豈東周。", "上方已聽尚書履，聲在星辰最上頭。"]'),
('48eb7ad1-c1d6-4118-9526-dfda16a6c96e','謁京口張守  其二','劉過','宋','宋诗','song-poetry','','[]','危樓年少記登臨，老矣重來力不禁。',64,'全唐诗/poet.song.172000.json','["危樓年少記登臨，老矣重來力不禁。", "風月欲談嫌許事，山川不險似人心。", "淡烟衰草鄉關遠，細雨黄花節序深。", "雖有小詩行樂處，世無知己爲誰吟。"]'),
('09d2f1ca-67a1-476d-8ee3-0483aa91174a','上劉和州  其一','劉過','宋','宋诗','song-poetry','','[]','戟外梅花角有聲，使君心與月華明。',64,'全唐诗/poet.song.172000.json','["戟外梅花角有聲，使君心與月華明。", "郡當采石今衝要，船在烏江罷戰爭。", "酒賤人家歌袴飲，地寬客子带刀耕。", "太平官府無公事，見說香凝燕寢兵。"]'),
('d1bc6bf4-7a51-437b-90b5-849aaaf922e9','上劉和州  其二','劉過','宋','宋诗','song-poetry','','[]','草樹荒寒晚葉枯，又尋短棹泛焦湖。',64,'全唐诗/poet.song.172000.json','["草樹荒寒晚葉枯，又尋短棹泛焦湖。", "場經古戰心欲折，客老諸侯饑更驅。", "去國寂寥從白眼，籌邊謀畫看洪儒。", "袖詩來謁公應記，曾說襄陽厠座隅。"]'),
('4beb2e10-ecf2-4183-8b3b-69d9b73cc22b','雪中呈顔使君升堅  其一','劉過','宋','宋诗','song-poetry','','[]','一冬所欠者雪耳，造物忽然如戲兒。',64,'全唐诗/poet.song.172000.json','["一冬所欠者雪耳，造物忽然如戲兒。", "清甚牧之江上郡，朗吟次仲館中詩。", "試燈夜靜疎梅落，賣劍村深小麥滋。", "多少使君調燮意，風流自有化工知。"]'),
('09edddc7-bb3c-422c-8d05-fe406dcdeae5','雪中呈顔使君升堅  其二','劉過','宋','宋诗','song-poetry','','[]','陰陽舒慘剎那間，刺使天高見一斑。',64,'全唐诗/poet.song.172000.json','["陰陽舒慘剎那間，刺使天高見一斑。", "人物眼中如水鑑，世情身外不冰山。", "滌除瑕垢與掩匿，彈壓風雲俱澀慳。", "羔酒帳金輸武庫，煮茶蕭寺等僧閒。"]'),
('a8390eea-e96c-4051-bf93-01c3837bb4bc','春雨寄徐東陽','劉過','宋','宋诗','song-poetry','','[]','和州昔有賢從事，今作東陽父母官。',64,'全唐诗/poet.song.172000.json','["和州昔有賢從事，今作東陽父母官。", "百里望風皆畏易，四郊得雨及時難。", "秋成有望米價減，水滿不爭民業安。", "詩句定多公事少，不妨閒寫寄人看。"]'),
('b96882ce-554d-4001-986c-50fdb9082bea','謁江華曾百里  其一','劉過','宋','宋诗','song-poetry','','[]','摳衣三十年前事，曾以諸生傍絳紗。',64,'全唐诗/poet.song.172000.json','["摳衣三十年前事，曾以諸生傍絳紗。", "一國所尊吾白下，雙鳬猶遠令江華。", "時來館學總餘事，老去衣冠懷故家。", "共怪我門郊島外，狂生尚有一劉叉。"]'),
('df7e1279-f784-4b3c-9a22-c04e6fef1bd4','謁江華曾百里  其二','劉過','宋','宋诗','song-poetry','','[]','鬢髮已皤非故吾，依然破帽老騎馿。',64,'全唐诗/poet.song.172000.json','["鬢髮已皤非故吾，依然破帽老騎馿。", "江邊遊子斷腸句，漢殿逐臣流涕書。", "父祖松楸三世塚，弟兄桑梓百年居。", "狐丘未死歸心切，未有相如駟馬車。"]'),
('00c39e84-d55d-4cf2-b6d7-6123817e74bc','贈鄂渚李廣文','劉過','宋','宋诗','song-poetry','','[]','曾去征袍冀主恩，青衫君已染塵痕。',64,'全唐诗/poet.song.172000.json','["曾去征袍冀主恩，青衫君已染塵痕。", "故人然諾千金重，刺史文章一代尊。", "楚澤地多增感慨，峽江天小易黄昏。", "要知後夜相思處，細雨青燈獨掩門。"]'),
('a1702562-a2fd-4dd0-8de8-61da144e5984','贈侯戎','劉過','宋','宋诗','song-poetry','','[]','江淮萬里以詩行，此老胸中有甲兵。',64,'全唐诗/poet.song.172000.json','["江淮萬里以詩行，此老胸中有甲兵。", "何止據鞍猶矍鑠，試教落筆便縱橫。", "逢時有用真才出，知己不遭儒者輕。", "若見英雄今馬帥，爲言劉子尚狂生。"]'),
('c9c0f5e9-c96c-4669-a14c-e38492d23efa','贈趙道卿','劉過','宋','宋诗','song-poetry','','[]','虬髭蝟鬢虎精神，大袖披披二尺巾。',64,'全唐诗/poet.song.172000.json','["虬髭蝟鬢虎精神，大袖披披二尺巾。", "散盡貲財猶結客，畧爲言語便驚人。", "斬蛟橋下懲前失，藏兔窟中甘後塵。", "朝士只今誰著眼，顛狂贏得且安身。"]'),
('057e2ad1-7836-4631-8fce-70be1765ecd8','贈陳時可','劉過','宋','宋诗','song-poetry','','[]','交游半世已公卿，猶抱遺經對短檠。',64,'全唐诗/poet.song.172000.json','["交游半世已公卿，猶抱遺經對短檠。", "負米過於扛鼎重，選官難似上竿行。", "百年母子相依命，一片忠忱誰爲明。", "燈火小樓風雨夜，歲寒時得話平生。"]'),
('85e58ed9-6e92-41d7-8ba8-21e2fd19bf58','呈胡季解','劉過','宋','宋诗','song-poetry','','[]','老病顛狂藥不醫，粗豪駡坐欲何爲。',64,'全唐诗/poet.song.172000.json','["老病顛狂藥不醫，粗豪駡坐欲何爲。", "前生縱使希真是，已死尚存忠簡知。", "顛倒六經鸜鵒舞，瀾翻一曲竹枝詞。", "雖然結襪王生僭，人以此賢張釋之。"]'),
('0b0f1650-20e2-4137-bad2-09e6daa74825','簡季文','劉過','宋','宋诗','song-poetry','','[]','衰鬢蕭騷半欲絲，尚能隨隊作兒嬉。',64,'全唐诗/poet.song.172000.json','["衰鬢蕭騷半欲絲，尚能隨隊作兒嬉。", "棋無殺意從人活，琴有仁聲却自悲。", "落魄陳平歸漢日，中傷張祿入秦時。", "諸公莫作狂夫看，恐是英雄未可知。"]'),
('f2d9f6f5-f242-4f5b-a77a-fbf4ea127810','陪趙丞飲東軒','劉過','宋','宋诗','song-poetry','','[]','冠蓋如雲許後陪，酒紅醫老上吾腮。',64,'全唐诗/poet.song.172000.json','["冠蓋如雲許後陪，酒紅醫老上吾腮。", "轉旋舞影乾坤窄，摇撼歌聲風雨來。", "魚網撒池蓮葉老，龍涎熏坐桂花開。", "羣娥捧勸同文字，商畧西風更百杯。"]'),
('ef176212-9d7d-4253-9c99-f82e4a1c5e02','上張紫微真仙','劉過','宋','宋诗','song-poetry','','[]','真仙元是昔于湖，今在高樓何處居。',64,'全唐诗/poet.song.172000.json','["真仙元是昔于湖，今在高樓何處居。", "非玉不容陪偉論，撥灰猶爲作行書。", "雲霞縹緲來旌節，瓊玖玲瓏聞珮琚。", "幽顯殊途人世隔，冷風吹雨送回車。"]'),
('580d1368-bbdb-4571-958e-b6286fdb9d51','送劉從周教授','劉過','宋','宋诗','song-poetry','','[]','鳳閣鸞臺次第留，此生何必爲身謀。',64,'全唐诗/poet.song.172000.json','["鳳閣鸞臺次第留，此生何必爲身謀。", "工夫到易通三聖，潔白持身第一流。", "桑梓靜思如子少，萍蓬自嘆此生浮。", "還鄉若有過從便，會盡人間只點頭。"]'),
('556cda84-294d-475c-a788-58d208fe3fda','送王東鄉歸天台  其一','劉過','宋','宋诗','song-poetry','','[]','枚數人才難倒指，有如公者又東歸。',64,'全唐诗/poet.song.172000.json','["枚數人才難倒指，有如公者又東歸。", "班行失士國輕重，道路不言心是非。", "載酒青山隨處飲，談詩玉麈爲誰揮。", "歸期趁得東風早，莫放梅花一片飛。"]'),
('67222d39-4ae3-4919-962a-5ca32a757c96','送王東鄉歸天台  其二','劉過','宋','宋诗','song-poetry','','[]','千岩萬壑天台路，一日分爲兩日程。',64,'全唐诗/poet.song.172000.json','["千岩萬壑天台路，一日分爲兩日程。", "事可語人酬對易，面無慚色去留輕。", "放開筆下閒風月，收斂胸中舊甲兵。", "世事看來忙不得，百年到手是功名。"]'),
('c631052b-d956-4a47-8136-1c1af3c7247a','送劉允叔還浙東','劉過','宋','宋诗','song-poetry','','[]','樹倒羣公尚不飛，先生於此獨知幾。',64,'全唐诗/poet.song.172000.json','["樹倒羣公尚不飛，先生於此獨知幾。", "殺身無益事成敗，閉口不言心是非。", "吳渚蓴鱸張翰去，鑑湖風月賀章歸。", "從教血染長安市，一舸清風眠釣磯。"]'),
('fe915613-7a85-4739-9483-86e024900064','送友人得館遊南康','劉過','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匏大從來速售難，依人高戴誤儒冠。',64,'全唐诗/poet.song.172000.json','["匏大從來速售難，依人高戴誤儒冠。", "江南又客諸侯去，梅子愁人四月寒。", "半世光陰旋蟻磨，百年舉子上魚竿。", "世間多少不平事，盍向廬山靜處看。"]'),
('c25dfe72-1f67-43f6-a075-aa97369fad6f','寄張都幹蒙正','劉過','宋','宋诗','song-poetry','','[]','林深葉密綠陰繁，荷漸生芽蒲有根。',64,'全唐诗/poet.song.172000.json','["林深葉密綠陰繁，荷漸生芽蒲有根。", "心事蹉跎過歲月，故人落寞共乾坤。", "舟行蓴菜水雲浦，路入楊梅烟雨村。", "何日扣門尋子去，一樽聊對話黄昏。"]'),
('d0a90cbf-8d49-47a4-a9fc-530eeaf11ee7','寄郭德順','劉過','宋','宋诗','song-poetry','','[]','玉弟金昆共七人，典刑惟有此公存。',64,'全唐诗/poet.song.172000.json','["玉弟金昆共七人，典刑惟有此公存。", "一區未盡揚雄宅，滿座常傾北海樽。", "人品細看真第一，詩篇遠寄不辭頻。", "筍輿歸路無人管，風雨瀟湘行暗村。"]'),
('7810e906-4f8b-4306-a9e5-0b44964572bc','寄郭伯瞻','劉過','宋','宋诗','song-poetry','','[]','聖門力學錢公輔，盛世能書蔡伯喈。',64,'全唐诗/poet.song.172000.json','["聖門力學錢公輔，盛世能書蔡伯喈。", "出處有時安義命，笑談無我見襟懷。", "桂花香滿山堂閙，秋氣清連石洞偕。", "只好放教椽筆健，留將大字寫磨崖。"]'),
('df661674-48bc-481a-a4a2-ef3e1d8c1462','醉中寄王子林','劉過','宋','宋诗','song-poetry','','[]','我頭扶病醉岑岑，履歷糟丘歲月深。',64,'全唐诗/poet.song.172000.json','["我頭扶病醉岑岑，履歷糟丘歲月深。", "行李隨身惟一劍，對花買笑亦千金。", "離鄉別去天涯淚，上塚凄其寒食心。", "風雨閉門無客過，爐香銷盡夜沈沈。"]'),
('a51a1d55-f1d1-494b-8619-40e43db17e3c','寄呂英父  其一','劉過','宋','宋诗','song-poetry','','[]','清時蕭散坐才疎，收拾窮愁却著書。',64,'全唐诗/poet.song.172000.json','["清時蕭散坐才疎，收拾窮愁却著書。", "詩筆有神通夢寐，丰標不俗更清癯。", "黄花細雨圖江路，落日西風處士廬。", "抖擻塵埃舊時帽，不妨覓句倒騎馿。"]'),
('e580f2d2-e30d-4d93-8245-6291c5287410','寄呂英父  其二','劉過','宋','宋诗','song-poetry','','[]','秋到家山冷不知，但驚風露入新詩。',64,'全唐诗/poet.song.172000.json','["秋到家山冷不知，但驚風露入新詩。", "低頭欲拜無東野，滿耳惟聞說項斯。", "骨格昂藏雲鶴瘦，吟哦凄斷雪猿悲。", "文章已得真消息，三十科名未是遲。"]'),
('572c7add-be3e-480d-bd63-c833e54cf82b','寄潘文叔','劉過','宋','宋诗','song-poetry','','[]','不隨千騎過維揚，夜渡關山却一航。',64,'全唐诗/poet.song.172000.json','["不隨千騎過維揚，夜渡關山却一航。", "臭味偶同貧更好，功名有志老何傷。", "自甘商皓來東閣，敢怨陳登卧上床。", "欲擊單于知力倦，歸來且理舊詩囊。"]'),
('10d0ee57-7a2a-479d-8111-58d376bb2fd8','寄程鵬飛','劉過','宋','宋诗','song-poetry','','[]','往事遊邊憶少年，未嘗携刺五侯門。',64,'全唐诗/poet.song.172000.json','["往事遊邊憶少年，未嘗携刺五侯門。", "春風躍馬漢南道，落日椎牛淮上村。", "科舉未爲暮年計，窮途不忍向人言。", "男兒慷慨頭當斷，未有人施可報恩。"]'),
('bde455d5-ab2c-474c-847b-49ebac2bfc35','襄陽雪中寄江西諸友','劉過','宋','宋诗','song-poetry','','[]','雨澀風慳夜向闌，粉花飄撲客衣單。',64,'全唐诗/poet.song.172000.json','["雨澀風慳夜向闌，粉花飄撲客衣單。", "功名有分平吳易，貧賤無聞訪戴難。", "懶逐銀盃行處馬，靜思玉鑑舞時鸞。", "詩成咫尺誰堪寄，當與邦人醉底看。"]'),
('58bf1483-a6b9-433b-a92c-44e77dda87c3','舟次富池寄九江諸公','劉過','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','既無文彩又顛狂，五十餘年夢一場。',64,'全唐诗/poet.song.172000.json','["既無文彩又顛狂，五十餘年夢一場。", "錯認我爲林子晦，也教人喚賀知章。", "樽前鶴翅從誰舞，老去槐花尚自忙。", "船解酒醒人不見，長江萬里水茫茫。"]'),
('5391fb00-97b6-4eab-90b5-fdea6f2df42b','南康邂逅江西吳運判  其一','劉過','宋','宋诗','song-poetry','','[]','一節西來已駭傳，不堪歸去便湘川。',64,'全唐诗/poet.song.172000.json','["一節西來已駭傳，不堪歸去便湘川。", "舟行彭蠡輕文種，酒到潯陽醉樂天。", "臺諫久無公議論，朝廷新有驟除遷。", "臣心畢竟終憂國，不敢瞻烏涕泫然。"]'),
('c583b091-82e3-4eeb-8d19-5e4575efa5e2','南康邂逅江西吳運判  其二','劉過','宋','宋诗','song-poetry','','[]','萬里西征一葉舟，誰憐天地此生浮。',64,'全唐诗/poet.song.172000.json','["萬里西征一葉舟，誰憐天地此生浮。", "初征秋浦雁飛處，又泊江南霜葉洲。", "貧困盡從歸後見，雄豪半爲病來休。", "十年心事閒搔首，荻雨蘆風總是愁。"]'),
('8a7189a7-55cc-43da-829e-25d4843647fe','湖口邂逅張伯豐同行','劉過','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','萬里無人獨自行，得君逆旅尉東征。',64,'全唐诗/poet.song.172000.json','["萬里無人獨自行，得君逆旅尉東征。", "聯同騎馬相先後，共作詩詞迭唱賡。", "僕向洞庭和雪渡，船從湖口带冰撐。", "明年袍綠荆州去，遇有西人好寄聲。"]'),
('2033b771-34a1-4862-bc9f-85b7aa91eb13','西湖別舍弟潤之','劉過','宋','宋诗','song-poetry','','["\u897f\u6e56"]','幾度歸程入夢間，秋鴻社燕兩爲難。',64,'全唐诗/poet.song.172000.json','["幾度歸程入夢間，秋鴻社燕兩爲難。", "西湖半夜風雨急，交泗一床心膽寒。", "落第我爲中酒味，圜橋子亟洗儒酸。", "臂弓秣馬長淮去，莫笑狂夫老據鞍。"]'),
('d7d88325-59b3-4dcd-9e25-e7e47286a5ac','張帥幹席上口占','劉過','宋','宋诗','song-poetry','','["\u897f\u6e56"]','海樹婆娑日出東，一年窮處已殘冬。',64,'全唐诗/poet.song.172000.json','["海樹婆娑日出東，一年窮處已殘冬。", "春衫濕到西湖雨，魂夢覺來長樂鐘。", "梅擲白英樓壓鳳，燈挑紅焰劍纏龍。", "便教分閫持麾去，未愜平時錦鄉胸。"]'),
('717ee2d2-a62b-42c8-b454-f3eb65f70ea9','姑蘇送王武岡不值訪汪仲冕席上口占','劉過','宋','宋诗','song-poetry','','[]','嚴城夜出鼓鼕鼕，畫鷁三更不見蹤。',64,'全唐诗/poet.song.172000.json','["嚴城夜出鼓鼕鼕，畫鷁三更不見蹤。", "何必披雲尋樂廣，真成避雨識茅容。", "蘚花似雪玲瓏白，臘酒如春琥珀濃。", "若使世間無我輩，老夫何處不窮冬。"]'),
('31a840d4-ced3-43eb-9465-d200c7035818','毛積夫席上口占','劉過','宋','宋诗','song-poetry','','[]','夜聽南窗金屈枝，水花凉果似秋時。',64,'全唐诗/poet.song.172000.json','["夜聽南窗金屈枝，水花凉果似秋時。", "人言愛酒陶元亮，坐有能詩無本師。", "顛倒六經鸜鵒舞，瀾翻一曲鷓鴣詞。", "同遊那得輕相笑，恐是長庚未可知。"]'),
('3b725fe9-1504-4fbb-bf07-294bf09568b5','放翁坐上','劉過','宋','宋诗','song-poetry','','[]','林霧霏霏曉意凉，野梔纔放已傳香。',64,'全唐诗/poet.song.172000.json','["林霧霏霏曉意凉，野梔纔放已傳香。", "幸哉世事日相遠，怪底詩情老更狂。", "臘蟻三杯浮重碧，春膏一幅砑輕黄。", "何如放浪形骸外，盡乞江湖作醉鄉。"]'),
('aa4d3f89-e211-4b7d-9f8c-538a4522b7ad','次劉啟之韵','劉過','宋','宋诗','song-poetry','','[]','豪結交游三十年，暮年識子海霜邊。',64,'全唐诗/poet.song.172000.json','["豪結交游三十年，暮年識子海霜邊。", "江西析派詩同社，鴻寶傳家子已仙。", "無用白鬚甘我老，有才青眼望誰憐。", "譬如飄泊湓城下，篁竹蕭疎無管絃。"]'),
('e4e75363-d8a3-493d-a222-87177355fd39','次張昌化合溪新亭韵  其一','劉過','宋','宋诗','song-poetry','','[]','不礙溪流水不平，主人平處主鷗盟。',64,'全唐诗/poet.song.172000.json','["不礙溪流水不平，主人平處主鷗盟。", "兩峰呈秀出天造，雙澗同流到地清。", "尚憶經過曾對酒，欲來登覽恨無名。", "仙凡咫尺紅塵隔，草草題詩亦浪評。"]'),
('f1c1a97b-8bee-4fd5-9816-90fdf97e3079','次張昌化合溪新亭韵  其二','劉過','宋','宋诗','song-poetry','','[]','燕尾溪流上下分，中餘里許地翻平。',64,'全唐诗/poet.song.172000.json','["燕尾溪流上下分，中餘里許地翻平。", "林疎邑屋高低見，水漲舫船來往輕。", "坡老已仙誰傑作，詩人爲縣得重評。", "唐山見說雙溪館，今見雙溪亭又成。"]'),
('d84ebe77-c457-4491-89ec-6146c6ea648f','次呂簿池亭韵','劉過','宋','宋诗','song-poetry','','[]','舉杯邀月到幽塘，八月波心碎夜光。',64,'全唐诗/poet.song.172000.json','["舉杯邀月到幽塘，八月波心碎夜光。", "倒影簾花翻翠色，飛梭錦段織紅芳。", "是中有客供千首，此外無塵染六郎。", "昨夕主人閒立久，一身風露带天香。"]'),
('646c63d7-d574-4106-91e6-63ced8045944','次史良夫寄題雲岫','劉過','宋','宋诗','song-poetry','','[]','輕烟薄霧任渠行，幽壑深崖款我生。',64,'全唐诗/poet.song.172000.json','["輕烟薄霧任渠行，幽壑深崖款我生。", "變化不知天地闊，行藏只要日星明。", "肯同蒼狗移常熟，每爲鳴鳩放好情。", "便趁風雷助霶霈，人間匕筯不須驚。"]'),
('d37867a6-62c7-461d-832c-abf888ee0b21','長干寺用荆公韵','劉過','宋','宋诗','song-poetry','','[]','縈紆一徑試幽尋，花竹禪房未是深。',64,'全唐诗/poet.song.172000.json','["縈紆一徑試幽尋，花竹禪房未是深。", "野水不波清欲凍，崇岡有竹翠成陰。", "琵琶昵昵怨兒語，蘭桂溫溫和水沈。", "詩句欲追前輩後，誰呼粉黛汙清吟。"]'),
('57a63b24-7e63-49af-8826-11407eced8c5','和都幹并柬允道','劉過','宋','宋诗','song-poetry','','[]','老子聲名舊白眉，客窗相款話心時。',64,'全唐诗/poet.song.172000.json','["老子聲名舊白眉，客窗相款話心時。", "相猶忘我吾無法，骨已換仙君有詩。", "蓴菜羹香春冉冉，鹿遊臺上草離離。", "一樽吊古平章看，未羨君王郡牧麾。"]'),
('f3438a81-b29e-443d-b28e-1ac83dee2f27','和印監寺玉簪花','劉過','宋','宋诗','song-poetry','','[]','得得尋芳聽自由，名花先占八分秋。',64,'全唐诗/poet.song.172000.json','["得得尋芳聽自由，名花先占八分秋。", "鷺鷥折股晚風冷，姑射遺簪勝地幽。", "霜葉皺痕羅扇薄，香苞破處雪衣柔。", "一瓶一鉢休岑寂，騎鶴腰錢豈易謀。"]'),
('63adebed-fbf9-4969-9296-b4c4f4fcc05a','咏余商卿梔子花','劉過','宋','宋诗','song-poetry','','[]','香不求知色自然，朝來何許雪華鮮。',64,'全唐诗/poet.song.172000.json','["香不求知色自然，朝來何許雪華鮮。", "如行佛國參知識，未嫁仙姿益凈娟。", "梅子已黄猶夜雨，客遊方倦作春眠。", "地卑山近征衣潤，不費熏爐一炷烟。"]'),
('22996c56-c55b-4553-aaea-483a3146c0dd','與青原正庵老','劉過','宋','宋诗','song-poetry','','[]','倦行老矣徧東南，最後青原識正庵。',64,'全唐诗/poet.song.172000.json','["倦行老矣徧東南，最後青原識正庵。", "無法更求身外說，有禪應向意中參。", "春風遶寺雨花墜，石鼎烹茶泉味甘。", "暫脫塵囂聊稅駕，與君相對款清談。"]'),
('6b288539-b6d4-4f62-bdd5-ea9add96c9fe','簡能仁禮老','劉過','宋','宋诗','song-poetry','','[]','幻身到處等空虛，習氣依然未掃除。',64,'全唐诗/poet.song.172000.json','["幻身到處等空虛，習氣依然未掃除。", "柏樹子邊尋祖意，栴檀林下伴僧居。", "三千世界初無礙，十二時辰得自如。", "牛糞火堆煨芋熟，時時拾得懶殘餘。"]'),
('fd9476ac-d383-43a6-9782-cd985887f58e','贈張道士','劉過','宋','宋诗','song-poetry','','[]','修廊行盡到山齋，中有高人百念灰。',64,'全唐诗/poet.song.172000.json','["修廊行盡到山齋，中有高人百念灰。", "門外不知春出筍，池邊惟見地生苔。", "內丹久鍊龍長在，大藥將成鶴屢來。", "想見年年朝玉帝，眉間一點淡黄開。"]'),
('91e523d4-f1dd-4626-8b5d-294cc6f2a35c','贈永嘉張相士','劉過','宋','宋诗','song-poetry','','[]','青城遊遍蜀中山，歸看公卿飽已諳。',64,'全唐诗/poet.song.172000.json','["青城遊遍蜀中山，歸看公卿飽已諳。", "桀驁稍能兒德祖，興亡何闕百曹參。", "諸公富貴紙上語，滿座風雷終日談。", "我似北人君記取，偶然留滯在東南。"]'),
('ed6e9419-321e-41d7-8396-6dc40a283287','贈術士','劉過','宋','宋诗','song-poetry','','[]','一性圓明俱是佛，四方落魄總成仙。',64,'全唐诗/poet.song.172000.json','["一性圓明俱是佛，四方落魄總成仙。", "逢人只可少說話，賣卜不須多覓錢。", "退一步行安樂法，道三箇好喜歡緣。", "老夫亦欲挑包去，若要相尋在酒邊。"]'),
('0a463344-ed5b-4913-b6a5-09f2a9e6b547','夜思中原','劉過','宋','宋诗','song-poetry','','[]','中原邈邈路何長，文物衣冠天一方。',64,'全唐诗/poet.song.172000.json','["中原邈邈路何長，文物衣冠天一方。", "獨有孤臣流血淚，更無奇傑叫天閶。", "關河夜月冰霜重，宮殿春風草木荒。", "猶耿孤忠思報主，插天劍氣夜光芒。"]'),
('b20c4e27-157f-4966-8da0-9e6db10d3520','題鳳凰臺','劉過','宋','宋诗','song-poetry','','[]','公子飄然有俊才，此臺翻覺在塵埃。',64,'全唐诗/poet.song.172000.json','["公子飄然有俊才，此臺翻覺在塵埃。", "江淮浩渺洲渚沒，鳳鳥寂寥鴻雁來。", "時事不言惟拄笏，書生無用且銜杯。", "生平自厭胸中窄，萬里霜天一日開。"]'),
('c4489123-2dde-4aae-a9ed-ce65dc7d95ce','題池州一覽亭','劉過','宋','宋诗','song-poetry','','[]','塵土中無絕妙詞，不能重賦翠微詩。',64,'全唐诗/poet.song.172000.json','["塵土中無絕妙詞，不能重賦翠微詩。", "淋漓醉墨楊廷秀，慷慨悲吟杜牧之。", "岩壑尚多吾足倦，江山信美客歸遲。", "夕陽鴉點城門閉，堤上鞭垂萬柳絲。"]'),
('57bc7164-44b7-4c9b-81ca-6695317fb3ae','題高遠亭','劉過','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','戍古城荒地勢雄，一亭分半庾樓東。',64,'全唐诗/poet.song.172000.json','["戍古城荒地勢雄，一亭分半庾樓東。", "廬山面目今真識，江漢朝宗此會同。", "司馬宅荒惟苦竹，元規塵遠尚西風。", "胡塵只隔淮河在，誰爲長驅一掃空。"]'),
('6ddbc581-0a21-4634-81ac-3d3453e6f85d','賞心亭','劉過','宋','宋诗','song-poetry','','[]','何人將我此來游，白鷺那知客有愁。',64,'全唐诗/poet.song.172000.json','["何人將我此來游，白鷺那知客有愁。", "如子矜持山玉立，似予迂闊水盤洲。", "塵襟抖擻風雲入，石刻摩挲歲月流。", "惆悵謫仙鸞馭遠，離離別恨黯灘頭。"]'),
('5edb6392-b5be-4d28-9876-97c4c28db8e1','龔山長棲閣','劉過','宋','宋诗','song-poetry','','[]','柳徑參差小葉藍，不知世有府潭潭。',64,'全唐诗/poet.song.172000.json','["柳徑參差小葉藍，不知世有府潭潭。", "揚雄宅就巢枝一，去病家寒繞樹三。", "從臾諸公時爛漫，勸酬終日酒醺酣。", "出門萬里江邊去，塵滿征衫我甚慚。"]'),
('ca3b284d-76bf-4fef-a839-2a84a4ee6c76','南康天開圖畫樓','劉過','宋','宋诗','song-poetry','','[]','樓外烟波渺去鴻，樓頭廬阜翠摩空。',64,'全唐诗/poet.song.172000.json','["樓外烟波渺去鴻，樓頭廬阜翠摩空。", "故知造物鋪張巧，不費丹青點染工。", "赤壁江山橫夜月，輞川庭館卧秋風。", "祇今滿地無圖畫，盡在西灣杳靄中。"]'),
('3b5a33b0-d8ed-4665-8edd-0e5c5eb59dbb','建業酒樓落成預點燈','劉過','宋','宋诗','song-poetry','','[]','高樓百尺久摧頹，輪奐重新亦壯哉。',64,'全唐诗/poet.song.172000.json','["高樓百尺久摧頹，輪奐重新亦壯哉。", "徹夜笙歌催臘盡，聒天簫鼓挽春回。", "都人雜沓揮千鎰，我輩登臨謾一杯。", "京國繁華欣再覩，老來醉眼更堪開。"]'),
('6176b2c5-9d91-4525-a001-bf41c0ada521','洞霄宮','劉過','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','杖藜隨步到瓊宮，滿目幽奇景莫窮。',64,'全唐诗/poet.song.172000.json','["杖藜隨步到瓊宮，滿目幽奇景莫窮。", "山鎖九層雖極遠，洞庭五處自相通。", "侵雲天柱籠朝霧，傍水清陰弄晚風。", "可惜春禽啼曉月，又催行李過江東。"]'),
('fac05d92-5fde-4cf6-b7f6-c00898659121','同許從道登瓊翠閣','劉過','宋','宋诗','song-poetry','','[]','清潭石洞游俱徧，最後來尋此閣遨。',64,'全唐诗/poet.song.172000.json','["清潭石洞游俱徧，最後來尋此閣遨。", "樹木滿林成芘蔭，溪山圍縣恰週遭。", "結交有味貧何害，薄酒雖村飲亦豪。", "明日重陽吾未去，更於何處可登高。"]'),
('b017c69a-0f4f-4912-ab2e-cc0c28a53b6b','同郭殿帥遊鳳山寺探桃李','劉過','宋','宋诗','song-poetry','','[]','廉纖小雨久於梅，喜得晴新亦快哉。',64,'全唐诗/poet.song.172000.json','["廉纖小雨久於梅，喜得晴新亦快哉。", "五色波光麗鳷鵲，十分雲氣近蓬萊。", "旌旗側畔宮牆轉，戈戟叢中武庫回。", "走馬看花生怕晚，果然桃李一山開。"]'),
('bad61f6b-a650-4f67-8a1f-6ed1438f00ee','雪晴遊惠山','劉過','宋','宋诗','song-poetry','','[]','松杉如立密當門，長在山中管送迎。',64,'全唐诗/poet.song.172000.json','["松杉如立密當門，長在山中管送迎。", "棲石草根留雪在，響階簷溜滴春聲。", "簿書撥置君能到，碑刻摩挲眼倍明。", "欲作小詩無好句，只題年月記經行。"]'),
('c68a0f43-33d8-4930-85da-9fd8e79b0b6d','遊岝崿山','劉過','宋','宋诗','song-poetry','','[]','倦遊華髮老飄飄，意氣依然在九霄。',64,'全唐诗/poet.song.172000.json','["倦遊華髮老飄飄，意氣依然在九霄。", "努力尚能登岝崿，廢詩那可寄參寥。", "欹斜古寺雲爲屋，穩帖溪流石架橋。", "安得柳間桃李動，丹青吾欲畫生綃。"]'),
('ac46f166-fa59-4ee7-884d-60bcf8fd8520','登白雲絕頂','劉過','宋','宋诗','song-poetry','','[]','雨罷新晴怯宿寒，一簾秋色滿闌干。',64,'全唐诗/poet.song.172000.json','["雨罷新晴怯宿寒，一簾秋色滿闌干。", "欲窮大地三千界，須上高峰八百盤。", "累世避人秦婦子，一時驚客漢衣冠。", "塵寰元有清吟處，便作三山蓬島看。"]'),
('c5e62217-bfd5-4f6c-b8f5-9561097d427a','登清凉臺寺','劉過','宋','宋诗','song-poetry','','[]','江南江北許多山，到處登臨得凭欄。',64,'全唐诗/poet.song.172000.json','["江南江北許多山，到處登臨得凭欄。", "老木漸丹霜有信，怒濤衝岸水生寒。", "倦遊半世烏三匝，往事千年指一彈。", "落日正西催上馬，依依回首問長安。"]'),
('a4f7413c-ff56-402a-8c70-9a7ff274a29f','又借韵小行','劉過','宋','宋诗','song-poetry','','[]','杖屨尋詩問所由，一天草木葉知秋。',64,'全唐诗/poet.song.172000.json','["杖屨尋詩問所由，一天草木葉知秋。", "天低雲淡村村好，雨過山深物物幽。", "斑駁岩頭苔蘚濕，鈎輈樹尾鳥聲柔。", "眼前不見市朝事，始笑從前利祿謀。"]'),
('7f29956b-aca0-4d54-9e27-259717ae78b5','大麓道中','劉過','宋','宋诗','song-poetry','','[]','竹輿啞軋曉烟收，蒼玉岩巉萬里秋。',64,'全唐诗/poet.song.172000.json','["竹輿啞軋曉烟收，蒼玉岩巉萬里秋。", "路轉羊腸回草徑，溪分燕尾遶沙洲。", "愛山有癖須還債，覓句無工是不休。", "晴得幾時尤更好，桂花蓓蕾作針頭。"]'),
('62c5ed28-f407-453c-bf9a-59c66579dd1c','登凌雲高處','劉過','宋','宋诗','song-poetry','','[]','攝衣更上一層樓，纔到層霄最上頭。',64,'全唐诗/poet.song.172000.json','["攝衣更上一層樓，纔到層霄最上頭。", "方識乾坤真轉轂，好知身世付虛舟。", "九秋草木嵐烟濕，萬里山川海氣浮。", "更欲杖藜窮望眼，眼中何處認神州。"]'),
('6fd62a2c-093b-4bd0-a4d7-a605c35abfb2','過泰和宮','劉過','宋','宋诗','song-poetry','','[]','林塘漠漠亂花飛，門掩蒼苔過客稀。',64,'全唐诗/poet.song.172000.json','["林塘漠漠亂花飛，門掩蒼苔過客稀。", "蝴蝶與身俱是夢，杜鵑憐我幾時歸。", "徐行便當籃輿穩，清話何妨羽扇揮。", "四十九年蘧伯玉，此生畢竟是邪非。"]'),
('10f2dc16-7236-41b0-9d18-738148da269f','過西興','劉過','宋','宋诗','song-poetry','','[]','奔濤洶涌欲騎鯨，船去錢塘棹不停。',64,'全唐诗/poet.song.172000.json','["奔濤洶涌欲騎鯨，船去錢塘棹不停。", "何日子胥鞭楚墓，傷時周顗泣新亭。", "蚊虻過耳蠻音惡，蝦蟹薰人海氣腥。", "吳下阿蒙非昔日，眼高相對有誰青。"]'),
('c5e2973b-db6a-4fb7-824b-89af85e5c912','遊北墅','劉過','宋','宋诗','song-poetry','','[]','客裏浮沈又一年，春風北墅故依然。',64,'全唐诗/poet.song.172000.json','["客裏浮沈又一年，春風北墅故依然。", "路邊花有香相引，澗下松無色可憐。", "仙鶴舞隨人擊筑，神鴉飛傍客歸船。", "何須故掃霜前葉，却趁東風學曉烟。"]'),
('bb8f20b6-d79d-4916-bfc6-3a4f8d3c545b','呂氏山堂喜雨','劉過','宋','宋诗','song-poetry','','[]','凉滿蒲萄磊落枝，倦遊來此亦忘歸。',64,'全唐诗/poet.song.172000.json','["凉滿蒲萄磊落枝，倦遊來此亦忘歸。", "溝渠水活龍蛇動，樹木月明烏鵲飛。", "欣減黄粱新米價，愁生白苧舊征衣。", "風流却扇團圞坐，一夜談兵玉麈揮。"]'),
('535966bc-aeda-4573-9176-6d59e1dce3cc','雨作妨登山  其一','劉過','宋','宋诗','song-poetry','','[]','莫笑林宗折角巾，雨師堅壁助愁城。',64,'全唐诗/poet.song.172000.json','["莫笑林宗折角巾，雨師堅壁助愁城。", "菰蒲乍冷橫烟淡，鷗鷺驚秋立水輕。", "山勢欲窮猶有路，溪流似斷又聞聲。", "好懷聊擬携筇去，政愜農夫荷笠耕。"]'),
('28d87bb5-14e0-4fff-b8d3-56252f7afbe2','雨作妨登山  其二','劉過','宋','宋诗','song-poetry','','[]','暑風快處岸烏巾，去去扁舟遠帝城。',64,'全唐诗/poet.song.172000.json','["暑風快處岸烏巾，去去扁舟遠帝城。", "過眼溪山含霧重，多情草木逗烟輕。", "琴書正要疎人事，禽鳥跫然聽履聲。", "莫恨漏天霖雨惡，雞窗好好筆爲耕。"]'),
('5330cc5b-bb6c-48b1-b626-0d2e08e4db36','雨作妨登山  其三','劉過','宋','宋诗','song-poetry','','[]','杖履飄然不整巾，緣何問得梵王城。',64,'全唐诗/poet.song.172000.json','["杖履飄然不整巾，緣何問得梵王城。", "淡烟翠濕千螺皺，微日烟消一紙輕。", "隔山鳥語如人語，觸處風聲若水聲。", "見說一犁今已足，笑歌蓬首餉夫耕。"]'),
('08a9c5cb-3e3e-4b36-a9e6-8536bfa13393','掛搭松窩','劉過','宋','宋诗','song-poetry','','[]','十年南北走東西，豪氣崢嶸老不衰。',64,'全唐诗/poet.song.172000.json','["十年南北走東西，豪氣崢嶸老不衰。", "快斬妖魔三尺劍，朗吟風月五言詩。", "山無福地吾焉往，神有靈丹世不知。", "却恐松窩知此意，一絲掛搭去何疑。"]'),
('c4a6e389-a997-46d0-b143-4e68bceb2a3c','鹽官權學','劉過','宋','宋诗','song-poetry','','[]','人生百歲等歡悲，已判行藏任所之。',64,'全唐诗/poet.song.172000.json','["人生百歲等歡悲，已判行藏任所之。", "筆硯重尋驚夢覺，課程聊復伴兒嬉。", "荒原傍海多閒趣，閉戶觀書有倦時。", "破帽塵埃今已矣，不妨更借蹇馿騎。"]'),
('d0aed39e-e26a-46ad-835d-1480656d8ae8','鹽官借沈氏屋','劉過','宋','宋诗','song-poetry','','[]','借宅西頭對短檠，一燈相對紙窗橫。',64,'全唐诗/poet.song.172000.json','["借宅西頭對短檠，一燈相對紙窗橫。", "煨爐火活蹲鴟熟，沸鼎茶香蚯蚓鳴。", "萬卷讀書空老大，諸生蓋世盡功名。", "依稀草木還鄉去，便向夜深聞雨聲。"]'),
('cbc7ebb8-7b82-4e91-92b4-446ad5840529','入徽州','劉過','宋','宋诗','song-poetry','','[]','白傅庭前正解船，夢中忽已過番川。',64,'全唐诗/poet.song.172000.json','["白傅庭前正解船，夢中忽已過番川。", "紅塵冉冉行天上，黄道駸駸近日邊。", "石洞歙溪俱可硯，山肥徽路總堪田。", "把茅便欲僑居去，奈此功名未了緣。"]'),
('faa21090-04cc-4566-b2b9-b8b49e4591ab','寓公坊','劉過','宋','宋诗','song-poetry','','[]','秋風漸漸正吹凉，似報歸期未欲忙。',64,'全唐诗/poet.song.172000.json','["秋風漸漸正吹凉，似報歸期未欲忙。", "尋路竹間深入寺，泊船沙外遠依莊。", "小槽壓酒珠紅滴，新飯炊粳雪白香。", "更聽夜來思遠浦，軍聲十萬似錢塘。"]'),
('4b96e923-18ec-4af5-a969-4e57f31b1d87','六合道中','劉過','宋','宋诗','song-poetry','','[]','十年曾記此來游，有策中原一戰收。',64,'全唐诗/poet.song.172000.json','["十年曾記此來游，有策中原一戰收。", "蒲柳易凋嫌勢去，金湯無用卒和休。", "悲風髣髴鳴刁斗，缺月參差照敵樓。", "廟食封侯何日事，不堪老馬又滁州。"]'),
('d1082633-35f2-48fb-9ce9-1c1a7581b1f6','醉中偶成','劉過','宋','宋诗','song-poetry','','[]','小院蒲萄月架東，舞腰忙趁鼓聲雄。',64,'全唐诗/poet.song.172000.json','["小院蒲萄月架東，舞腰忙趁鼓聲雄。", "詩成綵筆分題後，人在金釵賭令中。", "秋葉冷吟風浩蕩，晚林烘透日玲瓏。", "腰間若佩滁州印，定有人呼作醉翁。"]'),
('72e094e5-f6f3-465c-a273-d93e772ef5b7','無錫道觀','劉過','宋','宋诗','song-poetry','','[]','門外紅塵市一廛，買瓜買李興悠然。',64,'全唐诗/poet.song.172000.json','["門外紅塵市一廛，買瓜買李興悠然。", "樹根石透月灑落，殿閣屋多風折旋。", "賣墨道人勤置酒，能詩老子欲飛仙。", "髑髏南面蛆蟲輩，鵬鷃逍遥各自天。"]'),
('728186bc-d2ac-496d-90a9-08f5c3a34af1','招義銘育王見佛照','劉過','宋','宋诗','song-poetry','','[]','豪傑書生懶散仙，小菴藏跡得安閒。',64,'全唐诗/poet.song.172000.json','["豪傑書生懶散仙，小菴藏跡得安閒。", "禪曾勘破諸公去，詩在推敲一字間。", "夜雨滴殘梧葉老，夕陽行處水花慳。", "買舟便欲乘風去，孤絕同游海島山。"]'),
('22718ea9-d0a2-4443-b035-8dcd36813b21','金陵雪中','劉過','宋','宋诗','song-poetry','','[]','風幻寒威夜撲人，曉看雲脚四垂陰。',64,'全唐诗/poet.song.172000.json','["風幻寒威夜撲人，曉看雲脚四垂陰。", "牧羝塞上功名淚，騎馬藍關竄逐心。", "冷面不春愁菀結，凍鬚如鐵恐蕭森。", "晝爐醉撥灰爲字，不爲閒思煖帳金。"]'),
('428625c0-0851-48c5-b21d-238f0991bef5','對雪效樂天','劉過','宋','宋诗','song-poetry','','[]','匣中雷吼一長劍，溪上月明多少舟。',64,'全唐诗/poet.song.172000.json','["匣中雷吼一長劍，溪上月明多少舟。", "無賊可平閒李愬，有人不訪倦王猷。", "銀杯縞带從渠便，瑶樹瓊林得自由。", "衣敝獨嫌灰絮料，簾高想見月垂鈎。"]'),
('4828c9a4-539d-4338-939e-46da5f18908e','觀白鷺洲風濤','劉過','宋','宋诗','song-poetry','','[]','一聲雷鼓挾風威，頃刻衝濤沒釣磯。',64,'全唐诗/poet.song.172000.json','["一聲雷鼓挾風威，頃刻衝濤沒釣磯。", "行客駭看銀漢落，陽侯驚起玉山飛。", "蛟龍便爾爭先化，鷗鷺茫然失所依。", "安得長竿入吾手，翩然東海釣鼇歸。"]'),
('af8e0bfd-e458-4c16-89b2-5c6147aa2e19','偕陳調翁龍山買舟待夜潮發','劉過','宋','宋诗','song-poetry','','[]','來逢春雨長魚苗，去見秋風擘蟹螯。',64,'全唐诗/poet.song.172000.json','["來逢春雨長魚苗，去見秋風擘蟹螯。", "久矣歸心到鄉國，依然水宿伴漁舠。", "一天如許皆明月，二客所須惟濁醪。", "今夜四更潮有信，更須留眼看銀濤。"]'),
('a65fb872-cdeb-43f2-9a4e-31f8f2d41f53','發舟','劉過','宋','宋诗','song-poetry','','[]','寶氣亭前首問途，清飈日日送籧篨。',64,'全唐诗/poet.song.172000.json','["寶氣亭前首問途，清飈日日送籧篨。", "丹楓無處不愁客，白鷺有情如導吾。", "青竹閒垂任子釣，紫鱗時掣季鷹魚。", "烟波渺渺江天晚，水宿又聽溪鳥呼。"]'),
('75e1b58b-bcc7-452b-b101-020b00c2e95a','舟中偶作','劉過','宋','宋诗','song-poetry','','[]','日日拖舟上碧溪，寒灘水淺草離離。',64,'全唐诗/poet.song.172000.json','["日日拖舟上碧溪，寒灘水淺草離離。", "尺書雁斷歲行盡，五兩風輕帆去遲。", "白鷺導吾如有志，丹楓愁客亦何爲。", "關頭要趁梅花約，更著寬程五日期。"]'),
('6f0a2a21-6310-4572-b7aa-9758f76175d9','舟中','劉過','宋','宋诗','song-poetry','','[]','下水南風未覺難，我舟不動穩如山。',64,'全唐诗/poet.song.172000.json','["下水南風未覺難，我舟不動穩如山。", "東西日月尋常事，變化烟雲頃刻間。", "沙鳥似驚皆退避，林巒如畫亦渾閒。", "歸期只欲長安近，屈指何時到北關。"]'),
('23e7ac8d-72c6-429c-be13-0347329f7ba3','霜寒舟中','劉過','宋','宋诗','song-poetry','','[]','展轉牛衣冷不禁，著人無奈曉寒侵。',64,'全唐诗/poet.song.172000.json','["展轉牛衣冷不禁，著人無奈曉寒侵。", "由來十月清霜重，况乃荒村白露深。", "有客分金來橘社，何人塗血染楓林。", "不堪青女來料理，折盡衰翁一片心。"]'),
('2c9e8c8b-ad55-470c-bbc3-6eea24bed671','春日即事  其一','劉過','宋','宋诗','song-poetry','','[]','久客無人問所須，小窗翻得逐癡愚。',64,'全唐诗/poet.song.172000.json','["久客無人問所須，小窗翻得逐癡愚。", "黄昏以後酒三盞，白日之間飯兩盂。", "穀雨笋茶俱俊美，條風杞菊競甘腴。", "先賢且謂可行樂，况是平生山澤癯。"]'),
('75f73abd-3ef6-4a17-9881-b13c8b30b6f3','春日即事  其二','劉過','宋','宋诗','song-poetry','','[]','出門雖是欠陶朱，便使關門亦可居。',64,'全唐诗/poet.song.172000.json','["出門雖是欠陶朱，便使關門亦可居。", "物價甚廉常食肉，傭貲極省易鈔書。", "已安櫟社如無用，若比叢林似有餘。", "歸與未歸天上事，只消如此看何如。"]'),
('bdf9251b-ebbf-48b2-9fce-fd439eeb9c33','幽居','劉過','宋','宋诗','song-poetry','','[]','對面滄浪可濯纓，不思泛舸出春城。',64,'全唐诗/poet.song.172000.json','["對面滄浪可濯纓，不思泛舸出春城。", "浮沈枌社何人重，俯仰茅簷是事輕。", "玉蕊連屏寒徙倚，蒲萄上架月縱橫。", "江湖老矣無他願，只欲清陰便得成。"]'),
('79357b15-bcb2-40f4-b8de-2f333fa00aaa','自述  其一','劉過','宋','宋诗','song-poetry','','[]','扁舟送客出姑蘇，晚泊吳江夜雨餘。',64,'全唐诗/poet.song.172000.json','["扁舟送客出姑蘇，晚泊吳江夜雨餘。", "波浪稍平風力定，青黄相間橘林疎。", "匆忙旅館催行酒，草率杯盤旋買魚。", "與我壁間書歲月，無人爲作小王書。"]'),
('ad7e4cbf-35d7-4927-8763-b4866519e79e','自述  其二','劉過','宋','宋诗','song-poetry','','[]','精神凋耗鬢毛衰，劫火光中第幾回。',64,'全唐诗/poet.song.172000.json','["精神凋耗鬢毛衰，劫火光中第幾回。", "無可奈何教老去，有時猛省忽愁來。", "師崇道學原非僞，客寄蘇州却類獃。", "明日重陽又佳節，得錢且醉菊花杯。"]'),
('c2499613-49d1-4ce7-845e-b33397eecdca','自慚','劉過','宋','宋诗','song-poetry','','[]','一榻留人去便垂，自慚非友亦非師。',64,'全唐诗/poet.song.172000.json','["一榻留人去便垂，自慚非友亦非師。", "初無伎倆惟貪酒，遇有工夫或賦詩。", "曬日棗林紅磊落，響風桐葉碧參差。", "人家正做鱸魚鱠，老子秋來却自悲。"]'),
('41c57ff1-ac8a-4128-954c-a7810761d337','下第','劉過','宋','宋诗','song-poetry','','[]','蕩蕩天門叫不應，起尋歸路嘆南行。',64,'全唐诗/poet.song.172000.json','["蕩蕩天門叫不應，起尋歸路嘆南行。", "新亭未必非周顗，宣室終須召賈生。", "振海潮聲春洶涌，插天劍氣夜崢嶸。", "傷心故國三千里，纔是餘杭第一程。"]'),
('75ff7cf1-c546-4055-a7dc-5d91f21fc716','歲晚','劉過','宋','宋诗','song-poetry','','[]','手種疎梅已發妍，相從三過客中年。',64,'全唐诗/poet.song.172000.json','["手種疎梅已發妍，相從三過客中年。", "吾生豈得須如意，隨處何妨且信緣。", "風月心多時小醉，軒裳夢少且閑眠。", "萬人海裏能如此，是自在禪并散仙。"]'),
('be7fedea-feb6-4fcd-be8c-495d9531e278','代上韓開府','劉過','宋','宋诗','song-poetry','','[]','位號鈞樞等，元勳閥閲傳。',48,'全唐诗/poet.song.172000.json','["位號鈞樞等，元勳閥閲傳。", "九重新洗日，一柱獨擎天。", "戰守籌帷外，遷除化筆邊。", "衣冠圖盛事，不記幾貂蟬。"]'),
('350cbbbe-8e08-405f-a0cb-22a316280fea','上周少保  其一','劉過','宋','宋诗','song-poetry','','[]','游戲公孤了，歸來不愛名。',48,'全唐诗/poet.song.172000.json','["游戲公孤了，歸來不愛名。", "昌黎前進士，司馬老先生。", "有節花宜晚，無波水自平。", "翳雲遮不得，南極益精明。"]'),
('bf776911-453d-4921-a135-f63bb80d23e3','上周少保  其二','劉過','宋','宋诗','song-poetry','','[]','早被儒冠誤，依稀老更侵。',48,'全唐诗/poet.song.172000.json','["早被儒冠誤，依稀老更侵。", "科名數行淚，岐路一生心。", "自惜亡猿木，誰憐躍冶金。", "使無鐘鼎志，何地可山林。"]'),
('9305e196-4736-4e8c-b319-50cfbe37566e','初伏闕上書得旨還鄉上楊守秘書  其一','劉過','宋','宋诗','song-poetry','','[]','郡大廬陵古，分符得秘郎。',48,'全唐诗/poet.song.172000.json','["郡大廬陵古，分符得秘郎。", "息爭民珥筆，課最米連檣。", "水隔蓬山遠，風凝畫戟香。", "少須官事了，歸去玉爲堂。"]'),
('f5e001b9-5248-4279-870f-6a76c1a4abc6','初伏闕上書得旨還鄉上楊守秘書  其二','劉過','宋','宋诗','song-poetry','','[]','百計歸無策，誰知禍有胎。',48,'全唐诗/poet.song.172000.json','["百計歸無策，誰知禍有胎。", "江河周顗泣，城郭令威來。", "訪舊鬚俱白，過家心欲摧。", "故鄉非不好，不是錦衣回。"]'),
('a5b81f09-5c1e-46ab-b3f1-52de8a52062b','上范秘監  其一','劉過','宋','宋诗','song-poetry','','[]','郡大當塗古，分符得少蓬。',48,'全唐诗/poet.song.172000.json','["郡大當塗古，分符得少蓬。", "威如烏府在，令與繡衣同。", "鈴閣紬書外，花村賣劍中。", "少需撫摩意，來作玉堂翁。"]'),
('055f8c44-f875-4894-897c-5a23ec8ef57a','上范秘監  其二','劉過','宋','宋诗','song-poetry','','[]','疇昔經行路，黄山更一過。',48,'全唐诗/poet.song.172000.json','["疇昔經行路，黄山更一過。", "天涯知己少，歲晚客愁多。", "路斷車生角，冰堅水不波。", "使君森畫戟，聞此盍如何。"]'),
('b113cc9c-27e8-4b99-aa98-9d679a484ca9','寄周益公','劉過','宋','宋诗','song-poetry','','[]','猥賤詩難化，讙囂語不齊。',48,'全唐诗/poet.song.172000.json','["猥賤詩難化，讙囂語不齊。", "長途難短堠，小雨易深泥。", "逐利如爭鹿，傷人類割雞。", "心雖懷益國，夢亦畏江西。"]'),
('7c328ff1-3068-4d86-8e3e-c97f487bdce9','和大參相公  其一','劉過','宋','宋诗','song-poetry','','[]','松深烟鎖逕，月冷水明樓。',48,'全唐诗/poet.song.172000.json','["松深烟鎖逕，月冷水明樓。", "日漲滄溟窄，山陰古木秋。", "琴書超物表，氣宇識神遊。", "突兀東南壯，乾坤第一流。"]'),
('c0b1edfa-2e9b-406c-bbd7-3f73f514e9a6','和大參相公  其二','劉過','宋','宋诗','song-poetry','','[]','氣壓三千界，雲橫百尺樓。',48,'全唐诗/poet.song.172000.json','["氣壓三千界，雲橫百尺樓。", "地靈絕興替，木老閲春秋。", "杖屨逍遥步，琴書汗漫遊。", "利名空役役，回首愧禪流。"]'),
('1c52988b-4303-49e8-943f-996fbd97ec74','和大參相公  其三','劉過','宋','宋诗','song-poetry','','[]','山邃龍蟠屈，江昏蜃吐樓。',48,'全唐诗/poet.song.172000.json','["山邃龍蟠屈，江昏蜃吐樓。", "撞鐘千百指，閲世八千秋。", "僧笑衣冠累，天容杖屨遊。", "松梢清影碎，薄月带沙流。"]'),
('1477ce67-069d-4bdb-9ef0-965d5fadaa4b','和子純韵','劉過','宋','宋诗','song-poetry','','[]','橋下水如箭，驚奔萬古號。',48,'全唐诗/poet.song.172000.json','["橋下水如箭，驚奔萬古號。", "溪毛翻碧带，石蘚襯銀濤。", "天外千層秀，雲低數尺高。", "垂垂興偏惡，蓬鬢爲詩搔。"]'),
('241d12d0-3cc0-4b7e-baa5-b4b6605829e1','贈劉叔擬招山','劉過','宋','宋诗','song-poetry','','[]','不醉何勞飲，無詩底用吟。',48,'全唐诗/poet.song.172000.json','["不醉何勞飲，無詩底用吟。", "百年爲客老，一念愛鄉心。", "草路青原淚，烟波白鷺心。", "班超歸未得，愁見舊家林。"]'),
('f944d24e-1646-4260-acfc-930074266f2a','送楊伯子','劉過','宋','宋诗','song-poetry','','[]','天下少奇士，况乎吾一州。',48,'全唐诗/poet.song.172000.json','["天下少奇士，况乎吾一州。", "逢人問姓字，知子有源流。", "蘭砌多黄口，蓬山半白頭。", "誠齋知未可，喚作小坡休。"]'),
('072f7f4e-4d0f-4f2f-822c-52ffd91c5a62','送金陵胡撫幹仲芳  其一','劉過','宋','宋诗','song-poetry','','[]','故家凋喪後，初識澹庵孫。',48,'全唐诗/poet.song.172000.json','["故家凋喪後，初識澹庵孫。", "玉樹明庭角，冰澌吐話言。", "荆州得上幕，楚壤带中原。", "我欲附舟去，白魚朱橘繁。"]'),
('884c9318-e6b0-4f42-8435-151aa8765ff8','送金陵胡撫幹仲芳  其二','劉過','宋','宋诗','song-poetry','','[]','共醉百斛酒，千金一笑傾。',48,'全唐诗/poet.song.172000.json','["共醉百斛酒，千金一笑傾。", "寄情桃葉渡，弔古石頭城。", "戰守籌雄地，更番出戍兵。", "甕天留不住，圖畧遂西征。"]'),
('d06ae666-a6d4-40ca-a557-a14421d932ff','都中留隨州李判官','劉過','宋','宋诗','song-poetry','','[]','幸自東南好，西歸未可忙。',48,'全唐诗/poet.song.172000.json','["幸自東南好，西歸未可忙。", "茶添橄欖味，酒借蛤蜊香。", "絕品宜春醉，新烹趁日長。", "倒囊煩厚載，歸遣北人嘗。"]'),
('db14d66a-d54c-4297-9cb1-4cc028a1444d','江頭送趙教即席同賦','劉過','宋','宋诗','song-poetry','','[]','東州二三子，相送黄鶴磯。',48,'全唐诗/poet.song.172000.json','["東州二三子，相送黄鶴磯。", "渭北烟樹合，江南春水肥。", "波寬魚意足，沙淺鳥痕微。", "我亦欲東去，斜風雨濕衣。"]'),
('f79fca4e-679f-4bc9-8428-21644bb6430b','送許閻二兄歸岳陽','劉過','宋','宋诗','song-poetry','','[]','岳鄂舊遊處，重來歲月更。',48,'全唐诗/poet.song.172000.json','["岳鄂舊遊處，重來歲月更。", "聯翩識吾友，邂逅慰平生。", "風送故人遠，槐催舉子驚。", "扁舟更珍重，萬里莫留行。"]'),
('da228e82-fafa-4cd9-870b-796dc9cf2b45','九日寄陳君舉舍人','劉過','宋','宋诗','song-poetry','','[]','白髮江湖暗，青燈几席涼。',48,'全唐诗/poet.song.172000.json','["白髮江湖暗，青燈几席涼。", "病身幾千百，佳節又重陽。", "命也吾何奈，天乎孰可量。", "元龍樓百尺，猶得慰行藏。"]'),
('085d0bbc-6494-4a6e-99de-c24f43f08da1','除夜寄盧菊磵','劉過','宋','宋诗','song-poetry','','[]','見說盧夫子，詩成手自書。',48,'全唐诗/poet.song.172000.json','["見說盧夫子，詩成手自書。", "雪便金帳煖，雲蔭玉山居。", "椒葉儲名酒，萍虀薦野蔬。", "夜寒裩犢鼻，應念馬相如。"]'),
('7afcf5bd-031a-4500-9ae1-fcf6d8e821e4','寄桐廬程宰','劉過','宋','宋诗','song-poetry','','[]','路入嚴州去，桐廬得暫過。',48,'全唐诗/poet.song.172000.json','["路入嚴州去，桐廬得暫過。", "盤餐湯餠賤，機杼綺羅多。", "令尹哦詩治，居民酌酒歌。", "吏人公事少，門雀可張羅。"]'),
('fc917899-665b-4e06-b44b-f2ab2ca0988c','寄吳子雲','劉過','宋','宋诗','song-poetry','','[]','曾是乘軒客，飄零老更窮。',48,'全唐诗/poet.song.172000.json','["曾是乘軒客，飄零老更窮。", "棹船秋葉浦，策杖桂枝叢。", "往事都如夢，新詩不用工。", "草廬消得幾，不許卧隆中。"]'),
('97ed36ba-1eec-4308-b962-c54238bd014c','吳尉東閣西亭  其一','劉過','宋','宋诗','song-poetry','','[]','襲桂行香徑，朱欄稍轉西。',48,'全唐诗/poet.song.172000.json','["襲桂行香徑，朱欄稍轉西。", "水風颼石冷，雲月墮簷低。", "棋敗深杯罰，詩豪健筆題。", "舞忙釵鬢亂，更爲捧柔荑。"]'),
('b91fd91d-52e7-41d6-92df-63a0a5dffd7a','吳尉東閣西亭  其二','劉過','宋','宋诗','song-poetry','','[]','石板橋東閣，軒窗如此華。',48,'全唐诗/poet.song.172000.json','["石板橋東閣，軒窗如此華。", "碧虛澄水鑑，紅影侵霜花。", "似串歌雲駐，如泥醉帽斜。", "但驚風露冷，飄落怕還家。"]'),
('70ea62d4-aa0e-4f4a-a230-f58227eb9482','湖口宰任伯厚挹清亭','劉過','宋','宋诗','song-poetry','','[]','正笑行役倦，登臨心眼開。',48,'全唐诗/poet.song.172000.json','["正笑行役倦，登臨心眼開。", "舒蘄千里見，蜀贛兩江來。", "老覺樹如此，涼生風快哉。", "主人方好客，不算酒行盃。"]'),
('e3439c75-25e7-4d2d-839b-6ea8bf4fe773','題龔山長栖閣','劉過','宋','宋诗','song-poetry','','[]','愛客龔山長，能容日日過。',48,'全唐诗/poet.song.172000.json','["愛客龔山長，能容日日過。", "栽培初種竹，愛護乍生荷。", "堂對青山短，門關白日多。", "細聽閒議論，不似我狂歌。"]'),
('e0f486b9-745b-46a5-b864-15cb85590cbb','題禾川龍飛英疏榮閣','劉過','宋','宋诗','song-poetry','','[]','堂扁朱書字，何人可得之。',48,'全唐诗/poet.song.172000.json','["堂扁朱書字，何人可得之。", "三衙新統帥，六館老宗師。", "文武無窮意，江山不盡詩。", "親恩如可報，會有報君時。"]'),
('9079f2fc-349b-4beb-b5e7-40498cb7dbcf','題黄文叔燕堂  其一','劉過','宋','宋诗','song-poetry','','[]','仕宦不愜意，有家胡不歸。',48,'全唐诗/poet.song.172000.json','["仕宦不愜意，有家胡不歸。", "林栖烏反哺，梁語燕于飛。", "鷗鷺忘之久，貂蟬貴者稀。", "但存慈母健，日日舞斑衣。"]'),
('bebb086e-72ae-4541-8a24-299a4d18121a','題黄文叔燕堂  其二','劉過','宋','宋诗','song-poetry','','[]','著屋圖書裏，四山樓觀重。',48,'全唐诗/poet.song.172000.json','["著屋圖書裏，四山樓觀重。", "蓴添張翰思，橘當李侯封。", "湖水自平淡，花枝多冶容。", "興來詩已就，只可酒千鍾。"]'),
('5ba23edd-a7f3-4789-abe3-ed44bfc0117f','西湖次弟潤之韵','劉過','宋','宋诗','song-poetry','','["\u897f\u6e56"]','舊說西湖好，春來更一遊。',48,'全唐诗/poet.song.172000.json','["舊說西湖好，春來更一遊。", "林逋山際宅，蘇小水邊樓。", "行密柳堤閙，樹多花影稠。", "天堂從此去，真箇說杭州。"]'),
('c7728932-5e45-4e88-8987-b1055e7101cf','雨華臺次胡仲芳韵','劉過','宋','宋诗','song-poetry','','[]','寒意濕烟草，浮生吹浪花。',48,'全唐诗/poet.song.172000.json','["寒意濕烟草，浮生吹浪花。", "繞臺皆峻嶺，陳迹一飛霞。", "子醉辭吐鳳，吾狂字落鴉。", "兒童應笑客，風颭角巾斜。"]'),
('df272735-438b-4503-a897-7213a73793c6','酒樓','劉過','宋','宋诗','song-poetry','','[]','夜上青樓去，如迷洞府深。',48,'全唐诗/poet.song.172000.json','["夜上青樓去，如迷洞府深。", "妓歌千調曲，客雜五方音。", "藕白玲瓏玉，柑黄磊落金。", "酣歌恣蕭散，無復越中吟。"]'),
('72ae4efd-9ceb-4d4b-8d01-120dae7a54fe','登曠軒','劉過','宋','宋诗','song-poetry','','[]','去春曾與客，携手過橋來。',48,'全唐诗/poet.song.172000.json','["去春曾與客，携手過橋來。", "寺陰松極美，塢深桃不開。", "紅塵萬里去，白首一年回。", "凈洗曠軒眼，雪天閒看梅。"]'),
('2498a085-bce4-45f9-af39-a2a35e919e93','鐵塔寺呈輕老','劉過','宋','宋诗','song-poetry','','[]','樹木有古意，軒窗多野情。',48,'全唐诗/poet.song.172000.json','["樹木有古意，軒窗多野情。", "斷岡城一带，齊岸草叢生。", "醉骨風蟬蛻，病身沙鳥輕。", "惜無東野筆，琢句鬭僧清。"]'),
('b650be51-9748-4e51-8c14-70663fc0bdf6','同曹元章遊新安寺','劉過','宋','宋诗','song-poetry','','[]','畏暑倦杯酌，修廊散步行。',48,'全唐诗/poet.song.172000.json','["畏暑倦杯酌，修廊散步行。", "寺深藏古意，蟬老带秋聲。", "去就諸緣薄，窮通一念輕。", "更尋水清處，爲我濯塵纓。"]'),
('352df2fe-23c5-4330-9f96-e5ab74f6b073','遊古山','劉過','宋','宋诗','song-poetry','','[]','信步作幽討，有菴如此深。',48,'全唐诗/poet.song.172000.json','["信步作幽討，有菴如此深。", "佛燈明老屋，秋日淡疎林。", "柏樹祖師意，松楸老子心。", "十年棄墳墓，灑淚一悲吟。"]'),
('fd60c827-8035-4330-8651-502a0d7671e0','題古山菴','劉過','宋','宋诗','song-poetry','','[]','薄醉來遊此，西風吹帽紗。',48,'全唐诗/poet.song.172000.json','["薄醉來遊此，西風吹帽紗。", "倦鴉叢密樹，凉雨濕秋花。", "題壁人何在，哦詩句未加。", "一杯湯餠具，坐到日西斜。"]'),
('b5cb02f9-b776-448c-8899-2a5f188c122d','題龍華寺壁','劉過','宋','宋诗','song-poetry','','[]','春事梅邊動，荒江信馬行。',48,'全唐诗/poet.song.172000.json','["春事梅邊動，荒江信馬行。", "久窮知遠舉，多瘦怯衣輕。", "今日龍華寺，昔時黄姥城。", "廢興吾已解，一醉萬緣清。"]'),
('0c07bb01-fe4b-43d6-a0f0-9a7076250db0','題雁汊峰東林寺','劉過','宋','宋诗','song-poetry','','[]','雁汊泊船去，岸頭閒訪僧。',48,'全唐诗/poet.song.172000.json','["雁汊泊船去，岸頭閒訪僧。", "故人留少駐，俗子見何曾。", "佛屋擎天柱，心光續命燈。", "任渠狂到死，吾老慢騰騰。"]'),
('49861c9c-9b24-4bb0-8ad0-84e66450fc05','書高塘庵','劉過','宋','宋诗','song-poetry','','[]','庵上木已拱，山前水可陂。',48,'全唐诗/poet.song.172000.json','["庵上木已拱，山前水可陂。", "崢嶸晦翁字，突兀大參碑。", "雲葉孤飛白，烏羣反哺慈。", "傷心前輩盡，問道欲從誰。"]'),
('a9f90b3a-d613-4519-87d5-db38a07980c3','聿追菴題壁','劉過','宋','宋诗','song-poetry','','[]','路轉羊腸曲，山藏蝸角深。',48,'全唐诗/poet.song.172000.json','["路轉羊腸曲，山藏蝸角深。", "樹多成蔭密，水少亦悲吟。", "露草重陽淚，風花寒食心。", "摩挲墓銘看，久立讀碑陰。"]'),
('bf53f8e8-4b56-4fad-9649-09e16659d796','元宵偶書','劉過','宋','宋诗','song-poetry','','[]','磊落東遊客，磨跎但過僧。',48,'全唐诗/poet.song.172000.json','["磊落東遊客，磨跎但過僧。", "有懷千不足，自顧百無能。", "舊日名城酒，他時夢境燈。", "放歌聲激烈，醉倒睡騰騰。"]'),
('1fac58ef-49c3-45c6-bf28-9754d85e437e','寓東陽  其一','劉過','宋','宋诗','song-poetry','','[]','元帥東陽主，令君吾故人。',48,'全唐诗/poet.song.172000.json','["元帥東陽主，令君吾故人。", "可憐九華客，猶是一窮民。", "古者狂狷士，人間自在身。", "化工都不管，何地有陽春。"]'),
('86ad0f0d-3d96-494b-9621-472bd7e3c1b1','寓東陽  其二','劉過','宋','宋诗','song-poetry','','[]','不學老無似，艱難却飽諳。',48,'全唐诗/poet.song.172000.json','["不學老無似，艱難却飽諳。", "遠從陶靖節，來訪杜征南。", "意到羹蓴適，貧猶食薺甘。", "惜無廬可卧，尚遶鵲枝三。"]'),
('195b0f9b-add1-4670-a549-1d568621cf5a','泊船吳江縣','劉過','宋','宋诗','song-poetry','','[]','草樹連塘岸，人家半橘洲。',48,'全唐诗/poet.song.172000.json','["草樹連塘岸，人家半橘洲。", "暖寒尋酒去，覺懶罷詩休。", "逆境年年夢，勞生處處愁。", "天涯倦行客，明日又蘇州。"]'),
('422318c6-f09e-4589-b22a-2a4907e39010','送客剡溪','劉過','宋','宋诗','song-poetry','','[]','送客山陰路，春風散馬蹄。',48,'全唐诗/poet.song.172000.json','["送客山陰路，春風散馬蹄。", "縱觀神禹穴，深入子猷溪。", "嫩草綠於染，珍禽嬌已啼。", "去程千萬里，步步有雲梯。"]'),
('98571764-4cb7-40cd-be9f-1f402ec857c9','闕景初進納長安相值於西采石話及家事因與對酌','劉過','宋','宋诗','song-poetry','','[]','未有還家策，故鄉吾太和。',48,'全唐诗/poet.song.172000.json','["未有還家策，故鄉吾太和。", "龍洲沙石健，快閣水雲多。", "場屋科名累，江湖歲月磨。", "茅柴一杯酒，相對奈愁何。"]'),
('6b3dea82-a2aa-45af-912d-a9e7b0924a4c','方竹杖','劉過','宋','宋诗','song-poetry','','[]','鶴骨風前瘦，龍姿雨後鮮。',48,'全唐诗/poet.song.172000.json','["鶴骨風前瘦，龍姿雨後鮮。", "鋒稜四面峻，節操一生堅。", "荷篠行隨適，看山倚最便。", "從教方有礙，終不效規圓。"]'),
('c06182ab-fba3-44b5-9bbf-a4ed3bf33b94','挽拙庵楊居士  其一','劉過','宋','宋诗','song-poetry','','[]','前輩晨星似，如公抑又希。',48,'全唐诗/poet.song.172000.json','["前輩晨星似，如公抑又希。", "榆邊遊已倦，菊徑晚方歸。", "聽雨兄同老，沖天子欲飛。", "傷心彈指頃，一夢故人非。"]'),
('27391952-2358-4ae1-9359-4c504c0d60ab','挽拙庵楊居士  其二','劉過','宋','宋诗','song-poetry','','[]','尚憶龍蟠國，城西作客時。',48,'全唐诗/poet.song.172000.json','["尚憶龍蟠國，城西作客時。", "有山皆載酒，無日不賡詩。", "風雨交游散，江湖淚眼悲。", "百年心事在，只有鳳雛知。"]'),
('dc76b3c1-a8ec-43a5-842e-8fc3c5953169','挽蘇吏部','劉過','宋','宋诗','song-poetry','','[]','奕世徵文獻，逢時仕學優。',48,'全唐诗/poet.song.172000.json','["奕世徵文獻，逢時仕學優。", "愛遺邊郡在，官止外郎休。", "月黑新塋夜，溪橫舊隠秋。", "從游老賓客，欲替二孤愁。"]'),
('97854c6a-709b-40b5-aee5-37425cd1d74a','上益公十絕爲壽 金烏','劉過','宋','宋诗','song-poetry','','[]','金翰振曉近天威，玉宇循瓊晝影遲。',32,'全唐诗/poet.song.172000.json','["金翰振曉近天威，玉宇循瓊晝影遲。", "曾上大裘頭上看，曖然可愛是冬曦。"]'),
('8fc5ff68-3fe1-4c90-aafb-19e32af613dc','上益公十絕爲壽 玉兔','劉過','宋','宋诗','song-poetry','','[]','雪淡星疎月有光，廣寒仙府歲偏長。',32,'全唐诗/poet.song.172000.json','["雪淡星疎月有光，廣寒仙府歲偏長。", "多應自製延年藥，振古長同桂子香。"]'),
('c98e31ec-b330-47a0-bfd0-5253ce79a85e','上益公十絕爲壽 寶龜','劉過','宋','宋诗','song-poetry','','[]','納錫曾看上九江，又聞詹事奉儲皇。',32,'全唐诗/poet.song.172000.json','["納錫曾看上九江，又聞詹事奉儲皇。", "巢成荷上窺仙景，左顧溪中賜印章。"]'),
('91dd1f5c-422a-4327-8014-24725519d52e','上益公十絕爲壽 玄鶴','劉過','宋','宋诗','song-poetry','','[]','緱山橘井與青田，驅策風雲友列仙。',32,'全唐诗/poet.song.172000.json','["緱山橘井與青田，驅策風雲友列仙。", "名號橫空心萬里，九臯聲動九重天。"]'),
('61814192-b3e6-4569-bdb8-ee61c2ddc41a','上益公十絕爲壽 壽鹿','劉過','宋','宋诗','song-poetry','','[]','年永曾聞葛稚川，玉京何處錦紋鮮。',32,'全唐诗/poet.song.172000.json','["年永曾聞葛稚川，玉京何處錦紋鮮。", "賞花應制嘉賓宴，小雅當爲第一篇。"]'),
('1fb2476f-f0c3-493b-8c84-23de2bec5ada','上益公十絕爲壽 丹桂','劉過','宋','宋诗','song-poetry','','[]','少壯東堂奏捷功，浮香仙籍繼家風。',32,'全唐诗/poet.song.172000.json','["少壯東堂奏捷功，浮香仙籍繼家風。", "年年占得中元景，一顆冰輪照九穹。"]'),
('29fc6764-b3f2-4d1a-bd8c-823b5d52659f','上益公十絕爲壽 影木','劉過','宋','宋诗','song-poetry','','[]','枝如華蓋聳瀛洲，永世香風荏苒浮。',32,'全唐诗/poet.song.172000.json','["枝如華蓋聳瀛洲，永世香風荏苒浮。", "特有羣仙來弭節，細聽鳴鳳碧枝頭。"]'),
('72793ac1-20b2-4e54-af6a-1cb9f760f400','上益公十絕爲壽 古柏','劉過','宋','宋诗','song-poetry','','[]','冰條雪葉節高堅，臺憲風生凜凜然。',32,'全唐诗/poet.song.172000.json','["冰條雪葉節高堅，臺憲風生凜凜然。", "可羨堪爲棟梁用，至唐千載尚三千。"]'),
('50916908-d96d-4635-8afa-389d4001b79a','上益公十絕爲壽 佳菊','劉過','宋','宋诗','song-poetry','','[]','壽客尤宜在壽鄉，鈿花的皪傲新霜。',32,'全唐诗/poet.song.172000.json','["壽客尤宜在壽鄉，鈿花的皪傲新霜。", "更歌華壽今歸去，尚有淵明野趣香。"]'),
