('0aa5f2fe-6e04-4fa9-8c52-5d635f028670','聞鶑','劉過','宋','宋诗','song-poetry','','[]','東風扶日上花枝，恰恰幽禽弄暖時。',32,'全唐诗/poet.song.172000.json','["東風扶日上花枝，恰恰幽禽弄暖時。", "百囀忽驚春夢破，間關石上話相思。"]'),
('bfd92191-4c84-49c6-b557-01e73bb0e9ea','雁  其一','劉過','宋','宋诗','song-poetry','','[]','朝隨漢使到天涯，暮與江鷗宿浦沙。',32,'全唐诗/poet.song.172000.json','["朝隨漢使到天涯，暮與江鷗宿浦沙。", "歲晚客途營一飽，稻粱多處即爲家。"]'),
('4f741be3-2f4f-437a-859b-76659b1d349d','雁  其二','劉過','宋','宋诗','song-poetry','','[]','萬重山水萬重雲，歲歲江南客此身。',32,'全唐诗/poet.song.172000.json','["萬重山水萬重雲，歲歲江南客此身。", "天末西風晚來急，數行飛下一汀蘋。"]'),
('4c7cda10-8f70-4e60-864f-d93cf241b84a','漁翁','劉過','宋','宋诗','song-poetry','','[]','短篷三尺寄烟波，短褐休休歲月過。',32,'全唐诗/poet.song.172000.json','["短篷三尺寄烟波，短褐休休歲月過。", "江海不知戎馬事，酒酣搔首唱漁歌。"]'),
('d81f7bcc-553d-479f-86a3-24873039e63a','聽阮','劉過','宋','宋诗','song-poetry','','[]','絳蠟攢花夜氣橫，樽前更著許風情。',32,'全唐诗/poet.song.172000.json','["絳蠟攢花夜氣橫，樽前更著許風情。", "却將江上風濤手，來聽紗窗側阮聲。"]'),
('40d21dd2-ed2d-4c6c-9ef5-30d2dc33984d','閒步','劉過','宋','宋诗','song-poetry','','[]','山徑無人鳥篆沙，杖藜閒看摘新茶。',32,'全唐诗/poet.song.172000.json','["山徑無人鳥篆沙，杖藜閒看摘新茶。", "錦綳委地筍翻籜，黄玉滿林松带花。"]'),
('9417a3e4-78ea-4a62-8363-119ec00e1783','夢覺','劉過','宋','宋诗','song-poetry','','[]','夢回斜日轉花陰，時有黄鸝送好音。',32,'全唐诗/poet.song.172000.json','["夢回斜日轉花陰，時有黄鸝送好音。", "高卧草廬人不識，東風啼鳥獨知心。"]'),
('42359f16-c9a9-41d3-8fa2-18b46994addb','感舊','劉過','宋','宋诗','song-poetry','','[]','羅結同心柳带青，碧桃香裏記將迎。',32,'全唐诗/poet.song.172000.json','["羅結同心柳带青，碧桃香裏記將迎。", "春風重到憑欄處，腸斷江樓不忍登。"]'),
('44ebd71f-905b-4130-addf-fbb07caae46c','遊郭希呂石洞二十詠 清曠','劉過','宋','宋诗','song-poetry','','[]','筍輿咿啞來，路轉此歇脚。',24,'全唐诗/poet.song.172000.json','["筍輿咿啞來，路轉此歇脚。", "長內挾秋下，深意滿萬壑。"]'),
('99baa7d4-915f-4d75-bf31-dcd35f34a01f','遊郭希呂石洞二十詠 深秀','劉過','宋','宋诗','song-poetry','','[]','蒼髯萬松宮，窈窕一徑開。',24,'全唐诗/poet.song.172000.json','["蒼髯萬松宮，窈窕一徑開。", "請回俗士駕，切莫呵殿來。"]'),
('6bf3d542-0ae4-4a9d-9888-7dd3e8762987','遊郭希呂石洞二十詠 書院','劉過','宋','宋诗','song-poetry','','[]','力學如力耕，勤惰爾自知。',24,'全唐诗/poet.song.172000.json','["力學如力耕，勤惰爾自知。", "便使書種多，會有歲稔時。"]'),
('777c2709-1b74-4466-98b3-7a016e97581c','遊郭希呂石洞二十詠 谷口','劉過','宋','宋诗','song-poetry','','[]','水流自何許，遠欲窮其源。',24,'全唐诗/poet.song.172000.json','["水流自何許，遠欲窮其源。", "石梯苔蘚層，微有屐齒痕。"]'),
('ea7a0752-763a-4174-b6a8-bc04ca32cd5d','遊郭希呂石洞二十詠 月峽','劉過','宋','宋诗','song-poetry','','[]','兩崖限東西，裏有一带天。',24,'全唐诗/poet.song.172000.json','["兩崖限東西，裏有一带天。", "老蟾更多事，駕月下潺湲。"]'),
('18b272da-f003-483c-bf8e-60704533a41b','遊郭希呂石洞二十詠 桂壑','劉過','宋','宋诗','song-poetry','','[]','叢叢萬橫枝，羅生雜松篁。',24,'全唐诗/poet.song.172000.json','["叢叢萬橫枝，羅生雜松篁。", "不以巖穴幽，歲晚政自香。"]'),
('29ac0609-92c1-4854-a7e7-bdec3145119f','遊郭希呂石洞二十詠 小爛柯','劉過','宋','宋诗','song-poetry','','[]','遊戲一彈棋，歲月駒隙過。',24,'全唐诗/poet.song.172000.json','["遊戲一彈棋，歲月駒隙過。", "不如兩忘機，石上跏趺坐。"]'),
('55ab5f83-2d79-4c41-b405-de6d17ffc3d0','遊郭希呂石洞二十詠 傾月','劉過','宋','宋诗','song-poetry','','[]','去去山轉深，樹下益凄冷。',24,'全唐诗/poet.song.172000.json','["去去山轉深，樹下益凄冷。", "時有月烏飛，間碎梧桐影。"]'),
('fe4f1f3d-2950-4359-b5a9-f6e1af14533a','遊郭希呂石洞二十詠 閟雲','劉過','宋','宋诗','song-poetry','','[]','仙宮已降敕，雅有新遷除。',24,'全唐诗/poet.song.172000.json','["仙宮已降敕，雅有新遷除。", "乞爲此閣使，雲物屢卷舒。"]'),
('8ab906e3-4deb-403f-84e0-9a2b74a249f0','遊郭希呂石洞二十詠 高碧','劉過','宋','宋诗','song-poetry','','[]','小山碧巉巖，直上與天齊。',24,'全唐诗/poet.song.172000.json','["小山碧巉巖，直上與天齊。", "詩成欲磨崖，藤羅費攀躋。"]'),
('7087b85d-1e24-4720-8edd-585748a4e814','遊郭希呂石洞二十詠 石井','劉過','宋','宋诗','song-poetry','','[]','銀床遶周遭，一規寒浸水。',24,'全唐诗/poet.song.172000.json','["銀床遶周遭，一規寒浸水。", "試敲拄杖看，恐觸蛟龍起。"]'),
('6f9df08e-b76f-41eb-84cd-c67b6c96463b','遊郭希呂石洞二十詠 壺天','劉過','宋','宋诗','song-poetry','','[]','逆溪隨水行，更上紫翠峰。',24,'全唐诗/poet.song.172000.json','["逆溪隨水行，更上紫翠峰。", "朱欄忽飛閣，映带烟霞重。"]'),
('0bde463f-76c5-44eb-a948-98ffabfaefc5','遊郭希呂石洞二十詠 玉珮','劉過','宋','宋诗','song-poetry','','[]','借榻卧雲屋，欹枕仔細聽。',24,'全唐诗/poet.song.172000.json','["借榻卧雲屋，欹枕仔細聽。", "誤疑鳴珂聲，不知水泠泠。"]'),
('72fe0b15-8af8-4184-8136-6274f8639ae4','遊郭希呂石洞二十詠 飛雪','劉過','宋','宋诗','song-poetry','','[]','山前大飛雪，路有何處入。',24,'全唐诗/poet.song.172000.json','["山前大飛雪，路有何處入。", "蒙茸亦花飛，冷濺征衣濕。"]'),
('650ad509-7c50-45cf-89b9-21c007d24d4a','遊郭希呂石洞二十詠 笙鶴','劉過','宋','宋诗','song-poetry','','[]','木末俯清軒，獨立久延佇。',24,'全唐诗/poet.song.172000.json','["木末俯清軒，獨立久延佇。", "何人騎鶴來，髣髴吹笙侶。"]'),
('fd190f3f-f2b7-42dc-8e81-d4e4ac86dc38','遊郭希呂石洞二十詠 韜玉','劉過','宋','宋诗','song-poetry','','[]','至寶不自獻，韜藏亦英華。',24,'全唐诗/poet.song.172000.json','["至寶不自獻，韜藏亦英華。", "餘香被草木，秀擢幽岩花。"]'),
('5155991c-b3d0-4954-842e-f93d8ab1b6d8','遊郭希呂石洞二十詠 倚劍','劉過','宋','宋诗','song-poetry','','[]','石壁自磨礲，三嘆用不久。',24,'全唐诗/poet.song.172000.json','["石壁自磨礲，三嘆用不久。", "如去到人間，爲儂洗塵垢。"]'),
('61fb7088-9d29-4d6c-9d7e-6827e9b1e428','遊郭希呂石洞二十詠 藥圃','劉過','宋','宋诗','song-poetry','','[]','古文不可賣，未覺賣藥非。',24,'全唐诗/poet.song.172000.json','["古文不可賣，未覺賣藥非。", "侵晨荷鋤往，暮得芝朮歸。"]'),
('c56445a9-40d2-47f1-9422-fa64db3270e3','遊郭希呂石洞二十詠 玉泉','劉過','宋','宋诗','song-poetry','','[]','石礫沙沃盡，悠悠潭影斜。',24,'全唐诗/poet.song.172000.json','["石礫沙沃盡，悠悠潭影斜。", "塵襟不忍濯，爲惜無玷瑕。"]'),
('fbb78dd9-d277-49a4-83ed-4b754a454607','遊郭希呂石洞二十詠 石橋','劉過','宋','宋诗','song-poetry','','[]','隔山聞禽聲，欲往道路隔。',24,'全唐诗/poet.song.172000.json','["隔山聞禽聲，欲往道路隔。", "顧瞻此橋上，白雲出迎客。"]'),
('e873bd5c-ef68-400d-8082-a28401df9829','題京口多景樓','劉過','宋','宋诗','song-poetry','','[]','壯觀東南二百州，景于多處却多愁。',64,'全唐诗/poet.song.172000.json','["壯觀東南二百州，景于多處却多愁。", "江流千古英雄淚，山掩諸公富貴羞。", "北府只今唯有酒，中原在望莫登樓。", "西風戰艦成何事，只送年年使客舟。"]'),
('83d7e901-3bf7-4fca-be8d-d47d4660b53b','賦羊腰腎羹','劉過','宋','宋诗','song-poetry','','[]','拔毫已付管城子，爛胃曾封關內侯。',32,'全唐诗/poet.song.172000.json','["拔毫已付管城子，爛胃曾封關內侯。", "死後不知身外物，也隨樽俎伴風流。"]'),
('27472ec2-70a1-4ca9-8448-c9e32d0773a4','挽張魏公','劉過','宋','宋诗','song-poetry','','[]','背水未成韓信陣，明星已隕武侯軍。',32,'全唐诗/poet.song.172000.json','["背水未成韓信陣，明星已隕武侯軍。", "平生一點不平氣，化作祝融峰上雲。"]'),
('63861476-064c-4a91-8a2f-8172da6cd83d','再游儀真呈張使君','劉過','宋','宋诗','song-poetry','','[]','江淮冠蓋閙如林，求一己知何處尋。',64,'全唐诗/poet.song.172000.json','["江淮冠蓋閙如林，求一己知何處尋。", "風月欲談嫌許事，山川不險似人心。", "使君德量如天遠，舉子科名自陸沉。", "秋氣未悲先淚下，黄花雖好不曾簪。"]'),
('08bcd2cb-d131-4002-8ce2-a5a54d3027d0','寄如皋葉尉','劉過','宋','宋诗','song-poetry','','[]','借馬石莊去，天寒曉出門。',48,'全唐诗/poet.song.172000.json','["借馬石莊去，天寒曉出門。", "亂崗行兔窟，數點入鴉村。", "欲醉酒力薄，如迷海氣昏。", "客游無限事，端的向誰言。"]'),
('2cef2e2d-c7b4-4eef-bc7f-d5797c834b8f','遊靈巖','劉過','宋','宋诗','song-poetry','','[]','風露凄然八月秋，瘦藤扶我到山頭。',64,'全唐诗/poet.song.172000.json','["風露凄然八月秋，瘦藤扶我到山頭。", "僧居突兀飛鴻上，人跡依稀任鹿遊。", "舊事已空流水在，閑情都付落花休。", "越王未是真嘗膽，計出嬋娟事可羞。"]'),
('234cb9c1-21d2-4953-a7cc-8bf0b68853a2','王農丞舟中','劉過','宋','宋诗','song-poetry','','[]','危檣高占飛鴉字，京淮兩路傳宣使。',64,'全唐诗/poet.song.172000.json','["危檣高占飛鴉字，京淮兩路傳宣使。", "面如玉盤腰有金，見說京淮已無事。", "儒生性命何足憐，十年厭聞犬羊膻。", "一朝悔禍亦不惡，且願四海皆安眠。"]'),
('33d5a928-5d20-47a4-8ed0-5d6f72e25338','寄王巽伯','劉過','宋','宋诗','song-poetry','','[]','朋從紛如雲，愈覺居索甚。',48,'全唐诗/poet.song.172000.json','["朋從紛如雲，愈覺居索甚。", "肺肝百憂集，五夜不安枕。", "長恐鐵石心，化作萋其錦。", "日暮懷佳人，霜風悄寒凜。"]'),
('12fa67c6-cac3-4348-8ee1-bd0f52e3670d','贈鄉人曹倅待聘爲通州靜海宰及施博士','劉過','宋','宋诗','song-poetry','','[]','茅葦連天昨已非，二年重到最堪悲。',64,'全唐诗/poet.song.172000.json','["茅葦連天昨已非，二年重到最堪悲。", "芹宮尚有肩吾在，花縣猶存子建知。", "躑躅南飛三繞樹，淒涼北望四愁詩。", "東風若不均披拂，薦福仍然又斷碑。"]'),
('a2c6a049-3121-48f9-b642-f4996abbc7ae','代歐陽丞上韓平章  其一','劉過','宋','宋诗','song-poetry','','[]','當年歐富與韓范，戮力同心佐漢庭。',32,'全唐诗/poet.song.172000.json','["當年歐富與韓范，戮力同心佐漢庭。", "今日故家渾似舊，醉翁之後獨雕零。"]'),
('29ccd9ff-6e78-4507-a8c9-ff322f893342','代歐陽丞上韓平章  其二','劉過','宋','宋诗','song-poetry','','[]','玉立堂堂社稷臣，人言忠獻是前身。',32,'全唐诗/poet.song.172000.json','["玉立堂堂社稷臣，人言忠獻是前身。", "三生晝錦堂前夢，莫忘當年作記人。"]'),
('517a545e-ada2-4e0c-85a1-9036c5b20adb','謁蘇州守','劉過','宋','宋诗','song-poetry','','[]','十年狂蕩客征途，時爲文章未剖符。',64,'全唐诗/poet.song.172000.json','["十年狂蕩客征途，時爲文章未剖符。", "引臂欲攀天上月，回身却礙日中烏。", "窮愁自是真男子，慷慨須投大丈夫。", "聞道使魚鰲海闊，特將香餌釣姑蘇。"]'),
('2ad0331d-6d71-4fed-bb31-1fa248129218','題疊浪軒','劉過','宋','宋诗','song-poetry','','[]','僧房矮占一窗幽，不見當年疊浪浮。',64,'全唐诗/poet.song.172000.json','["僧房矮占一窗幽，不見當年疊浪浮。", "湖已爲田知幻化，律更以教示精修。", "白蓮何日還同社，頑石無時不點頭。", "可惜能詩張孟輩，却無一字此間留。"]'),
('1275a232-605e-41e4-93bb-861febbc1f49','思劉改之','吳英父','宋','宋诗','song-poetry','','[]','襄陽劉子謫仙儔，揮斥塵寰却寓遊。',64,'全唐诗/poet.song.172000.json','["襄陽劉子謫仙儔，揮斥塵寰却寓遊。", "醉眼芒羊天地窄，吟魂凄蕩鬼神愁。", "生來不带封侯骨，老去徒深活國謀。", "旦暮風塵起河朔，未容埋沒委山丘。"]'),
('4fc9a7d5-966a-4161-b42d-4b74fa9a563f','以入定大士太乙真人像送莞晦叔','敖陶孫','宋','宋诗','song-poetry','','[]','真人與大士，蘭菊而異芳。',204,'全唐诗/poet.song.172000.json','["真人與大士，蘭菊而異芳。", "坐卧得定力，銅眼鐵脊梁。", "是中有佳趣，山海俱茫茫。", "或時現神妙，塵蹟生怪光。", "云何得此本，有僧吳下狂。", "飲酒不計斗，褚無一絲藏。", "興來高閉門，落筆如追亡。", "走送臞庵室，洗心一鑪香。", "盤陀旃林闊，枕藉玉井凉。", "蒙頭帔衲古，遮眼經論長。", "不知幾陵谷，睡穩坐不僵。", "君家定吉夢，二士相迎將。", "辟除寒具油，靜展垂中堂。", "會當同一龕，寒泉薦空觴。", "夜窗摇茶煙，駝褐依繩牀。", "楊枝灑寥闃，蔾杖輝森芒。", "與君六根靜，讀書到虞唐。"]'),
('1caa7f53-beb2-4aaf-9c3d-5c58859dfbf4','寄福清翅山舅陳夢寔','敖陶孫','宋','宋诗','song-poetry','','[]','路岐引人不作長，野梅官柳禪風光。',224,'全唐诗/poet.song.172000.json','["路岐引人不作長，野梅官柳禪風光。", "看山看水入詩眼，歲月不覺鬚眉蒼。", "請從丈人開肺腸，身非石人忘故鄉。", "五年江湖枕書睡，夢隨南雲落翁堂。", "亦知行坐歌白頭，池南隠几浴鳬雙。", "鰥孤肯復有羈旅，石塘破寺魂悲凉。", "毛錐不補萬事裂，存者各在天一方。", "善和里第知幾易，遼東城郭空相望。", "平生何用酷似舅，政似嫫母顰施嬙。", "兒時拊頭祝文章，祇今未入崔蔡行。", "三年一書願見貰，骨肉滿縣愁難當。", "屋頭荼䕷定過牆，滿窗日色文書香。", "眼前欠甥頗念否，我亦口挂蠔山旁。", "煩將歸意作泉下，小待錦衣漫俗妝。"]'),
('618b1621-90be-4ba9-9ec5-4da83a455630','送林伯農還鹿角山','敖陶孫','宋','宋诗','song-poetry','','[]','今我不樂遊四方，夙昔已具浮海航。',104,'全唐诗/poet.song.172000.json','["今我不樂遊四方，夙昔已具浮海航。", "十年點化鷗心性，一生正坐虎文章。", "海山未必盡佳處，往與蜑子收漁梁。", "夢中了了說吳楚，山川如掌今羊腸。", "讀書南隣索檳榔，原頭汙邪豚酒香。", "何時攝衣上公堂，蛤蜊含漿魚尾黄，客從南來勤寄將。"]'),
('78f1244b-88fa-47f1-a91f-e1b99cab377d','洗竹簡諸公同賦','敖陶孫','宋','宋诗','song-poetry','','[]','舍東脩竹密如櫛，一日洗浄清風來。',96,'全唐诗/poet.song.172000.json','["舍東脩竹密如櫛，一日洗浄清風來。", "脫巾解带坐寒碧，置觴露飲始此迴。", "平林遠靄開圖畫，西望羣山如過馬。", "詩翁意落帆影外，孤村結廬對瀟灑。", "百年奇事笑談成，向來無此蒼龍聲。", "閑身一笑直錢萬，剜粉劖青留姓名。"]'),
('6bef910b-d3c9-4e75-a43e-4e466c5df5a7','用韵謝竹主人陳元仰','敖陶孫','宋','宋诗','song-poetry','','[]','熱中褦襶令我汗，日暮佳人期不來。',96,'全唐诗/poet.song.172000.json','["熱中褦襶令我汗，日暮佳人期不來。", "陳郎揖人不下榻，青山白雲喚得迴。", "手開十畝蕭郎畫，箇裏何妨繫吾馬。", "食單得凉清可啜，毳褐分陰翠如灑。", "摇金戛玉真天成，夢搗風前茶臼聲。", "一川窈窕荷萬柄，野翁得此甘辭名。"]'),
('a5e03435-ae83-4f4d-8a45-23666042b1e3','竹閒新闢一地可坐十客用前韵刻竹上','敖陶孫','宋','宋诗','song-poetry','','[]','竹君得姓起何代，渭川鼻祖茲雲來。',96,'全唐诗/poet.song.172000.json','["竹君得姓起何代，渭川鼻祖茲雲來。", "主人好事富千埒，日報平安知幾迴。", "平生好山仍好畫，意匠經營學盤馬。", "別裁斗地規摩圍，自汲清池行播灑。", "一杯壽君三徑成，請君靜聽風來聲。", "醉眠煮得石根爛，以次平章身與名。"]'),
('4febb42f-d995-4b7d-a9b6-41ec3d6b99c1','謝葉司理徐知縣見貽之什','敖陶孫','宋','宋诗','song-poetry','','[]','書生自是鑽簡蠹，浄業還從竹背來。',96,'全唐诗/poet.song.172000.json','["書生自是鑽簡蠹，浄業還從竹背來。", "新詩細字行茂密，驚蛇起草盤蛟迴。", "是身政欠虎頭畫，望山氣如還櫪馬。", "翛然君子六千人，不受湘靈清淚灑。", "竹林定交業已成，北窗讀書吾伊聲。", "金魚玉带不汝却，社中未厭山王名。"]'),
('aeabd149-c4bc-4cde-923e-79eed1b4e5d7','一日復一日','敖陶孫','宋','宋诗','song-poetry','','[]','一日復一日，來如赴海波。',132,'全唐诗/poet.song.172000.json','["一日復一日，來如赴海波。", "今晨我無糧，未卜晡夕過。", "辛苦幸一飽，知復有明何。", "平生實愚闇，慮淺憂則多。", "雀鼠偷太倉，田野蜚螟蛾。", "至尊尚旰食，邊防望投戈。", "我欲瀝血訴，官府多譴呵。", "進退羝觸藩，屈鬰鵬在羅。", "壯心一不遂，六龍奄蹉跎。", "所以憂世人，散髮歸巖阿。", "長生儻可學，吾其駐羲娥。"]'),
('32ab9e76-8150-485d-bdfa-e93e3a250f71','放船','敖陶孫','宋','宋诗','song-poetry','','[]','柳邊放船試南風，揚溪荷花能艷紅。',160,'全唐诗/poet.song.172000.json','["柳邊放船試南風，揚溪荷花能艷紅。", "一川雲錦步不盡，我舟正在繁香中。", "午天無雲青脈脈，枕舷哀歌醉脫幘。", "更將綠葉穿碧筒，欲臣屈巵奴太白。", "風前一笑玉麈橫，蜻蜓側翅潜魚驚。", "騎馬貴人多內熱，此歡勿語長安城。", "須臾客醉船亦醉，信流一抹西村外。", "翁媼負牆樵牧奔，拾薪供茶初不記。", "還家鼻息撼四鄰，閬風接夢疑非真。", "清遊何時記三人，臞庵與弟拙鄉陳。"]'),
('892d0bd6-7615-4b28-8c7c-9377f21190d0','次韵謝李秘校','敖陶孫','宋','宋诗','song-poetry','','[]','大雅熄自鄶，續絃久無人。',264,'全唐诗/poet.song.172000.json','["大雅熄自鄶，續絃久無人。", "中間翰墨場，名字俱已堙。", "江山亦何助，東海真揚塵。", "我笑李夫子，缾無半合陳。", "人書兩俱亡，何用語逼真。", "作詩來起予，欲卜二仲鄰。", "依然送鴻目，衮衮天機新。", "莫欺鬢眉蒼，持護應有神。", "狗鬚侯舞陽，羝角相平津。", "皇天信平分，萬物各得春。", "但願閲世心，孤特凜箭筠。", "日者鶴飛書，江漢起隠淪。", "三物論鄉國，六藝程成均。", "秋風入帝閑，錯落騅駓驎。", "君曾讀詔否，却枕方欠伸。", "勿驚作詩面，酒纈吹微鱗。", "唾手洗衰陋，一返姚姒純。", "稽古不無力，政復昌其身。", "它時玉堂夢，與問三生因。", "盟我良不難，欲託孫子親。", "贄君以黄耳，附書莫辭頻。", "再拜賦斷章，水石俱磷磷。"]'),
('ac6bd0f2-36f9-41c3-a835-276f616a51c5','次韵馮孔武雪中簡聞人簿乞炭','敖陶孫','宋','宋诗','song-poetry','','[]','君不見朱門煌煌多近臣，豹胎煮蘼蠟爲薪。',163,'全唐诗/poet.song.172000.json','["君不見朱門煌煌多近臣，豹胎煮蘼蠟爲薪。", "庭中盛設潑寒戲，炙手欲近還嗔人。", "誰知曝背茆簷下，欲獻要是山林真。", "兒童抑搔皮肉軟，日輪過中方欠伸。", "懸鶉結駟兩相笑，百年俱成一窖塵。", "先生自是冷官樣，要看入火紅麒麟。", "撚鬚自作詠雪句，秘思蚤與相如親。", "蒲團擁裘結僧坐，別有絺綌君南鄰。", "願迴六龍照后土，施與萬國無邊春。", "屑瓊鏤玉入肺腑，拍手一笑未吾貧。"]'),
('ead707ac-6ddb-477c-8660-34a473c1021b','乞炭於馮孔武再用前韵','敖陶孫','宋','宋诗','song-poetry','','[]','君不見元光河決愁從臣，天子有詔皆負薪。',163,'全唐诗/poet.song.173000.json','["君不見元光河決愁從臣，天子有詔皆負薪。", "當時實炭知幾畚，下與魚鼈爭生人。", "孰知木黔善制水，火出木盡全其真。", "一朝入火縱粉骨，曲身得煖龍蛇伸。", "成虧等作萬世計，肯與胡僧推劫塵。", "我欲詼諧與作傳，上繼毛穎追獲麟。", "日燒崑崙十挺指，惜哉黔也非吾親。", "窮朝破竈鬰煙燼，青唇黑腕羞比鄰。", "誰能輿致送煖熱，坐使有脚歌陽春。", "將軍羔酒空作夢，十年未有今年貧。"]'),
('a371a6e1-3331-4ca4-ad2e-f0a1c4dd6dd4','思古人','敖陶孫','宋','宋诗','song-poetry','','[]','思古人，思古人，古人皦皦若日月。',278,'全唐诗/poet.song.173000.json','["思古人，思古人，古人皦皦若日月。", "我欲剖棺斲出古人心，惟見蒼苔漫白骨。", "請陳古人心，君勿駭客言。", "古人惟一真，可使風俗皆還淳。", "殺雞不及林宗，炊黍不候龐公。", "雪中安道興適盡，坐上公榮樽已空。", "呼酒徑勸君，欲眠即遣客。", "嵇康巨源不爲絕，戴崇彭宣本相得。", "徐庶失老母，密如玄德不能奪之臣。", "嚴陵薄宦情，狎如文叔不能止之客。", "包胥伍員不失其爲友，羊祜陸抗不害其爲敵。", "我有蒸壺，安事隠語。", "我但食韭，安用多種。", "割肉元知方朔真，拏金豈即劉叉勇。", "古人心事有如此，何至顔色相媚奉。", "道衰舛仁義，世亂生姦雄。", "君知臧否不掛口，正慮匕首揕其胸。", "我生恐無用，我死知無聞。", "作書預與兒輩訣，葬時定覓要離墳。"]'),
('ee4173e8-313c-405a-ba00-d3db2639913a','贈墨工陳伯升','敖陶孫','宋','宋诗','song-poetry','','[]','古墨法變今百年，雪齋乃能幻神藥。',64,'全唐诗/poet.song.173000.json','["古墨法變今百年，雪齋乃能幻神藥。", "杜乂膚清衛玠神，眼明再見老陳作。", "墨如人意隨短長，用之不盡渠解笑。", "須君筆端馭龍蛇，他日始信入木妙。"]'),
('0e962b3f-e38f-4241-bede-3c32f6edbdd3','僕以紹熙壬子中夏二十有五日始躋風篁討龍井遂至廣福謁三賢像閲舊碑追觀一代風流爲賦此詩適月林依公留設茗併因書以遺之他日能爲我揭詩板於壁間使示來者亦山中之一助也','敖陶孫','宋','宋诗','song-poetry','','[]','奇石斕橫道，茲山信多姿。',192,'全唐诗/poet.song.173000.json','["奇石斕橫道，茲山信多姿。", "江湖釃兩股，一泓乃孤危。", "相傳龍所家，或恐神護持。", "腥風轉霮䨴，陰崖立淋漓。", "惜無緯蕭勇，探此抱寶癡。", "山僧作屋意，慘澹生幽思。", "胡爲金繆影，顛倒眩俗兒。", "坐來百念失，蒼官導前馳。", "招提果深登，屐痕恍前期。", "咄哉少肉山，著此高顴師。", "端能致遨頭，絕唱相娛嬉。", "過溪亦何事，相送了不疑。", "渠能縛禪律，因來數鬚眉。", "我愛秦郎記，字壓頭陀碑。", "月林只夜夜，人物自一時。", "賢愚盡蟻封，來者吾得知。"]'),
('c93bd27b-7900-49e5-85a1-c2616c0b5dfa','佳人珮明月贈俞德章','敖陶孫','宋','宋诗','song-poetry','','[]','佳人珮明月，笑語含春姿。',96,'全唐诗/poet.song.173000.json','["佳人珮明月，笑語含春姿。", "手握幽蘭叢，照影清漢湄。", "少年冶遊子，行樂方及時。", "折苕戲相贈，玉色頩自持。", "歸來種白璧，日漚文錦絲。", "加幣欲聘君，常恐歲月遲。", "終然不可諧，翕欻聽所之。", "願言遺薌澤，遠慰千里思。"]'),
('bc677cb7-4918-47e2-951b-9588874f3b5c','六月內喜雨詩','敖陶孫','宋','宋诗','song-poetry','','[]','炎天亦靳雨，特地費雷將。',216,'全唐诗/poet.song.173000.json','["炎天亦靳雨，特地費雷將。", "隠隠來何久，飛飛勢稍颺。", "初從霑塊潤，忽作建瓴忙。", "穉子拋書出，臞禪解縛狂。", "苖滋應秀穎，風過忽溫凉。", "蛛網掀三面，蟲書漫數行。", "衾箱開歲事，恩澤到詩章。", "怨暑移今昨，煩痾覺在亡。", "青蓮開紺宇，白苧舞彫牆。", "隻影還晡暮，驚心重渺茫。", "思惟大火聚，迴向六時香。", "脫略時流輩，周旋古佛場。", "身纔丈六足，舌乃大千長。", "此理憑誰詰，何方更舉揚。", "鼠愁燈崛峍，鴉睨鐵琅璫。", "生理何聊頼，斯文重激昂。", "盛時追少壯，故步失尋常。", "政爾蓬心薆，依然貝葉光。"]'),
('824ad913-8ff4-4f2b-a176-24d2ceaf27ec','再次徐先輩二首  其一','敖陶孫','宋','宋诗','song-poetry','','[]','淺聞懲闕漏，小學到凡將。',216,'全唐诗/poet.song.173000.json','["淺聞懲闕漏，小學到凡將。", "始制初龍遁，流風漸鳥颺。", "汔今緗帙富，益我手抄忙。", "半世真書癖，衰年忽酒狂。", "壯懷邀汗漫，奇服間庬凉。", "身許羲黄上，名卑崔蔡行。", "知心屐幾量，闕計木千章。", "湖海堪流滯，陳劉略喪亡。", "每思辭北闕，直欲老東牆。", "度嶺官憔悴，藏山計杳茫。", "尚方何日舄，侍女幾時香。", "歛板予行役，懷鉛子舉場。", "翅垂雖一眚，腹果自三長。", "孰使多爲累，還成少不揚。", "忽驚投暗璧，曾是獻明璫。", "閲世肱三折，論文首一昂。", "結歡慚季札，抗對敢元常。", "它日聯詩社，前羞李杜光。"]'),
('225127f7-460e-4741-bb31-f80519f46c54','再次徐先輩二首  其二','敖陶孫','宋','宋诗','song-poetry','','[]','身是韓康伯，名慚許子將。',216,'全唐诗/poet.song.173000.json','["身是韓康伯，名慚許子將。", "居然屯澤閉，何得巽風颺。", "憶昔求詩甚，端成刻燭忙。", "出喉真自苦，舞手或成狂。", "楊柳偏歌雨，蒲萄肯博凉。", "羣兒哀齒舊，諸武讓顔行。", "禹穴魚龍陳，天門虎豹章。", "陰符空獨佩，秘論未應亡。", "自築揚雄宅，誰窺宋玉牆。", "鄉英殊磊磊，俗物自茫茫。", "祓厲三精劍，寧神百藴香。", "諾交那復社，取醉莫論場。", "高節看徐穉，妍詞伏仲長。", "泥蟠雖汩汰，韝掣會飛揚。", "列屋多齊趙，華榱間璧璫。", "從渠誇富艷，試與校低昂。", "丘喙徒三尺，公才可百常。", "素交風雨盡，雪涕魯靈光。"]'),
('e90502c1-e95e-4eca-8879-97057a476e19','畢叔茲可掃園賞牡丹','敖陶孫','宋','宋诗','song-poetry','','[]','衣冠塞繁都，茂苑非夙昔。',216,'全唐诗/poet.song.173000.json','["衣冠塞繁都，茂苑非夙昔。", "雙鋪俯行渠，文簡相公宅。", "是家固多賢，滿篋載春秋。", "中有數畝園，頗復修風流。", "新亭著高穩，佳木行清幽。", "客來必置醴，井蛙挾其輈。", "張燈看洛花，意作長門愁。", "小却得一欣，凍壁纏蛟虬。", "先朝補天手，翰墨皆其遊。", "再拜閲帝書，局促虞褚歐。", "平生實好奇，兩武布九州。", "恍然駕閬風，坐我曲池頭。", "竹間是茶煙，松風助颼颼。", "梅食亦登盤，按行感良儔。", "櫪馬喧午枕，土毛擷晨羞。", "似聞屋東偏，萬指食鋤耰。", "行當賣書籍，買鄰託羊求。", "與公行灌園，第一營瓜疇。"]'),
('6ed9bd02-b116-492c-b195-5a7bfc693846','四月二十三日始設酒禁試東坡羹一杯其味甚真覺麴糵中殊無寸功也食已得三詩  其一','敖陶孫','宋','宋诗','song-poetry','','[]','今日忽感悟，閉門謝麴生。',72,'全唐诗/poet.song.173000.json','["今日忽感悟，閉門謝麴生。", "未危却二孺，不戰仇三彭。", "掊擊北海樽，嚌量東坡羹。", "尚恨薄滋味，未能免虧成。", "我欲嚥元和，默坐朝上京。", "坐等梨棗熟，小試昇天行。"]'),
('120cfa10-f2b6-403d-b6e2-d52b60bff7de','四月二十三日始設酒禁試東坡羹一杯其味甚真覺麴糵中殊無寸功也食已得三詩  其二','敖陶孫','宋','宋诗','song-poetry','','[]','評詩要平淡，此語吾不然。',72,'全唐诗/poet.song.173000.json','["評詩要平淡，此語吾不然。", "大千自有舌，何用長短篇。", "謂是天送句，端正落我前。", "旋聞口吻鳴，頗益心腸煎。", "少陵躭句佳，欲以一死捐。", "是中有真意，靖節差獨賢。"]'),
('747738cb-8cac-4a8a-b2f9-3a099f13ae3f','四月二十三日始設酒禁試東坡羹一杯其味甚真覺麴糵中殊無寸功也食已得三詩  其三','敖陶孫','宋','宋诗','song-poetry','','[]','去夏苦多雨，勢若無炎官。',72,'全唐诗/poet.song.173000.json','["去夏苦多雨，勢若無炎官。", "今晨迫重午，香黍仍膠槃。", "天機杳難測，人言亦多端。", "祗今原田上，立苖未妨寒。", "但願含穎時，借日開迷漫。", "蟪蛄爾何知，喣喣啼夜闌。"]'),
('8538f68b-4a7e-41d0-a551-220045ff3c86','改周晉仙贈丁相士之什','敖陶孫','宋','宋诗','song-poetry','','[]','張顛許我以神仙，薛顛謂予可英傑。',96,'全唐诗/poet.song.173000.json','["張顛許我以神仙，薛顛謂予可英傑。", "丁生謂二俱無成，世間那得此奇崛。", "麒麟閣上森貂蟬，龍虎鼎內飛大丹。", "腰錢跨鶴誰不願，只有圮下先吾鞭。", "何如吳松江上住，門橫釣車屋農具。", "卧看蒼虬擾白雲，正午堂堂拔江去。"]'),
('f97435ab-cdb4-492b-94d0-b1fb684fc41d','奉寄旌德尉劉申之','敖陶孫','宋','宋诗','song-poetry','','[]','諸劉兄弟賢，一一無可選。',216,'全唐诗/poet.song.173000.json','["諸劉兄弟賢，一一無可選。", "竹林銳頭郎，風味吾小阮。", "平生天機深，善閉得內楗。", "邇來卿何曹，不辦折腰本。", "稍傳詩語東，朝日照蘭畹。", "伊余戰紛華，心旆凡幾偃。", "劃逢君家語，雋永初一臠。", "識遺飽新得，友勝悟夙捐。", "緬懷歌商地，蕭瑟松磵遠。", "陰陰蕪菁花，碧蝶相與晚。", "是中著高士，物意自偃蹇。", "向來白衣宰，雲壑論補衮。", "優游濟艱難，如以禹代鯀。", "劉郎秀眉宇，秋隼立高巘。", "端能謝師匠，萬卷自鉏墾。", "時須閲世諦，一及城門鍵。", "功名頭上簪，日月風中幰。", "何時會吳下，春動長洲苑。"]'),
('608cb9ae-267c-4ef3-bdf2-872d4064e622','送王郎','敖陶孫','宋','宋诗','song-poetry','','[]','車輪何由方，草色欲無路。',240,'全唐诗/poet.song.173000.json','["車輪何由方，草色欲無路。", "晴川媚雙燕，及此送將去。", "若人天機深，奇服雅自與。", "色溫無可鉏，語妙時一吐。", "相逢大江上，爲我浣塵土。", "後期豈前料，已作千歲語。", "告歸何草草，雙水深霧雨。", "稍聞父老舊，門戶要渠補。", "祗愁模楷地，與世作誇詡。", "寧當去樓梯，閉置吾叔度。", "翼翼吳齊門，大江流日夜。", "別君雖咫尺，即是風牛馬。", "君才何如我，我拙猶肯借。", "淮人買繡絲，布洲市如赭。", "張皇十日飲，著公喬松下。", "畫工亦豈學，愛玩此粲者。", "人情勿苦拒，輿馬幸整暇。", "向來三宿戀，取別萬里駕。", "想當雙玉瓶，酣歌淚盈把。", "縹緲鴻鵠去，吾甘老原野。"]'),
('3f29904d-28bb-480c-97f8-ee0aa5d831ff','次韵張長公寵賜初度致禱之語','敖陶孫','宋','宋诗','song-poetry','','[]','何人著書補獲麟，竹汗未乾頭已星。',144,'全唐诗/poet.song.173000.json','["何人著書補獲麟，竹汗未乾頭已星。", "天上風流張公子，散髮滄浪歌獨醒。", "威名徧滿淮草木，肯借妙語春冥靈。", "臞翁之腹無三壬，平生貯書纔一丁。", "泥塗斷道學龜曳，雲天潑眼慚鸞停。", "亦知封侯下曹掾，寧與阿堵高寧馨。", "夢從諸兒坐家塾，十年燈火寒青熒。", "分無黄色明天庭，獨倚一片藏無形。", "虞翻骨相當自程，曲江風度乃不名。"]'),
('3fea04cd-8cde-467f-979b-83cce9dfe2f1','上閩帥范石湖五首  其一','敖陶孫','宋','宋诗','song-poetry','','[]','人物于今正眇然，欲從江表訪先賢。',64,'全唐诗/poet.song.173000.json','["人物于今正眇然，欲從江表訪先賢。", "邇來耆舊無新語，誰使文章漫兩川。", "利器蚤能誇穎脫，偏師聊復制中權。", "騷人有幾登青竹，耐可同時欠執鞭。"]'),
('364c8dd7-edeb-4501-b249-368eacdafd82','上閩帥范石湖五首  其二','敖陶孫','宋','宋诗','song-poetry','','[]','今代論文更是非，賞音誰復得牙夔。',64,'全唐诗/poet.song.173000.json','["今代論文更是非，賞音誰復得牙夔。", "直從長慶成編日，便到先生晚歲詩。", "萬馬蕭蕭閑律令，孤峰隠隠出旌旗。", "了知長短三千首，收拾餘師即我師。"]'),
('8dc9ac0e-24da-4cc6-b5e0-b5e6a25c9e44','上閩帥范石湖五首  其三','敖陶孫','宋','宋诗','song-poetry','','[]','丁年口伐真奇事，一代詩鳴不救貧。',64,'全唐诗/poet.song.173000.json','["丁年口伐真奇事，一代詩鳴不救貧。", "大手欲推浯水頌，羣酋曾折石湖巾。", "乃今謝傅還初志，其奈王陽是故人。", "獨有吾閩欠公句，詔書果起釣磻濱。"]'),
('7e36f090-2d32-4c22-beb3-f87b5814c1e9','上閩帥范石湖五首  其四','敖陶孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','此行閩嶠吾能數，行盡天南未了青。',64,'全唐诗/poet.song.173000.json','["此行閩嶠吾能數，行盡天南未了青。", "莫倚看山韜墨本，要須入界挾圖經。", "西湖楊柳雲生鏡，東阜離支錦作屏。", "欲託翁冰烏石篆，請公作屋與新銘。"]'),
('1f7d0828-dd90-49cd-bcb3-aa6a52a40bb9','上閩帥范石湖五首  其五','敖陶孫','宋','宋诗','song-poetry','','[]','蚤知吳下多奇士，身許先生嫡子行。',64,'全唐诗/poet.song.173000.json','["蚤知吳下多奇士，身許先生嫡子行。", "他日略容追李杜，斯文何敢望班揚。", "向來流水孤三奏，此去飛霞乞一翔。", "牛鐸調宮吾豈敢，噓濡萬一借聲光。"]'),
('661e642e-3934-4887-abd3-82e763cb8f3d','代人壽度支郎中李嘉言','敖陶孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','李下老人龍作儔，談經閲世無春秋。',256,'全唐诗/poet.song.173000.json','["李下老人龍作儔，談經閲世無春秋。", "一朝函谷占紫氣，萬里西極行青牛。", "青蓮居士亦其裔，太白淪精來謁帝。", "江東狂客漏神機，一號謫仙人得制。", "天人驚世時一班，文采風流有遠孫。", "百篇斗酒真細事，郡有德政朝功言。", "晉陵坐嘯列城祖，一札細書風九土。", "爲郎不用漢山錢，度支事繁通會府。", "向來供億寬艱虞，祗今笏畫通材須。", "裕農足國端有道，判花視草皆夷途。", "金魚玉带公所有，太夫人高松柏壽。", "綵衣板輿堪作圖，贔屭閬州陳母後。", "人間盛事省見稀，王母一笑攘桃兒。", "花明柳暗白日靜，鶑穿燕颺青春遲。", "請君酌此西湖水，萬歲千秋佐天子。", "清明寒食數日間，謹勿拋擲爲佳耳。"]'),
('a5b0c35c-eca8-4bb1-8b65-9d72c9d36f4b','登蘇臺用袁憲韵贈兩趙提幹','敖陶孫','宋','宋诗','song-poetry','','[]','勝賞多從暇日違，眼中朋友欲星稀。',64,'全唐诗/poet.song.173000.json','["勝賞多從暇日違，眼中朋友欲星稀。", "退休不復思三顧，能賦猶堪廣七依。", "遊鹿臺前空逝水，棲烏曲裏只斜暉。", "書生懷古真癡絕，看盡閑雲入棟飛。"]'),
('e5af0263-ad07-4ff6-bd05-6778b7cc0afc','次韵萍鄉文叔章訪別','敖陶孫','宋','宋诗','song-poetry','','[]','力田望逢年，倚市勝刺繡。',240,'全唐诗/poet.song.173000.json','["力田望逢年，倚市勝刺繡。", "十年丘里語，失火要自救。", "君行半天下，何處得耆舊。", "請從老龐說，龍風相赴湊。", "全家隠鹿門，遺安不求富。", "常時拜牀下，大鐘盡徐扣。", "男兒惟一身，用在百歲後。", "譬如營屋室，宗廟先庫廄。", "不聞買山隠，而有居巷陋。", "君看鍾鼎家，粱肉或墨瘦。", "寧爲賣文活，一經老學究。", "出身即九折，時命迺大繆。", "向來尸裹革，口語困逗留。", "居然齒編貝，月粟供賃僦。", "何知山澗底，鹿豕對飯糗。", "文章忌隨人，謹勿誇客右。", "書林無淺植，筆耒有深耨。", "紛紛青紫楦，後進渠領袖。", "結交兩任昉，設客一陰就。", "卑官慚處贈，俚語致公壽。"]'),
('1902be3c-c120-48fc-89a2-5ebc817f940a','高郵因師蒲萄蘆鴈秋瓜三種  其一','敖陶孫','宋','宋诗','song-poetry','','[]','漢家士馬知多少，晚得蒲萄繞院栽。',32,'全唐诗/poet.song.173000.json','["漢家士馬知多少，晚得蒲萄繞院栽。", "何物支郎能伎倆，龍鬚馬乳應時來。"]'),
('d58823a8-a3e8-45a4-bd65-6379c36b7383','高郵因師蒲萄蘆鴈秋瓜三種  其二','敖陶孫','宋','宋诗','song-poetry','','[]','莫話凄凉塞北秋，銜蘆避弋使人愁。',32,'全唐诗/poet.song.173000.json','["莫話凄凉塞北秋，銜蘆避弋使人愁。", "與君細展江南畫，水宿沙眠得自由。"]'),
('e4832867-faa7-4b29-bdd8-2458f2d9c8f1','高郵因師蒲萄蘆鴈秋瓜三種  其三','敖陶孫','宋','宋诗','song-poetry','','[]','子母鉤牽曉露漙，行人暍暑慰艱難。',32,'全唐诗/poet.song.173000.json','["子母鉤牽曉露漙，行人暍暑慰艱難。", "青門種色今餘箇，莫作黄臺秋盡看。"]'),
('2b927aa5-8a65-4ff8-92a5-9661918dda81','用香字遺李恭叔','敖陶孫','宋','宋诗','song-poetry','','[]','我無令君三日香，瘦鶴爲軀龜作腸。',128,'全唐诗/poet.song.173000.json','["我無令君三日香，瘦鶴爲軀龜作腸。", "薄寒中人曳兩縰，獨吟猗那遺我將。", "憶從兩脚萬里回，政坐羣兒相謗傷。", "朅來一見老柱史，城郭落落巋靈光。", "安得與君壽六龍，探借千歲北斗漿。", "却乘斑虬訪月窟，盡斫惡樹無留藏。", "天風泠泠吹佩環，洞視碧落豁四旁。", "下方應奉正三入，閑置可憐青瑣窗。"]'),
('8f8d5cb9-46c3-44a0-ba3e-c7fd310a7ac7','再用晨吐字韵寄潘德久  其一','敖陶孫','宋','宋诗','song-poetry','','[]','舍人賓日姿，起居庭燎晨。',108,'全唐诗/poet.song.173000.json','["舍人賓日姿，起居庭燎晨。", "豈惟瑞朝廷，薦紳目多聞。", "就如田甲謿，死灰果不然。", "那知碩果剝，中有一念仁。", "稽古得微酬，櫑具峩進賢。", "琴爲悲風彈，茶必活水煎。", "平生轉庵詩，小當壽千年。", "忽聞朔方騷，更欲腰黄間。", "向來撲朔豪，日者今華顛。"]'),
('c4bd0604-0f00-4969-8289-39d99fa402e9','再用晨吐字韵寄潘德久  其二','敖陶孫','宋','宋诗','song-poetry','','[]','下客時覘君，車茵陽醉吐。',108,'全唐诗/poet.song.173000.json','["下客時覘君，車茵陽醉吐。", "萬事君不理，傳聲拒開戶。", "雖然臭味合，更覺心貌古。", "書讎嶧山棗，羹臛首陽苦。", "坐令府西門，平輿說二許。", "君當我輿臺，銀艾心已灰。", "尚有西山緣，共待石髓開。", "神仙覺易與，詩句端難裁。", "却後五百年，化鶴吾獨來。"]'),
('78fe3418-46e9-4af9-a1c4-52990ca7e19a','酬答李學長','敖陶孫','宋','宋诗','song-poetry','','[]','夫子焉不學，高朕羅三賢。',216,'全唐诗/poet.song.173000.json','["夫子焉不學，高朕羅三賢。", "橫前一片石，教外皆別傳。", "三虎誰最怒，未覺相後先。", "渠伊囊中方，貴在後者鞭。", "我家一佛堂，盎背知廟堧。", "憶昨祠上丁，蕡燭初欲然。", "諸生氣清明，人如出雩泉。", "洗爵俯象鼻，掩豆高豚肩。", "朱弦張文王，繁聲斥師延。", "此時識方屨，綦滿青苔錢。", "李公獨鳳儀，衆中得何堅。", "惜無補天手，轉之上細氈。", "朝來食盤中，穉蕨初數拳。", "蒼蒼本難測，何由賾真筌。", "自我得此士，可以一當千。", "如聞縫掖姿，欲重世所捐。", "舂容吐握詩，法用春秋全。", "酬贈無玉案，三復緇衣篇。"]'),
('2d83e234-1955-485e-975f-5b0728660102','大風懷林伯農','敖陶孫','宋','宋诗','song-poetry','','[]','江湖易高風，六月寒㾕㾕。',144,'全唐诗/poet.song.173000.json','["江湖易高風，六月寒㾕㾕。", "中宵會急雨，凉意到衾枕。", "顛披蒲葦亂，抑壓烏鳶噤。", "禾頭欲生耳，樹背各流瀋。", "不謂晡來霞，橫拖半天錦。", "初疑鴉翻晴，旋覺虹投飲。", "晦明信難料，暘霽吾誰諗。", "所思隔江水，筆力望徐沈。", "十年一葛衣，肘見尚整衽。", "想當風雨夕，憂國願歲稔。", "凄凉新豐邸，避濕幾違寢。", "何由語連牀，共破秋氣凜。"]'),
('ca14db86-a8ad-4eac-8e77-a60c5a90b8f7','醉歌贈鄒孝忠','敖陶孫','宋','宋诗','song-poetry','','[]','老鄒草檄如吹律，能令陰谷回陽春。',192,'全唐诗/poet.song.173000.json','["老鄒草檄如吹律，能令陰谷回陽春。", "手提赤心獻天子，布衫麻鞋驚市人。", "戈船上噓五里霧，詔發內府捐金銀。", "進賢冠者不好武，歸來結屋看濤雲。", "却回孤憤與江浪，氣壓千人萬人將。", "或時飲就夷門屠，亦有撾摻漁陽唱。", "埋名袖手君得辭，行宮今在江之湄。", "高帝遊魂正思沛，太王有道聊居岐。", "一杯屬君當起舞，能令公喜令公怒。", "捽摩青山鬭兩虎，搜攪中流鵝鸛語。", "平生未受噲等伍，圖中襃鄂爾如許。", "六十小劫胡運去，老上單于公手取。"]'),
('b5c501c5-39a4-4113-8c41-646b57a60250','次韵張宰牡丹','敖陶孫','宋','宋诗','song-poetry','','[]','羯鼓勿罷弄，吾琴無成虧。',156,'全唐诗/poet.song.173000.json','["羯鼓勿罷弄，吾琴無成虧。", "潘桃既無頼，陶柳自不持。", "造物有鑪錘，攬之杜拾遺。", "卷簾出傾城，一笑不用帷。", "輸心巧當面，珍重來如期。", "人爲曲江秀，花自潜溪移。", "美人欲晞紅，鏡中靦東施。", "如聞姚魏風，紅紫合折枝。", "常恐砑光帽，半倒金屈巵。", "作詩苦留春，出吻竟不奇。", "但當闃幽閒，屬賦歌載馳。", "慇懃禪靈錦，丈尺餘丘遲。", "公杯當再行，雉邊多小兒。"]'),
('07ae71bf-5ecd-422d-ab5b-3154124e9198','上鄭參政四十韵','敖陶孫','宋','宋诗','song-poetry','','[]','吾閩天下選，人傑聖時蕃。',288,'全唐诗/poet.song.173000.json','["吾閩天下選，人傑聖時蕃。", "佐戴高前諜，承家裕後昆。", "海門當劍立，洋嶼焱鵬騫。", "氣色來迴互，耆明有討論。", "蟠胸三萬卷，落筆五千言。", "地芥垂頭拾，天瓢信手翻。", "餘陰潤桑梓，賸馥到蘭蓀。", "白日騏驎坂，青春桃李園。", "揚鬐方澤國，插羽已天閽。", "伊昔昌能諫，于今弘獨尊。", "夙驚山有虎，已驗鹿隨幡。", "带草書籤麗，金華講舌溫。", "履聲仍獨上，驛置愈爭奔。", "有客迷途甚，勞公倒屣煩。", "請先陳失馬，次第說投猿。", "漳水頭堪白，融峰淚幾吞。", "嵌𡼭辭故里，觚角見脩門。", "到遞吳蠶宿，留交楚鴈番。", "忽通狂客刺，俄返獨縲魂。", "望祿蒲生節，隨人柳折圈。", "天高難發口，地縮會移跟。", "一昨哄堂暇，深知納牖恩。", "印刓聊小靳，縕束更能存。", "日者叨堂貼，時哉會氣元。"]'),
('a979f450-168a-416a-806e-795d5de5b0a3','體齋詩爲梁谿馮季求作','敖陶孫','宋','宋诗','song-poetry','','[]','口腹不自主，來吟體齋詩。',240,'全唐诗/poet.song.173000.json','["口腹不自主，來吟體齋詩。", "三肅齋中人，問體安措辭。", "體卑語近拘，體高語近欺。", "耳目口鼻形，人各師其師。", "要之天地間，當以一理推。", "馮侯好兄弟，一一清廟姿。", "是家好談道，脫略毛與皮。", "一堂春愔愔，詩禮相娛嬉。", "但媿遠客塵，涴子連理枝。", "雖然參自訣，要知不磷緇。", "我車得國工，分路有險夷。", "君知魯叟聖，妙在物不遺。", "當其作春秋，一字如權錘。", "越境惜趙盾，斷謂此語非。", "俗儒無已心，望道如隔紕。", "閉門畫圓方，用世多參差。", "千載堪一咍，汝足未及巇。", "馮郎顧我笑，坐久鑪煙遲。", "黄花粲牆東，青山轉牆西。", "吾言亦已費，須君浮一巵。"]'),
('5c57fec5-263f-4f5b-abac-53f894b48d42','予客崑山得薦嚴長老時道人散朗閒遠不交人事心甚敬之今來海上復得悟公老成疏練能言吳中山水人物甚詳東軒種竹如雲不問其人可知也一日忽起故山之想予語悟野田荒草在處愁人心目安能復作溈山之牛乎因作一詩言君子出處之大致以告不知者','敖陶孫','宋','宋诗','song-poetry','','[]','平生庾公塵，可涴通州泥。',204,'全唐诗/poet.song.173000.json','["平生庾公塵，可涴通州泥。", "朅來海門上，日瘦氣慘凄。", "春風有相導，佚我以闥閨。", "前身定聞法，夢作三生猊。", "悟公癡鈍禪，迎客忽虎溪。", "招要得半席，紙帳春繒綈。", "東軒養蒼雲，大似開昔迷。", "計程南山北，托宿東院西。", "絕憐維摩牀，而置法喜妻。", "是身於虛空，了不礙角圭。", "四大師本無，客亦何所携。", "頗聞弁山隅，髯松作兒啼。", "山神喝連聲，已受三十篦。", "豈知溈山牛，未脫靶與犂。", "去來同一雲，未覺道理睽。", "幸勿使竹歸，留與老鳳棲。", "鑿齒恐無對，後期當噬臍。"]'),
('82b7e0e9-d243-46c2-b47e-f613e2bacb5c','熊得自古英之近江舟子譁然此異徵也爲之留皮與膽餘均所獲以侈神貺云作獲熊一首時庚辰孟冬七日','敖陶孫','宋','宋诗','song-poetry','','[]','來黝者誰，僉曰熊與。',140,'全唐诗/poet.song.173000.json','["來黝者誰，僉曰熊與。", "涉江亂流，實始逆予。", "天畀敢違，俯取以薦。", "維古英神，謂予汝眩。", "有男不夢，有妃莫當。", "居然兩目，祝晝若盲。", "甚者痔下，取怒河伯。", "醫者色難，請謀諸藥。", "熊兮主方，我有玄囊。", "清汝决眥，扞汝濁腸。", "有如不信，剖肝自明。", "寧我一死，以與衆生。", "拜神之休，率曹披啖。", "爾愛其蹯，我愛其膽。"]'),
('b9fb3b14-a7ab-4dc7-9815-9b422e9d5d20','古興  其一','敖陶孫','宋','宋诗','song-poetry','','[]','我有古時鏡，云煉三精魄。',72,'全唐诗/poet.song.173000.json','["我有古時鏡，云煉三精魄。", "雙龍護其紐，玄霧紛四塞。", "持照盤古帝，面目湛可識。", "包藏久不事，天地稍蒼黑。", "昨中試拂拭，依舊存八極。", "惟有世人心，寸膜不可得。"]'),
('c08ffaa3-fc48-47cc-b276-61935e968c26','古興  其二','敖陶孫','宋','宋诗','song-poetry','','[]','昔我走東海，遥望殊庭曲。',72,'全唐诗/poet.song.173000.json','["昔我走東海，遥望殊庭曲。", "獨木盤九龍，欲以鐵網漉。", "紛紛下百怪，牙甲爭踏蹴。", "珊瑚泣沈沈，悵望不省錄。", "終然拙用大，坐閲年代速。", "寄謝寥陽天，龍宮書未讀。"]'),
('7c54d3b3-9416-451a-b869-2e31940c8327','前感興一首','敖陶孫','宋','宋诗','song-poetry','','[]','烏几學癡坐，吾炊何以晨。',216,'全唐诗/poet.song.173000.json','["烏几學癡坐，吾炊何以晨。", "了知詩自好，不與甑相聞。", "蒼蒼本空空，嗚呼誰使然。", "甌窶知滿篝，稍喜斗斛仁。", "而我亦齊民，不貪後世賢。", "腹無一寸溫，百憂鎮燒煎。", "巋然一破竈，寒蟲欲無年。", "更欲辨名字，蟋蟀螽斯間。", "書生謹守書，放步防疾顛。", "蝦蟆緣青冥，孤光恣吞吐。", "於菟無角翼，爲天守門戶。", "持此感物化，堯舜萬萬古。", "冰蠶不知寒，蓼蟲不知苦。", "未知了身口，甘煖復幾許。", "高高化人臺，下視多劫灰。", "我欲轟雷車，老天怒不開。", "死語無出路，六經聖所裁。", "惟應蒯緱劍，日夕同歸來。"]'),
('9e980bbd-5730-495b-8c3b-f4ef7bc080af','後感興二首  其一','敖陶孫','宋','宋诗','song-poetry','','[]','皇天分四時，氣節幾錯遌。',84,'全唐诗/poet.song.173000.json','["皇天分四時，氣節幾錯遌。", "俗兒一驚呼，識者淚橫落。", "悠悠羲皇前，日月何磊犖。", "不世更凌歷，地上光景薄。", "十年看花草，皴面少膏沃。", "看看六鰲背，坐愛白日曝。", "何當寥陽天，朗咏無生樂。"]'),
('7378e97f-f505-4962-b161-7784733f93ee','後感興二首  其二','敖陶孫','宋','宋诗','song-poetry','','[]','朝爲感興吟，暮作感興吟。',84,'全唐诗/poet.song.173000.json','["朝爲感興吟，暮作感興吟。", "何者最可憐，淚盡枯人心。", "身後多所化，所遇或淺深。", "奈何姝姝人，色裹矜冠襟。", "野芳必在擷，濁酒必在斟。", "死題善人表，生托君子林。", "置之勿復言，愁陰復愁陰。"]'),
('1f2d85c4-f61f-4147-a6da-07eddfb5bf4f','秋日雜興  其一','敖陶孫','宋','宋诗','song-poetry','','[]','凉颸動空谷，振我庭樹枝。',60,'全唐诗/poet.song.173000.json','["凉颸動空谷，振我庭樹枝。", "鮮榮忽顰蹙，顔色慘不怡。", "節序一如此，明當戒裘衣。", "寒蟲勸機杼，敦迫不貸時。", "汝意固可尚，我機坐無絲。"]'),
('b399e88c-fcd4-4cce-b96a-1067db812ca4','秋日雜興  其二','敖陶孫','宋','宋诗','song-poetry','','[]','晝氣差小祥，夜氣益以清。',72,'全唐诗/poet.song.173000.json','["晝氣差小祥，夜氣益以清。", "林端動華彩，初月當我楹。", "澗光若翻鶴，草露如栖螢。", "攬衣一徙倚，肝鬲涵空明。", "一室噤衆籟，寂寥無人聲。", "落葉忽墮瓦，憂心還獨驚。"]'),
('77d50388-8abc-4656-a64b-f642d39f4a4d','秋日雜興  其三','敖陶孫','宋','宋诗','song-poetry','','[]','客從湘中來，問我手中松。',60,'全唐诗/poet.song.173000.json','["客從湘中來，問我手中松。", "當時一寸根，翥霄作鸞龍。", "子可爇我鼎，肪可澤我容。", "松今已如此，而况種樹翁。", "寄聲十八丈，法當理歸筇。"]'),
('65acfe27-6066-493e-9446-3a7b2aae05af','秋日雜興  其四','敖陶孫','宋','宋诗','song-poetry','','[]','陣雲起西北，中原暗黄塵。',60,'全唐诗/poet.song.173000.json','["陣雲起西北，中原暗黄塵。", "豈無匡時算，無路不得陳。", "書生亦過計，夜夜占天文。", "匣劍似識時，中宵啞然鳴。", "我亦發悲歌，沾衣涕從橫。"]'),
('3a378926-1b27-4fc3-8370-eb41d4d67e96','秋日雜興  其五','敖陶孫','宋','宋诗','song-poetry','','[]','昨日尚絺綌，今日便衾帟。',72,'全唐诗/poet.song.173000.json','["昨日尚絺綌，今日便衾帟。", "在公不關白，故故出不測。", "鄉來三丈熱，變滅在倏忽。", "蓬根爽然醒，凉意滿巾幘。", "團扇豈辦此，羞澀謝陋質。", "不必待秋來，理宜長棄擲。"]'),
('c26674f6-e0b1-498e-b9e8-c0570b1eefd7','袁同史丈令賦所欲作醉皓堂詩以爲後日數椽張本四老有袁謂乃其遠祖云','敖陶孫','宋','宋诗','song-poetry','','[]','黄雲護靈芝，丈人非獨醉。',192,'全唐诗/poet.song.173000.json','["黄雲護靈芝，丈人非獨醉。", "蕭然四鶴髮，海鳥眩觴味。", "古來閉關人，學道用其意。", "滈池未返璧，政欠頹然睡。", "仙苗足風露，中有熏心厲。", "支頤得一笑，劉郎已爲帝。", "乾坤重盪滌，奈何前星墜。", "昂藏君家老，招喚作許事。", "當筵就羽翼，顔色變韶穉。", "出山雲怡怡，還山雲洩洩。", "追思千載上，把酒足自慰。", "君堂定果耳，或者樓閣氣。", "是間堪底用，萬甕盛醴齊。", "阿戎氣如虎，神手了一世。", "政宜日無何，雪紵展鵠翅。", "高吟紫芝曲，四老恐欻至。"]'),
('dac40c55-7691-4264-a17d-f74f21cdc91b','再簡林子大','敖陶孫','宋','宋诗','song-poetry','','[]','糟丘酒無時，釋麵雲濤翻。',132,'全唐诗/poet.song.173000.json','["糟丘酒無時，釋麵雲濤翻。", "前身阮步兵，搜句急追奔。", "詩清酒更冽，自扣玻璃盆。", "緬懷君家翁，滿懷蟠虞軒。", "職當調九鼎，小却護北門。", "胸中補衮線，豈但民瘼痊。", "胡爲坐海山，揖客通寒溫。", "邊庭失細大，益我愁思繁。", "今君富文采，色正語不喧。", "念我死塵𡏖，妙語爲返魂。", "班班古罍洗，一笑三家村。"]'),
('8ae204c0-52ef-475a-a59a-74f20d8b873d','凄其歲晚不勝鄉國墳墓之情再得四篇贈宗之毋以示他人也  其一','敖陶孫','宋','宋诗','song-poetry','','[]','鄰曲竟還往，歲除當餽分。',48,'全唐诗/poet.song.173000.json','["鄰曲竟還往，歲除當餽分。", "作我淡生活，小龍破密雲。", "天機亦良勤，錯綜合瘁芬。", "松柏青始獨，苕華黄已芸。"]'),
('11c981aa-0566-4dc4-9e64-7d696b5aad3e','凄其歲晚不勝鄉國墳墓之情再得四篇贈宗之毋以示他人也  其二','敖陶孫','宋','宋诗','song-poetry','','[]','重趼踏九州，一源貫九流。',48,'全唐诗/poet.song.173000.json','["重趼踏九州，一源貫九流。", "歲晚天報子，茲樓斂其秋。", "正西蒼龍尾，下掉白鷺洲。", "旁人爲我嘆，污瀆橫吞舟。"]'),
('a550dba3-93f6-454e-8c2b-4ce982f458e4','凄其歲晚不勝鄉國墳墓之情再得四篇贈宗之毋以示他人也  其三','敖陶孫','宋','宋诗','song-poetry','','[]','紅塵暗九衢，生白有我室。',48,'全唐诗/poet.song.173000.json','["紅塵暗九衢，生白有我室。", "山平拄笏頤，月滿橫琴膝。", "三年蠻府掾，不愧紙尾筆。", "夢從南海君，供我波羅蜜。"]'),
('9249d31a-d08b-42d2-a53b-6c0d026a8c40','凄其歲晚不勝鄉國墳墓之情再得四篇贈宗之毋以示他人也  其四','敖陶孫','宋','宋诗','song-poetry','','[]','昔我宦南海，賓友日擊鮮。',48,'全唐诗/poet.song.173000.json','["昔我宦南海，賓友日擊鮮。", "今來童市歸，掌肉分烏鳶。", "旅食何足校，苦望雙旌煙。", "願爲墓戶家，毋爲地行僊。"]'),
('8f80730d-6608-450c-8e01-773aba15beeb','送安豐尉丁夢符歸霅川因簡之晦兄弟時寓崇川報恩寺','敖陶孫','宋','宋诗','song-poetry','','[]','世紛何豫人，直作走千里。',264,'全唐诗/poet.song.173000.json','["世紛何豫人，直作走千里。", "寒壓破虎韉，霜風殺淮葦。", "能來得吾願，連夜燈花喜。", "矯矯將軍力，一日破萬紙。", "填胸龍豹韜，政坐毛錐子。", "區區寄人幕，誰訪習鑿齒。", "相見各挽鬚，士窮乃如此。", "吾謀適不用，步到狼山趾。", "荒村圍海氣，尖城如卧已。", "幸當小盤旋，長袖爲君起。", "回首叫周郎，湟水面欲死。", "往者城南杜，鈿車湊流水。", "胡然落此地，伴客歌快耳。", "吾徒離闊好，見即裂其眥。", "中年迫婚宦，官事漫不理。", "關心且詩酒，甕面撥寒蟻。", "如聞董召南，犬鷄封石髓。", "感君好兄弟，行當訪虛址。", "雍丘且勿念，將星落寒紫。", "送歸無好語，凉月挂鯨尾。", "君行定過潘，茶鼎面曲几。", "因之啟三請，問酒所以止。"]'),
('fc960406-a709-414c-b51a-5426356a130a','別袁席之二首  其一','敖陶孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','漏盡有行客，袁侯挽不來。',156,'全唐诗/poet.song.173000.json','["漏盡有行客，袁侯挽不來。", "掉頭緇塵中，胡爲此徘徊。", "何處非詩具，螺江如潑醅。", "公子亦豈癡，索笑西湖梅。", "平生詩書腹，不計簿領材。", "噫嗚梁父吟，慷慨新豐杯。", "夢作方士鳬，喚杖聽風雷。", "何知江東路，瘦馬衝塵埃。", "君名在吏部，作吏始此回。", "獸弱而弩强，蹙縮生自猜。", "自猜固如此，一語須君裁。", "王事有靡盬，柴車誰當推。", "行矣勿告勞，試身文書堆。"]'),
('5aab072d-2c6f-42dc-a5dd-fe6313123ce2','別袁席之二首  其二','敖陶孫','宋','宋诗','song-poetry','','[]','昨送鄭廣文，持氈就客坐。',156,'全唐诗/poet.song.173000.json','["昨送鄭廣文，持氈就客坐。", "今辭習主簿，相與枕書卧。", "名字擅一世，此法當寒餓。", "臞庵書滿屋，十夏作僧過。", "就使君交我，指目等奇貨。", "百年寸箠折，萬事一甑破。", "獨念君行路，歷歷眼中墮。", "入衢酒無聲，道信山辭涴。", "每憶上程時，店火明箇箇。", "征人語暝靄，嘶馬带枯莝。", "是間萬金藥，貴子身劑和。", "飲酒端不惡，爲米知何奈。", "手板付丞相，此語尚須佐。"]'),
('79e7cc27-f91f-481d-851b-36a6c6834f80','次韵陳景齋糾掾題品山齋數石之作','敖陶孫','宋','宋诗','song-poetry','','[]','吾山何足誇，君語煩專送。',180,'全唐诗/poet.song.173000.json','["吾山何足誇，君語煩專送。", "姿爲丘壑媚，意重璆琳貢。", "芥胸劃玲瓏，瞇眼豁塵瞀。", "白雲足怡悅，明月得簸弄。", "居然衛霍近，頓壓鄒魯鬨。", "故人真陽守，遺補臞庵空。", "數株立拏螭，一笑慰歌鳳。", "緬思昔牛李，競勢急鞿鞚。", "能令山崒硉，所欠腹空洞。", "那知負之走，更使逐者衆。", "誰言山上山，竟作夢中夢。", "老衰本無欲，標榜聊取衷。", "獨憐伏虎雄，必得飲羽中。", "荆室雖苟完，漢儀亦多傯。", "君能載酒來，我願共飯甕。"]'),
('be24d904-87e2-4bda-aaf6-17d8a2757c77','有感一首','敖陶孫','宋','宋诗','song-poetry','','[]','典衣沽美酒，鑄金買艷歌。',168,'全唐诗/poet.song.173000.json','["典衣沽美酒，鑄金買艷歌。", "青燈炯長夜，如此粲者何。", "平生有廉藺，方駕欲更過。", "低顔兒女中，鬰若鷹在羅。", "酣望八極表，老淚如懸河。", "諸兒頗嗤黠，見謂同一波。", "相如混滌器，謝鯤困擲梭。", "古來賢達人，細過非所科。", "竊願天子聖，朝廷半丘軻。", "青春深農桑，東盡青齊阿。", "坐今倡樓女，委棄黛黑螺。", "下里羞陽春，中宮張雲和。", "我爲太平人，短褐生橐駝。", "醉魂招漫郎，或有石可磨。"]'),
('729091a3-2e67-483f-9f32-0aaef7489e4e','謗議','敖陶孫','宋','宋诗','song-poetry','','[]','四方集謗議，著面矢如雨。',144,'全唐诗/poet.song.173000.json','["四方集謗議，著面矢如雨。", "前身雷將軍，柴立吾甚武。", "却還觀我生，與世實鉏鋙。", "西通禰衡鄰，東接嵇康堵。", "以茲料身後，藐未得死所。", "一州納一嘲，一邑獻一侮。", "並浙十五州，我作大謗府。", "餘外九州者，設伏特未舉。", "徐思浮言端，中實無所主。", "怪雪羣犬吠，眩日百鳥語。", "何由澤其喙，環海變春醑。", "坐使聲名高，一日跨堯禹。"]'),
('b7f3e9d8-38ff-4b7b-bd04-66443bae9ff4','貫酒','敖陶孫','宋','宋诗','song-poetry','','[]','酒泉我南鄰，喚客青旗翻。',132,'全唐诗/poet.song.173000.json','["酒泉我南鄰，喚客青旗翻。", "渴心若絆馬，未騁意已奔。", "平生無長物，取具一瓦盆。", "萬事漫不理，得酒雙眉軒。", "相傳新豐坊，北奏司命門。", "衣冠敬再拜，一病煩公痊。", "富貴不敢願，施我腰脾溫。", "今晨客舟出，落日鳴蟬繁。", "屬車得鴟夷，秉羽可解暄。", "却愛畢吏部，神全不驚魂。", "渠能給萬甕，甘老愚公村。"]'),
('eaa52694-0259-4ccb-abf9-e15b95b69ca3','龔立道家藏虢月石屏','敖陶孫','宋','宋诗','song-poetry','','[]','桑田鑒一奪，周官寒如灰。',168,'全唐诗/poet.song.173000.json','["桑田鑒一奪，周官寒如灰。", "賜玨先淪奔，乃自垂棘胎。", "劫火到咸陽，六國無珍材。", "空餘虢山在，蚌水相縈迴。", "古潭月荒凉，孤光翳復開。", "六丁所邀留，珪魄幻紫瑰。", "閟藏三千年，掘獄無張雷。", "君先世閩南，家枕鳳咮堆。", "夜光有感觸，渠伊入剸裁。", "向來匪石心，不轉誤國魁。", "皦如照萬世，是君以聞來。", "遠孫極風流，乞語譾餘哀。", "摩挲紫雲姿，百感集我懷。", "石汝亦不遇，無兩歐蘇梅。"]'),
('f971107e-36ed-458a-a4be-08f32236e6ba','雪中陳孔章招飲','敖陶孫','宋','宋诗','song-poetry','','[]','始秋我如京，褚中無所齎。',276,'全唐诗/poet.song.173000.json','["始秋我如京，褚中無所齎。", "蕭條方逆旅，敗履手自提。", "入門一曲几，塵暗烏皮低。", "平生實有恃，壯氣干虹蜺。", "丈夫死則已，未死牛衣啼。", "以茲悟生理，得展庶可齊。", "城中雪沒靴，凍馬不敢嘶。", "病夫亦怕出，登樓去其梯。", "故人知我貧，坐有一石韲。", "招要過廬下，春風破餘凄。", "老懷不勝酒，秩筵已如泥。", "感君一寒語，醉鄉强攀躋。", "還歸叱塗路，撐斤只槁梨。", "我策三十六，第一捐町畦。", "佩服今十年，默化浙東西。", "惟有三宿戀，弱念牽房閨。", "常時過飯家，屋上瞻烏棲。", "勿輕一壺酒，踏凍誰爲携。", "窮途見弟兄，感涕沾䚢觿。", "世情尚酬答，人事多乖睽。", "終焉媿閔嘿，夜卧三畫臍。", "何時接綢繆，門牡炊家雞。", "入舍更主客，愧無鹿門妻。"]'),
('a0076352-76bd-423e-a94d-08b7b07a2ff7','謝蓋晞之餉筆仍酬以古壽春石刻金剛經','敖陶孫','宋','宋诗','song-poetry','','[]','詩人貴筆精，如射得矢同。',216,'全唐诗/poet.song.173000.json','["詩人貴筆精，如射得矢同。", "有筆仍工書，如矢入彀中。", "先從鼠乞鬚，次論腰到蜂。", "平生竹林交，未數阮仲容。", "住逢蔡邕書，三日清我胸。", "還臨晉賢帖，明眼搏赤熊。", "規摹到晚唐，戰手驚揚風。", "興來欲捉筆，趯若螽在蛩。", "夢想諸葛誠，腰錢走江東。", "霜氣侵短褐，十日守兔蹤。", "故人知我鄉，孤峰禿玉融。", "遣到管城子，令補麟趾終。", "驕豪始入手，廩如控奸雄。", "竊擬專賞罰，爵之中書公。", "何以報嘉恵，古壽碑色空。", "字方蘭亭逸，墨比頭陀濃。", "君家閲古脚，今日聊會逢。", "更待黑蚍蜉，滿紙昏花濛。"]'),
('85d0e8e1-6ec9-475b-9a05-9de0d354a1c6','和姜堯章桂花裙字韵','敖陶孫','宋','宋诗','song-poetry','','[]','紅紫有偏尚，桂花總宜人。',96,'全唐诗/poet.song.173000.json','["紅紫有偏尚，桂花總宜人。", "蠟雪明孤斟，絳雪嬌小顰。", "可憐愛花人，兩屐穿秋雲。", "懷人小山作，寄愁中書君。", "向來鷲嶺詩，政坐書檄嗔。", "月中落桂子，習氣知幾塵。", "潘郎桃李姿，頗亦尊所聞。", "提携風露前，縷衣深紺裙。"]'),
('658140a1-f597-470b-a218-a1afb5b6c924','送袁席之挈家之任','敖陶孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','神龍不池拘，威鳳非籠馴。',252,'全唐诗/poet.song.173000.json','["神龍不池拘，威鳳非籠馴。", "自我交袁君，愁見地上人。", "一官固兒嬉，君視真埃塵。", "去如下鞲鷹，來即釋嶠雲。", "相從復幾時，孰老西湖春。", "門前烏桕花，頗怪烏來頻。", "問知八九雛，翅短青尚新。", "感君携孥行，道路嗟良勤。", "念子春秋學，當重博士茵。", "胡爲簿餘干，折腰五斗陳。", "祭河先惡池，小大則有倫。", "細意事朱墨，凡例實要津。", "贈言吾豈敢，輒獻所食芹。", "惟時風雨交，塗潦埋車輪。", "十年上饒路，夢中說悲辛。", "黄泥漫塘坡，鳴鼉舞淵淪。", "贈子方竹筇，副以白紵巾。", "筇方嚇鬼蜮，巾白來祗神。", "意氣得人命，杯酒聊慇懃。", "上馬莫回頭，慎勿愁我貧。", "亦莫作怪事，祭竈通比鄰。"]'),
('c8a4444c-aa2b-4e82-9894-d2c964a4d9af','杼山閣詩','敖陶孫','宋','宋诗','song-poetry','','[]','攝身上諸峰，我無千手目。',240,'全唐诗/poet.song.173000.json','["攝身上諸峰，我無千手目。", "神交庶子泉，夢老王官谷。", "平生林壑趣，魚鳥即往復。", "杼山落何許，面勢工設伏。", "故人郊居賦，雌霓從衆讀。", "大聲嗑黄華，令德猗綠竹。", "永言乘樏叟，會計踵納麓。", "方尊讀書倚，肯效舞經祝。", "幸當草木近，安事筳篿卜。", "顔公况華扁，江令有餘馥。", "騫掀鵬摶海，夭矯龍起陸。", "於焉峙橫閣，渠是伯夷築。", "何年黄金彈，雞狗隨蹋踘。", "還持揮蠅扇，靜對振鷺瀑。", "前山入手版，後水激帽屋。", "風聲逐孫登，星采向荀叔。", "誰能治西曹，束带望賜沐。", "清客班雜坐，動處草皆蓼。", "乾坤磨旋蟻，身世蕉覆鹿。", "異時留峴首，羊公難諱獨。"]'),
('de34f076-3a3b-4a37-ae59-f22837be9723','次韵蓋宰','敖陶孫','宋','宋诗','song-poetry','','[]','大化我蟲臂，常時炙牛心。',168,'全唐诗/poet.song.173000.json','["大化我蟲臂，常時炙牛心。", "居然身桔槔，老圃愁漢陰。", "簡書實畏人，吏事頗見侵。", "千里得蠻語，十年生越吟。", "寧爲尺一稽，何者可枉尋。", "蓋公學齊魯，頗似東海任。", "雙骭留石涔，舉世方盤鍼。", "稍傳閉關術，抑按娛五禽。", "朅來道院中，狼山即知音。", "披衣起視夜，欲借北斗斟。", "寤言種秫陶，渠肯挾策欽。", "琅然庭柯句，欲和南風琴。", "勾牽老維摩，善哉去來今。", "飛潛不同穴，著鞭英雋林。"]'),
('7ebbfeea-e0ec-4fe5-af43-6810dab3a376','贈縉雲陳志仲主簿楚語一篇','敖陶孫','宋','宋诗','song-poetry','','[]','若有人兮江之臯，搴珠樹兮紉落毛。',300,'全唐诗/poet.song.173000.json','["若有人兮江之臯，搴珠樹兮紉落毛。", "既輕舉以遠睞，衆流靡靡兮汩獨與吾相遭。", "余懼夫人之仙幻兮，指逵術以要之。", "忽改容而善步兮，紛還折之得宜。", "斥姬滿之荒淫兮，服堯禹之所趨。", "載神鼎以自隨兮，出夔魍以驚愚。", "予慮夫參重以賈踣兮，曰此耿耿之故也。", "閔一世之滔滔兮，謂彼不吾即而吾亦爲此懼也。", "歲貿貿其婉晚兮，天浩浩其雨霜。", "反而顧余兮，被髮內狂。", "前九疑之喪道兮，後渭滻之無梁。", "微夫子之亢衡兮，幾人鬼之披攘。", "望兔迹之咫尺兮，仡馳騖之堅彊。", "車軋軋其相摩，肩促促其相望。", "欲抽心而改錯兮，慮夫子之我懲。", "忽風后其降予兮，天老字予以嘉名。", "獨怦怦其不自得兮，淚流軾之縱橫。", "幸哀其中道之離立兮，若示之以正通。", "縱世人之不吾與兮，吾將卒以自明。"]'),
('e2d2f453-3ca6-4e70-a47a-ca6f339fdfbd','燈前曲','敖陶孫','宋','宋诗','song-poetry','','[]','琉璃燈暖燒春紅，水晶簾垂望欲空。',64,'全唐诗/poet.song.173000.json','["琉璃燈暖燒春紅，水晶簾垂望欲空。", "美人縹緲隔花霧，春心咫尺無由通。", "寶釵沽酒市樓中，當筵一曲悲絲桐。", "少年遊蕩足行樂，江南日日長春風。"]'),
('f715ee50-d80d-4f2d-92b2-e8abd713bd01','借山谷後山詩編於劉宜之司戶因書所見呈宜之兄弟','敖陶孫','宋','宋诗','song-poetry','','[]','拾遣詩視孔子道，豫章配孟顔後山。',272,'全唐诗/poet.song.173000.json','["拾遣詩視孔子道，豫章配孟顔後山。", "自餘衆作等別派，彪虥貍豹虎一斑。", "我修直筆公萬世，議論不到甘謿訕。", "中間杜老饒寒餓，陳也絕葷黄尚可。", "天公讎施略相當，一字而貧更憐我。", "去年臞菴太荒凉，釜中得魚雷隠牀。", "了知詩祟力排擯，誰言錮疾蟠膏肓。", "劉郎食飽嗜昌歜，又一過目思手攬。", "編詩更著顧癡筆，字字可丹藏石䃭。", "知君療病我益病，心手相忘還展詠。", "百年長病可得辭，兩翁落唾皆可敬。", "忽云身後無知音，此詩百變無邪心。", "候蟲時鳥足感耳，我思正在南風琴。", "誰能首塗追四始，以經夾轂騷駕軌。", "意所不快鞭曹劉，此時折汝一寸箠。", "長安市上逢聯璧，人持一箭與我直。", "請君了却三萬軸，再見坐我牀下客。"]'),
('f8256111-b177-4115-9240-0b075a15b577','與太常丞丁晦甫','敖陶孫','宋','宋诗','song-poetry','','[]','我昔嘗爲李公客，坐覺金氣肅東南。',304,'全唐诗/poet.song.173000.json','["我昔嘗爲李公客，坐覺金氣肅東南。", "鉤章棘句護帖妥，獨立却視何巘巘。", "此公行世有步里，十不五試驚愚凡。", "尺書飛出岷峨西，每沐問訊相雕鑱。", "向來思賢實微尚，夢濯杜老百花潭。", "環英玉蘂媚初服，風日清美生妍酣。", "直言李公似杜公，前者何愧後何慙。", "今來劃逢丁太常，目所未接心已甘。", "孤標出林唳霜鶻，健論轉海驅風帆。", "張旜萬里足騎壯，富公所說惟饑饞。", "國中何自得吾兀，尊足乃爲公所貪。", "承郎曹司略清貴，龍鸞犧象勞所監。", "工歌韶頀未敢請，前有琴瑟紛相參。", "據梧枝策了自解，箭鋒一語渠誰諳。", "世間聲利大葦箔，置身各自縈繭蠶。", "一聞解縛脫軀命，往往唶舌徒婀媕。", "千人萬人聲一槩，請聽野老真常談。", "捐身大是守身橛，閲世當求出世銜。", "君今氣色日日上，歲晚能同彌勒龕。"]'),
('8a94fbb8-b9b9-4862-9a57-380acb29f05f','壽通守趙寺丞','敖陶孫','宋','宋诗','song-poetry','','[]','忠簡公騎箕尾星，千古萬古明天庭。',224,'全唐诗/poet.song.173000.json','["忠簡公騎箕尾星，千古萬古明天庭。", "在天高廟足歡喜，敕使孫枝扶炳靈。", "輟身仙班寄閑逸，閶闔正繞烟花出。", "朝元冠劍妥未動，一笑明朝作人日。", "漢家最重水衡丞，廩餼錢多上所能。", "掌藏頒用渠式法，置之忽分淮股肱。", "春風作意回焦土，黄池崎險爾如許。", "區區鼠輩何足磔，此心本應僧伽祖。", "甘泉酒作真珠紅，和氣已墮胡牀中。", "奮髯抵掌直細事，參佐同此祥沖融。", "大江洸洸去無極，江南老人候舟色。", "諸公歸補父兄處，二十五城那得直。", "海門短簿初來時，青衫恰輟惟烟姿。", "興來得句自推激，爲公壓倒崧高詩。"]'),
('7b553809-21f1-4dce-9928-c34b9674b2d2','代劉漕使壽相君','敖陶孫','宋','宋诗','song-poetry','','[]','神仙窟宅會四明，氣候中和開二月。',304,'全唐诗/poet.song.173000.json','["神仙窟宅會四明，氣候中和開二月。", "是間表表韋平家，奎閣明良拱天闕。", "前周後魯岌相望，孕昴降嵩天所設。", "大慈平等現官身，思日贊襄盡臣節。", "平生履狶真益下，餘刃磔牛何慮缺。", "道逢不平忽偉事，坐覺日月妖氣豁。", "未嘗示袒勃安劉，亦復和羹商得說。", "由來轉物得三昧，政爾成風聊一吷。", "涵濡少海益重潤，運動紫樞高柄揭。", "邇來邊瑣向平寧，西土民艱隨殄滅。", "撞搪噭呼間未免，寸地尺天吾忍免。", "公身固已佩安危，公壽應當等溟渤。", "花明柳暗沙堤外，著眼昌昌見春物。", "想當鳳沼引夔龍，內樂宮壼儼成列。", "天皇酌醴賜加勞，詞人第頌歌明哲。", "會令宇宙還帖泰，要與鴻濛論融結。", "此時桃李競新枝，草木恩光相煥發。", "小儒囿身坱圠內，獨駕封軺來百粵。", "惟當歲獻南山詩，長與天朝誇突兀。"]'),
('6eece68b-0f1a-4a15-80a6-e1058bef2dd3','贈龜山慧海長老','敖陶孫','宋','宋诗','song-poetry','','[]','向來縛虎正死急，今日看牛無可鞭。',304,'全唐诗/poet.song.173000.json','["向來縛虎正死急，今日看牛無可鞭。", "我提審定之兩印，十年勘盡諸方禪。", "浙東西山好僧相，頭目靜如秋水蓮。", "試令回眼參壁觀，掣頓已作獼猴顛。", "平生棒喝不作用，何者可毒臞翁拳。", "龜山爬沙吸淮海，上有蜀客蹲其顛。", "石顱鐵脊鋸牙齒，老龜無力供迴旋。", "自言小來坐鬼窟，木客對誦明月篇。", "山中白石足朝飯，無語可對蹲鴟前。", "一行乃得命大謬，萬事瓦裂今蕭然。", "祇念竿木事遊戲，鐵胎五百成拘牽。", "至人無心亦到我，顧念塵脚相摩湔。", "是身如雲即虛幻，安要包裹爭鮮妍。", "爾來臞翁頗狡獪，隨風轉柂忘洄沿。", "都梁采藥竟何有，杖頭挑得枯藤僊。", "高堂暗坐觸蝙蝠，放光時有階頭磚。", "了無一法可酬難，蒲團禪板久已捐。", "山空月明礎石員，百圍老幹行參天。", "何當斷手釋椎鑿，與師共泛荆溪船。"]'),
('99aa8966-441c-49ef-87cd-756f6b992c00','中夜嘆','敖陶孫','宋','宋诗','song-poetry','','[]','臞庵胸中空濩落，正爾有愁無處著。',304,'全唐诗/poet.song.173000.json','["臞庵胸中空濩落，正爾有愁無處著。", "比來有酒三捫膺，突兀又似堆衡霍。", "道邊俗子畧滿眼，舉扇障塵不容却。", "正如白日殺快讎，草草九衢面皆惡。", "不應叔末盡鬼魅，世道如此我何樂。", "獐頭鼠目動侮人，貌敬逡巡背輕薄。", "其餘邊幅綴周孔，汝身無苦何遭縛。", "中原干戈六十載，八陵玉座塵漠漠。", "假君無力堪汛掃，渠可忘憂置恢拓。", "屯田邊壘差易事，三十餘年束高閣。", "嗚呼吾君至仁厚，一言罷行水赴壑。", "雷塘勺陂可復請，專創一司足經畧。", "牛犁居屋旋填補，虎士編氓間參錯。", "聊城指日下魯奇，祁連刻期開衛幕。", "行之十年倘未效，臣頭請膏斬馬鍔。", "奈何諸人忍奈事，天保正用初無作。", "居然判道君北海，不復追隨我西洛。", "墨池到了須楯鼻，茶甌小緩支鐺脚。", "儒生寂寞守太玄，共盡同歸一丘壑。"]'),
('fbc548e9-2519-420f-869e-5b4d80a35fb7','張連魯仲本蜀人從其先宦嶺表僅五六十年矣爲言廣州城內有檜奇古甚土人相傳自唐末至今往時東坡先生道惠宿留此州嘗供佛其下得甘露綴枝之異予徵二事皆無所據而耆舊相傳云爾要必有從來者張乞詩爲賦長謠一篇','敖陶孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','亳州仙檜聃翁玩，西湖老檜陳朝餘。',304,'全唐诗/poet.song.173000.json','["亳州仙檜聃翁玩，西湖老檜陳朝餘。", "區區草木定何意，多生要傍齋房居。", "吾行東廣足已劬，兩年纔到安期蒲。", "菩提葉老還書蠹，波羅子重空懸壺。", "地荒了不快人意，照耀南海何能無。", "邇來劃見張公子，火雲肉山煉心水。", "搜奇訪古偶及之，破笑勞君相指似。", "門前罄折得堵宮，諸天龍神俱儼容。", "左呵右禁防所奪，上帝遺我駟玉龍。", "問從張公得明證，指畫檜身分四印。", "嗟哉此老亦不逢，生世適當唐晚閏。", "天迴地轉逢今茲，霸戰王爭了不知。", "試看左紐足奇怪，虎脛骨貫龍鱗皮。", "霜枝雪榦如相偶，老大商山餘四叟。", "年深幾慣雷霆爭，夜定一從牛兕走。", "道形天貌吾何心，晚歲聊依清磬音。", "忽然空中聞款綮，指李丈人勤遠臨。", "更傳坡仙曾設供，甘露綴枝如潑汞。", "桃源事託五柳翁，後世請將吾語用。"]'),
('679523e0-c6d6-40f8-af77-81576fbf06cb','長歌行','敖陶孫','宋','宋诗','song-poetry','','[]','徐州文壤基崇壇，老蔡徑尺刳心肝。',202,'全唐诗/poet.song.173000.json','["徐州文壤基崇壇，老蔡徑尺刳心肝。", "銅槃照夜血光碧，上有慘澹雙鏌干。", "請君載書許君死，徹器未竟盟已寒。", "了知今人不如古，古人亦有難知處。", "張生刎頸殲陳餘，酈兒給印屠諸呂。", "勸君結交勿結心，報君多是逡巡人。", "救饑重脫嗾獒厄，出淖曾叨食馬恩。", "輕言託心腹，心腹爲禍媒。", "畏途巉空薄側掌，要離孤塚空崔嵬。", "我願中堂置甕常盛酒，後列絲竹前賓友。", "細腰燈前拓秋窗，有來白事酹其口。", "交亦不必結，名亦不必聞。", "燕南氍毹藉地醉，千載一笑平原君。"]'),
('dbce8f25-e86e-4c2f-bd5d-1e8fd131a07b','次韵翁伯紹教授','敖陶孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南窗解衣學畫史，夢繞西湖貌西子。',208,'全唐诗/poet.song.173000.json','["南窗解衣學畫史，夢繞西湖貌西子。", "了無一語對青山，側釐隃糜相與閒。", "平明視鏡稀可數，生愛詩名壓千古。", "春風別我不作難，壺漿瘦馿行出祖。", "政思坐上覓佳客，廣文先生秀眉宇。", "船頭把詩報忙事，欲些黄陳作黄土。", "摩挲老眼說舊觀，絳衣大冠逢建武。", "二公派當百似續，行舒綴遠如觀舞。", "百年許長作灰冷，手披口吟心獨苦。", "許君一死力負荷，麾斥衆楚昌齊語。", "典衣沽酒人敢易，鼠壤猶堪窖餘窶。", "長生木瓢要賞真，元劉放浪猶詩人。", "眼前生後姑置論，紅紫事休天地貧。"]'),
('31e752ab-4793-4a37-b98f-b9d31afddf8e','代送別趙使君','敖陶孫','宋','宋诗','song-poetry','','[]','白衫紫領休霑襟，聽我一曲截鐙吟。',128,'全唐诗/poet.song.173000.json','["白衫紫領休霑襟，聽我一曲截鐙吟。", "使君五馬新鑿蹄，大江橫前氣駸駸。", "問知淮民何所戀，年來家有生氂犬。", "同州雜鞭且未下，山陰大錢聊可選。", "門闌書生守遺經，二年作吏勞丁寧。", "即日遂良鬚盡白，平生阮籍眼偏青。", "君行奏書踏龍尾，好爲人間種桃李。", "魚竿冷宦不足言，有一負公如此水。"]'),
('68b0a943-decb-4173-bc94-fa8c9f278354','雁中箭詞','敖陶孫','宋','宋诗','song-poetry','','[]','南來羈鴻北方客，背負嚴霜飛不得。',192,'全唐诗/poet.song.173000.json','["南來羈鴻北方客，背負嚴霜飛不得。", "日中命盡射生手，一箭正中凌空翮。", "一鴻中機百鴻驚，點空細字紛斜橫。", "力窮遭烹忍一死，可憐片影長孤征。", "古人畢弋豈無意，登俎亦可無肉味。", "至今暴殄及胎夭，殺氣爲妖滿天地。", "物生何至相吞屠，蒼天變化還須臾。", "坐殿忽作杜鵑去，行河豈意黄能趨。", "人蟲得喪無了日，客行感此淚橫臆。", "有弟落南今在亡，十年一字無消息。", "冥鴻一來聽祝辭，世間踏地皆危機。", "菰蒲飽霜湖水滿，見草爲人汝當遠。"]'),
('435f938d-9814-48b8-9445-e0374167ff00','送楊帥赴詔','敖陶孫','宋','宋诗','song-poetry','','[]','謂公目光謝牛背，公視赤子未脫綳。',208,'全唐诗/poet.song.173000.json','["謂公目光謝牛背，公視赤子未脫綳。", "謂公足跡躡龍尾，公守凍壁如癡蠅。", "看公進退無一可，公欲自判何方憑。", "邇來詔書下峻層，趣公入趁花底根。", "腰龜杖節亦已了，持橐上雍須公能。", "公言臣是江西獰，坐中十言九带棖。", "滿朝貴人面雪色，可忍一一爲臣頳。", "吉州城南水如澠，有蔞可絲魴可罾。", "書生說食涎已滿，寄謝龍闕雙觚稜。", "祝融海王神最靈，胡能呵霧遮前程。", "堂堂大舸截江去，天吳擊鼓馮夷迎。", "孰居其間爲此爭，東西欲奪公無情。", "衆生焦灼大火聚，公但抱寶眠清冷。"]'),
('c1944eea-c9ed-426a-8ea8-020166339a71','再用韵酬陳祕校來詩有擊楫清中原之志故中間多及之','敖陶孫','宋','宋诗','song-poetry','','[]','海中老蜃噓樓閣，局促鶢鶋魯東泊。',224,'全唐诗/poet.song.173000.json','["海中老蜃噓樓閣，局促鶢鶋魯東泊。", "忍能杯視九雲夢，戢戢魚頭沸相灂。", "濤江亭東識君面，再見白也大鵬作。", "雄辭已褫壯士氣，窮髮天驕堪面縛。", "我家荆楚起孤劍，奮身多自青油幕。", "南遷閩嶠已三世，土風正坐儒冠錯。", "尚當拂磨十丈崖，刻頌欲將文字託。", "今君精悍喜談兵，指畫魚麗分鸛鶴。", "會當平敵走行在，金印皇皇看手攫。", "不應從我學詩句，格律牽纏紛纆索。", "世間冷暖逐處所，火井自溫冰井涸。", "論詩說劍亦奇事，媿乏三盃澆索寞。", "誓將併敵起三關，不作羣狐猜鎮惡。", "齊紈魯縞我山東，指日戎車會于濼。"]'),
('3a68f0bf-cedf-47a6-92f0-bd43967ec983','永嘉魏祕校訪僕蕭寺且言出處甚詳屬與余同客崑山使人不能無懷魏云欲還故鄉而吳中兒女森森如立竹矣因用所惠詩韵聊綴數語以塞來意韵長不復櫽括資客中一噱可也','敖陶孫','宋','宋诗','song-poetry','','[]','陳侯一榻懸千古，賤子何能望入府。',224,'全唐诗/poet.song.173000.json','["陳侯一榻懸千古，賤子何能望入府。", "門前誰者高櫑具，甚口美髯方快覩。", "裙衣新失大雪寺，告訴天吳煩拆補。", "陰風立我鐵戶限，起到不供人笑侮。", "邇來稍挫牙角勇，一見何知肺肝吐。", "繪衣君欲試華蟲，鶑領吾方愧桑扈。", "新篇直欲命騷僕，寸舌寧當下齊虜。", "已從雁蕩歌貫休，更向烏江憐項羽。", "遥知筆下卷波瀾，乞與胸中洗塵土。", "魏侯魏侯聽我語，醉裏江山迭賓主。", "吳歌一聲落青蒲，遮莫催歸啼杜宇。", "江南江北知何許，萬水千山話僧廡。", "因君永嘉說謝客，南海維摩堪淚雨。", "樽前卜試鸜鵒舞，一鬨從渠較鄒魯。"]'),
('caecb9b4-a1b6-4ea0-a0d8-0382ab647207','送別張長官東歸','敖陶孫','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','勸君少留持一觴，三年一日纔初長。',256,'全唐诗/poet.song.173000.json','["勸君少留持一觴，三年一日纔初長。", "春風愔愔著桃李，露雨沃沃開麻桑。", "道傍簫鼓莫凄咽，使君平生面如鐵。", "裁量渠是臺閣具，坐使霜蹄困羈紲。", "前生瘡痏生潢池，手披腹摩隨所醫。", "州家徵財使家督，灌輸輦送無愆期。", "諸郎自是豐年玉，誰能待荒學儲穀。", "虛名作祟謹勿近，介者得嫌同者俗。", "臞庵先生室無鄰，晚年得君情更親。", "常時問政有寬猛，獨覺處世無緇磷。", "何人幕府容疎懶，憶君高樓衣带緩。", "朅來問訊池上魚，一笑相看喜無算。", "了知喜極還生愁，獨自含情上小舟。", "府中參佐足追送，坐念長江天際流。", "還家且種鹽官棗，垂柳當門樂華皓。", "詔書定起尹翁塗，珍重身名莫草草。"]'),
('d7bac91f-ec01-4b92-9f74-f912bc9be511','上丁郎中  其一','敖陶孫','宋','宋诗','song-poetry','','[]','君家去天纔三百，君身去天無尺五。',64,'全唐诗/poet.song.173000.json','["君家去天纔三百，君身去天無尺五。", "忽憶泥功棧外山，盡是杜老思君路。", "而今西子媚迴塘，坐令猛士紆柔腸。", "可能直下窺秦隴，翻作吳兒時世粧。"]'),
('1ae5d5fe-7d54-483e-b0c8-59207d0d8e77','上丁郎中  其二','敖陶孫','宋','宋诗','song-poetry','','[]','仲章薛公十一鶴，季章李白詩百篇。',64,'全唐诗/poet.song.173000.json','["仲章薛公十一鶴，季章李白詩百篇。", "自我過都得二老，頗覺閩蜀堪同川。", "今來劃逢丁將軍，秀傑萬里來嶓岷。", "篋中當自有行記，幸借天壁開嶙峋。"]'),
('02352272-24c9-4d64-9f35-1414a9f5da0c','送舅氏行','敖陶孫','宋','宋诗','song-poetry','','[]','迎面賓鴻去未多，攬袪官柳不勝拖。',64,'全唐诗/poet.song.173000.json','["迎面賓鴻去未多，攬袪官柳不勝拖。", "還家定笑扊扅曲，上水初聽欵乃歌。", "濁酒過鄰通問訊，青燈語夜愜平和。", "機雲也有謀東日，可解滄浪理釣蓑。"]'),
('8de9cf24-347f-4d69-ba4f-c2378f623145','北窗雅言寄朱仁叔','敖陶孫','宋','宋诗','song-poetry','','[]','風日暖，天大裘。',190,'全唐诗/poet.song.173000.json','["風日暖，天大裘。", "蠅飛打窗油，北窗墳策高於丘。", "我欲發視勞牽抽，把酒起望天門陬。", "斜鴻書破半張紙，枯荷網空散鉛水。", "機中挑出錦文詩，淚滿鴛鴦半身紫。", "新愁波不窮，後愁更隨風。", "美人如嬌春，何物可御冬。", "古人已恨愁不足，却遣今人送愁續。", "輕將玉斧贈吳剛，漏得寒光照孤宿。", "素女爲天揀退絲，伶倫猛截孤生枝。", "沙蟲含冤射千載，誰勸黄竹栽瑶池。", "歌夜長，歌夜短，淮南桂枝香滿滿。", "爲君持酒壽金人，少待露盤辭玉椀。"]'),
('0d72f224-0c9b-4819-a9a7-1add15546086','飄風荆溪','敖陶孫','宋','宋诗','song-poetry','','[]','船頭月渾雲不度，轉眼光陰遽如許。',64,'全唐诗/poet.song.173000.json','["船頭月渾雲不度，轉眼光陰遽如許。", "江湖無地寄風威，短蓑遺作胡旋舞。", "還將老病入孤舟，碧波爲人生白頭。", "闌中五更鵝鴨亂，老漁畫肚起長算。"]'),
('c56b7153-557e-4ffb-bafa-98a2551ec71c','贈英德風和尚','敖陶孫','宋','宋诗','song-poetry','','[]','風師風狂無是處，文采成龍或成虎。',64,'全唐诗/poet.song.173000.json','["風師風狂無是處，文采成龍或成虎。", "向來打橛釘虛空，今日入山還削鐻。", "晴窗洗出烟巖秋，休嗟李廣不封侯。", "見說行年今在坎，老慵且作囚山囚。"]'),
('20c8746f-bc5f-40c9-94be-49da72d039b1','月華道中','敖陶孫','宋','宋诗','song-poetry','','[]','善財平明白下床，供君一鉢曹溪香。',192,'全唐诗/poet.song.173000.json','["善財平明白下床，供君一鉢曹溪香。", "山中老盧致無恙，爲我一洗醒而狂。", "問君江行何所見，邂逅今朝識山面。", "羣峰亦自不相知，漥者欲逃危欲獻。", "漥逃危獻知奈何，小草遠志元同科。", "時來隨喜出雲雨，不來抱藹休巖阿。", "老人於山消底物，畢願託身仍託骨。", "接頤孤撐看未已，萬馬崩騰過倏忽。", "貴人祗聽宮門鐶，何曾一葉吼冰灘。", "轉頭便下貞陽峽，嶺猿舉臂招入還。", "歸來海上亦不惡，把酒持螯誇至樂。", "明朝遠碧望林巒，依舊朱欄照城郭。"]'),
('cf32a56a-8b80-435b-8f32-68e58278150c','再賦薄薄酒','敖陶孫','宋','宋诗','song-poetry','','[]','薄薄酒，全吾天。',190,'全唐诗/poet.song.173000.json','["薄薄酒，全吾天。", "醜醜婦，引吾年。", "敗繒粗布形骸便。", "辛勤著書塞屋椽，何如郭外二頃桑麻田。", "折腰斂板高鳶肩，何如方床八尺供橫眠。", "左爲劍鋩右鼎耳，勸君却步行相先。", "斗量明珠埒編錢，郿塢未就臍已燃。", "十眉間坐爭連蜎，絕纓滅燭薰腥膻。", "農家醜婦眉半櫛，白頭惟有夫壻憐。", "勸君酒薄君勿嗔，尚方賜尊能殺人。", "力微覆餗有明誡，食鮭三九元非貧。", "酒不薄，人自薄。", "妻不惡，人自惡。", "不如濁酒三盃呼醜婦，共作原頭賽神舞。"]'),
('256f73d7-6c32-4d7a-9e51-e1e901dc38af','續薄薄酒','敖陶孫','宋','宋诗','song-poetry','','[]','薄薄酒，勝齋蔬。',144,'全唐诗/poet.song.173000.json','["薄薄酒，勝齋蔬。", "粗粗布，勝無襦。", "醜妻惡妾勝鰥孤。", "叱塗呵道驅高車，何如醉歸連臂行相扶。", "巍冠束带商唐虞，何如北窗散髮擁腹千爬梳。", "金樽瓦盆酒如一，食芹差可無彫胡。", "名堯字孔相號呼，百年螻蟻同丘墟。", "朝爲卿相暮匹夫，青黄蚤失溝中枯。", "錐利未必賢椎愚，左圓右方徒區區。", "不如濁酒三盃對醜婦，荆釵布裙相媚嫵。"]'),
('0657e3a2-1c9d-438c-847e-bd75c6c5fe88','次醉中歌','敖陶孫','宋','宋诗','song-poetry','','[]','犢車油壁塵紛紛，恨君不識如花人。',179,'全唐诗/poet.song.173000.json','["犢車油壁塵紛紛，恨君不識如花人。", "金鞭爭道誰家郎，出門三日香人牀。", "春風酒面吹微鱗，主人拔釵留上賓。", "洞房燭花盡意明，爲君拂絃駐歡情。", "陣鴻塵澀聲難安，城烏夜啼訴春寒。", "吳歈未終初日上，璇題藻井知無恙。", "請君銜盃莫問天，茂陵劉郎初學僊。", "人生百歲俱可憐，願君流歡及盛年。", "世間萬事不如酒，九環寶带時人有。", "感君一曲寬百憂，當時見人面色羞。", "君不見牆東儒生食井李，一生飲牛廉讓水。"]'),
('58973ef3-9d42-40da-a0d5-1e573a1b1fa6','醉歌','敖陶孫','宋','宋诗','song-poetry','','[]','得誰釀法乃爾佳，連引數盃極口誇。',142,'全唐诗/poet.song.173000.json','["得誰釀法乃爾佳，連引數盃極口誇。", "須臾忘物亦忘我，是非榮辱不可加。", "兒童相隨拍掌笑，阿翁醉也扶歸家。", "平生故人趙半刺，遣騎折送園中花。", "飲酒不待勸，夜如何其月欲斜。", "倒著接䍦自起舞，笛聲趁拍鼓三撾。", "陶陶兀兀意有得，小姬在傍雙髻丫。", "驅令磨墨具紙筆，滿幅大草飛龍蛇。", "婦云汝醉當止矣，明日酒醒不愧耶。"]'),
('822619f9-0b26-4ecc-9774-8b8669cfa3ad','謁衛參政','敖陶孫','宋','宋诗','song-poetry','','[]','頃年投詩衛左史，今年謁詩衛相公。',288,'全唐诗/poet.song.173000.json','["頃年投詩衛左史，今年謁詩衛相公。", "何方客子辟道路，詩卷長邀石浦風。", "先生官職泥土如，萬事盡付阿堵中。", "天教權嬖表忠節，劍首一吷毫毛空。", "祇今事業已如許，願聞當時北歸語。", "面對手畫真自知，十年絕口吾甚武。", "謝安風流過王導，芙蓉王公竊其表。", "從來雅志在東山，角巾不爲箏歌老。", "古人進寸退一尺，江草江花足自適。", "功名時來不作難，雷動風行本無跡。", "百姓相驚當歷耳，三江五湖作瘡痏。", "百年天地亦悠悠，長鑱老人淚如水。", "側傍湖脚淀山藍，出見輕鷗已不凡。", "頗聞琳琅塞門內，三筆六詩公所監。", "何能撰杖閲諸子，看公著帽淹幾晷。", "朱衣目前空復愁，客有焦桐勞下指。", "去家初無可葺牆，獨抱遺經天一方。", "石浦倘爲蒼生起，天衢日轂遥相望。"]'),
('742593d9-45bf-4ce4-9c23-90943a02cb99','短歌贈臨安友人','敖陶孫','宋','宋诗','song-poetry','','[]','素絲衝塵化爲墨，老人雙鬢無由黑。',128,'全唐诗/poet.song.173000.json','["素絲衝塵化爲墨，老人雙鬢無由黑。", "俗兒翻手候炎凉，惟有君心比霜雪。", "破窗草亢風雨寒，夢遊帝鄉虎當關。", "枯魚對酒淚濺俎，雄劍夜吼銅花乾。", "二十辭家顔色故，春心不語絃解語。", "借君古鏡施鉛華，含羞獨泣羅房雨。", "青天中開多不平，少年裘馬如流星。", "千金無處買俠骨，坐念歲月空崢嶸。"]'),
('9a6c3c99-5f13-41ae-b41b-e00ffb9a06e5','夜坐','敖陶孫','宋','宋诗','song-poetry','','[]','來雁無消息，寒蟬久寂寥。',48,'全唐诗/poet.song.173000.json','["來雁無消息，寒蟬久寂寥。", "鬢毛隨日化，吾意得詩消。", "樓影三更淡，天星幾夜摇。", "眼中無長物，拄頰又明朝。"]'),
('543443f5-d216-414f-90fc-03739a123eab','倦夜','敖陶孫','宋','宋诗','song-poetry','','[]','河津傳五漏，霧雨入千家。',48,'全唐诗/poet.song.173000.json','["河津傳五漏，霧雨入千家。", "白日鳴饑鼠，深更歇怒蛙。", "境空愁稍進，詩短意能加。", "客路多風雨，深憂斗柄斜。"]'),
('85f3eb0a-30a4-41fa-a2c6-8f909260ba4b','贈得一禪師','敖陶孫','宋','宋诗','song-poetry','','[]','舊時黄正父，今日一浮屠。',48,'全唐诗/poet.song.173000.json','["舊時黄正父，今日一浮屠。", "四海誰知己，三更忽撚鬚。", "空山吼獅子，暗壁縛於菟。", "何日當吾眼，藜牀淡爾臞。"]'),
('bea2f3a3-0889-464b-a9e0-1bc35c3cdb6b','燈下嘆','敖陶孫','宋','宋诗','song-poetry','','[]','老馬知塗益可羞，寒燈冷硯照窮愁。',64,'全唐诗/poet.song.173000.json','["老馬知塗益可羞，寒燈冷硯照窮愁。", "著書不望從兒讀，歸舍何當與婦謀。", "赤脚踏鯤真浪許，短衣射虎恐長休。", "何人得似襄陽守，乞我苕湖十頃秋。"]'),
('45917c0d-0da0-4156-95b0-e98779bca4f1','次韓耕道贈別韵','敖陶孫','宋','宋诗','song-poetry','','[]','一昨羊城別五僊，駕言韶石叩鈞天。',64,'全唐诗/poet.song.173000.json','["一昨羊城別五僊，駕言韶石叩鈞天。", "偏師政擬劘詩壘，淺瀨那知滯酒船。", "但使繫書勤雁足，敢思騰上竦鳶肩。", "區區定取韓康笑，賣藥逃名却自然。"]'),
('4cec3386-6358-4a48-8cfd-c3a67a3527ff','病中用杜工部江村韵','敖陶孫','宋','宋诗','song-poetry','','[]','早歲縱橫論九流，中年往往愛清幽。',64,'全唐诗/poet.song.173000.json','["早歲縱橫論九流，中年往往愛清幽。", "細觀夢境皆爭鹿，靜遣機心欲狎鷗。", "池上貪閒臨晉帖，燈前抱病看吳鈎。", "山林鍾鼎從天賦，言志俱慚點與求。"]'),
('204fad03-0da6-4482-a25c-64b967ab2df1','和開元寺省公韵','敖陶孫','宋','宋诗','song-poetry','','[]','振錫浮盃定偶然，繭窠誰見老蠶眠。',64,'全唐诗/poet.song.173000.json','["振錫浮盃定偶然，繭窠誰見老蠶眠。", "祇知大膽嘲無本，渠識前身是普賢。", "師欲贏糧趨建德，我慚觀畫訪開先。", "莫將幻境誇陽燄，吐盡多生渴死涎。"]'),
('758bdf54-a3c1-4a49-b9d9-a1c28f8d421e','至日記見簡輔漢卿二首  其一','敖陶孫','宋','宋诗','song-poetry','','[]','滿窗晴旭散輕埃，報答生成只酒盃。',64,'全唐诗/poet.song.173000.json','["滿窗晴旭散輕埃，報答生成只酒盃。", "篇什正須今日用，歲時偏傍俗人來。", "輕舠上藕泥初拭，小巷爭魚臭不開。", "試作橫竿權土炭，聊從夜半候陽回。"]'),
('d656789c-7419-479e-bb6c-3b6bc98fa1c5','至日記見簡輔漢卿二首  其二','敖陶孫','宋','宋诗','song-poetry','','[]','枕上吟哦安意好，新詩自覺鬼神扶。',64,'全唐诗/poet.song.173000.json','["枕上吟哦安意好，新詩自覺鬼神扶。", "遥傳舊歲無多子，皆試新衣是早圖。", "天下自須胡伯始，江東只在管夷吾。", "鄉山此際當治麥，誤矣爲文傚兩都。"]'),
('c64e7071-8c1a-4304-8f9b-f2cc44e960df','賀郡守得江陰','敖陶孫','宋','宋诗','song-poetry','','[]','檢點詩篇方細讀，忽傳新渥照澄江。',64,'全唐诗/poet.song.173000.json','["檢點詩篇方細讀，忽傳新渥照澄江。", "榮公銅虎非渠事，舊憶河豚是此邦。", "蕭散蓋公宜置舍，風流謝守想臨窗。", "他時我得扁舟去，直過凝香索酒缸。"]'),
('2cf870cc-5075-4386-8698-5de1cd3e6ef8','自笑','敖陶孫','宋','宋诗','song-poetry','','[]','抱甕終焉與世迷，斲輪久矣嘆吾衰。',64,'全唐诗/poet.song.173000.json','["抱甕終焉與世迷，斲輪久矣嘆吾衰。", "江南未必無佳士，海內何由得二兒。", "不共施梁爭折角，却思陶謝與同時。", "歌成未免傍人笑，農馬雖專技已卑。"]'),
('87de8980-51e6-4872-94a5-64f93470dc18','清明日湖上晚步','敖陶孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一百五日苦多雨，二十四花能幾風。',64,'全唐诗/poet.song.173000.json','["一百五日苦多雨，二十四花能幾風。", "壯心欲與兒女競，春事翻成寇盜空。", "公私蛙合笙歌裏，客主山張圖畫中。", "作意後遊仍獨醉，西湖莫忘遠來翁。"]'),
('27c4444a-0b57-4a36-945a-a2babf1da256','寄德久舍人時將過吳門','敖陶孫','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','昏花亂眼嘆吾衰，寶带忘腰羨子宜。',64,'全唐诗/poet.song.173000.json','["昏花亂眼嘆吾衰，寶带忘腰羨子宜。", "碓下誰明能行者，甕中聊覓永禪師。", "醉鄉欲結無爲社，劫火難燒見在詩。", "忽憶扁舟洞庭路，霜螯斫雪點橙絲。"]'),
('125ff6ba-cd1c-4963-aa91-b7e7f09ad7ba','送王楚材往湖州聽讀','敖陶孫','宋','宋诗','song-poetry','','[]','短羽真成入彀游，小儒蹤跡欲誰求。',64,'全唐诗/poet.song.173000.json','["短羽真成入彀游，小儒蹤跡欲誰求。", "非關古字誅揚子，自是諸生欠沈猶。", "百計千方元薄命，雙溪二水各宜秋。", "此行試卜唐夫子，會向芹邊問楚囚。"]'),
('f8abf500-acfd-4e6e-9705-7475fbe97f7f','贈玻璃僧慧觀長老','敖陶孫','宋','宋诗','song-poetry','','[]','千年觀一如，三日客同居。',120,'全唐诗/poet.song.173000.json','["千年觀一如，三日客同居。", "祇道清淮近，烏知濁世疎。", "地窮初限橘，水富巧藏魚。", "排闥風烟入，觀心視聽虛。", "飯香鴉闖戶，茶熟水鳴除。", "潮載支祁憤，天關禹貢書。", "磬材徵古在，石蕝表兇餘。", "董杏通鄰堵，秦瓜過滿車。", "遊方孤雁去，問法翠屏舒。", "何日荆溪道，誅蓬對結廬。"]'),
('f0eca460-0ca2-4976-a4cc-8ed53d2f4fc1','晚霽湖邊獨步','敖陶孫','宋','宋诗','song-poetry','','[]','短短桃身盡著花，微風細雨響蘆芽。',32,'全唐诗/poet.song.173000.json','["短短桃身盡著花，微風細雨響蘆芽。", "一晴眼底皆新物，蛺蝶成羣聚淺沙。"]'),
('0cc2d962-45bb-4d46-bab7-eda75748bb4e','題郁氏子床屏','敖陶孫','宋','宋诗','song-poetry','','[]','歌舞教成王謝宅，百年華屋幾人居。',32,'全唐诗/poet.song.173000.json','["歌舞教成王謝宅，百年華屋幾人居。", "豈無藤葛垂陰地，女轉繅車兒讀書。"]'),
('ad7698ec-db62-4936-b52a-600abe73e9c4','醉歸','敖陶孫','宋','宋诗','song-poetry','','[]','夜深霜月冷侵膚，醉飲歸來得自娛。',32,'全唐诗/poet.song.173000.json','["夜深霜月冷侵膚，醉飲歸來得自娛。", "霧氣水光同浩渺，誤看田野作江湖。"]'),
('48497402-402f-4f83-9e56-f82cdbefea78','次潮陽寧公詩韵三首  其一','敖陶孫','宋','宋诗','song-poetry','','[]','天外誰飄桂子風，老夫鼻觀已先通。',32,'全唐诗/poet.song.173000.json','["天外誰飄桂子風，老夫鼻觀已先通。", "直須斬斷年時話，匹似西來歎不逢。"]'),
('43a6c9d4-c2cc-474a-a2ab-6a3888568f7e','次潮陽寧公詩韵三首  其二','敖陶孫','宋','宋诗','song-poetry','','[]','十方無壁慣曾遊，一片孤雲任去留。',32,'全唐诗/poet.song.173000.json','["十方無壁慣曾遊，一片孤雲任去留。", "莫話潮陽舊公案，天台行色滿簷頭。"]'),
('6e5b80e1-fc78-45a7-9b0d-e4bea2c533cb','次潮陽寧公詩韵三首  其三','敖陶孫','宋','宋诗','song-poetry','','[]','竹枝拗折殊多事，參取茶甌未到前。',32,'全唐诗/poet.song.173000.json','["竹枝拗折殊多事，參取茶甌未到前。", "爲報天台癡五百，撞齋邏粥莫爭先。"]'),
('2abaeec2-d528-4bd3-b70c-655ad26f0a39','送行者妙淙往青龍謁陳七官人','敖陶孫','宋','宋诗','song-poetry','','[]','三生同聽寺樓鐘，緊峭芒鞋任所從。',32,'全唐诗/poet.song.173000.json','["三生同聽寺樓鐘，緊峭芒鞋任所從。", "莫向華亭覓船子，趙州橋下有青龍。"]'),
('e66982ad-66e3-4855-9402-f36b68108b84','爲竹奴解嘲用山谷先生韻','敖陶孫','宋','宋诗','song-poetry','','[]','通身有眼更無腸，好上臞庵師子床。',32,'全唐诗/poet.song.173000.json','["通身有眼更無腸，好上臞庵師子床。", "莫作綠衣顛倒想，班姬陳后兩凄凉。"]'),
('bf47b8d0-eff8-4a02-95a2-d25bd0d307df','送霅川丁世卿宰舒之懷寧  其一','敖陶孫','宋','宋诗','song-poetry','','[]','長安亂葉舞征衣，獨把新詩送吏師。',32,'全唐诗/poet.song.173000.json','["長安亂葉舞征衣，獨把新詩送吏師。", "自古才名諳宦拙，邇來官事要兒癡。"]'),
('d8b757cd-7151-45c1-a0cb-b614b74008c1','送霅川丁世卿宰舒之懷寧  其二','敖陶孫','宋','宋诗','song-poetry','','[]','八公草木迎人處，三老風沙上水時。',32,'全唐诗/poet.song.173000.json','["八公草木迎人處，三老風沙上水時。", "直使邊頭行國寶，少年白面且經維。"]'),
('fc89fe34-bc91-4a68-a81d-73450d185fde','悼趙忠定','敖陶孫','宋','宋诗','song-poetry','','[]','左手旋乾右轉坤，羣公相扇動流言。',64,'全唐诗/poet.song.173000.json','["左手旋乾右轉坤，羣公相扇動流言。", "狼胡無地歸姬旦，魚腹終天痛屈原。", "一死固知公所欠，孤忠頼有史長存。", "九原若遇韓忠獻，休說渠家末代孫。"]'),
('89668402-8b64-4473-b7f2-7bdcc4986cf2','皋亭山','敖陶孫','宋','宋诗','song-poetry','','[]','樵路縈連入翠微，清泉白石可忘機。',64,'全唐诗/poet.song.173000.json','["樵路縈連入翠微，清泉白石可忘機。", "雲中犬吠劉安過，樹杪春深望帝歸。", "白鶴肯留華表語，蒼官合受錦衣圍。", "珠襦玉柙今何許，一笑人間萬事非。"]'),
('853c610b-4277-4565-ab60-061baa4705f5','擣衣吟','敖陶孫','宋','宋诗','song-poetry','','[]','北鄰擣衣聲，明當葭管動。',55,'全唐诗/poet.song.173000.json','["北鄰擣衣聲，明當葭管動。", "隨宜過街巷，一歲三日用。", "請君歇砧杵，指直霜氣重。", "君不見南鄰已試明年燈，應製春衫泥小鳳。"]'),
('59d68d52-5bcf-4a4e-a90f-14cd2bf22e71','雪中對酒效昌黎體','敖陶孫','宋','宋诗','song-poetry','','[]','雪乃雨之死，雨乃雪之生。',72,'全唐诗/poet.song.173000.json','["雪乃雨之死，雨乃雪之生。", "譬彼潮與水，同出而異情。", "洑流或亂潮，凍雨或間雪。", "達人於此時，著眼試分別。", "等是天一生，而有生殺存。", "所以古聖賢，諄諄畏鄉原。"]'),
('8104a933-561f-4b04-87b1-04e48528f14a','次韵蓋睎之見憶','敖陶孫','宋','宋诗','song-poetry','','[]','臞翁方解夏，蓋令正防秋。',48,'全唐诗/poet.song.173000.json','["臞翁方解夏，蓋令正防秋。", "浄社吾追遠，侯封子擇留。", "硬黄隨意草，大白幾時浮。", "莫話河南北，傷心感沛州。"]'),
('9bfac21c-9a9c-4924-9d3f-4d749d8b7eae','小樓  其一','敖陶孫','宋','宋诗','song-poetry','','[]','只有書樓日日登，欄干東角每深憑。',32,'全唐诗/poet.song.173000.json','["只有書樓日日登，欄干東角每深憑。", "一層已是愁無奈，想見仙人十二層。"]'),
('aaa40f95-a22b-495a-a25c-82f09acee94b','小樓  其二','敖陶孫','宋','宋诗','song-poetry','','[]','泥濫花淹燕不歸，輕陰時獵酒家旗。',32,'全唐诗/poet.song.173000.json','["泥濫花淹燕不歸，輕陰時獵酒家旗。", "無情最奈牆東柳，正嚮愁時寂寂垂。"]'),
('bb608c3a-67ee-46c5-8677-84b7d72055ca','旅舍七首  其一','敖陶孫','宋','宋诗','song-poetry','','[]','學道欠定力，一寒便生嗔。',72,'全唐诗/poet.song.173000.json','["學道欠定力，一寒便生嗔。", "古來雪埋腰，定知英雄人。", "去爲百錢遊，得酒不濡唇。", "慘澹行歌歸，仰面東南雲。", "紛紛過車馬，寂若耳不聞。", "退坐茆簷底，徒有豪氣存。"]'),
('f7886ec9-133e-4a56-99dc-ace4a92d79b3','旅舍七首  其二','敖陶孫','宋','宋诗','song-poetry','','[]','雪後天正碧，須臾白龍鱗。',72,'全唐诗/poet.song.173000.json','["雪後天正碧，須臾白龍鱗。", "暮寒急歸鳥，新月生微顰。", "帝居時節正，物肅天地仁。", "黄旗在何方，指畫分星辰。", "拊攔發浩歎，肝膽空輪囷。", "兒女顧我笑，微霜濕衣巾。"]'),
('b5d0ea43-2a78-4d13-a65d-87b33f420465','旅舍七首  其三','敖陶孫','宋','宋诗','song-poetry','','[]','今晨日色佳，負暄就前簷。',72,'全唐诗/poet.song.173000.json','["今晨日色佳，負暄就前簷。", "晴鳶盤空闊，始覺天宇嚴。", "怡然一欠伸，雙巒引遐瞻。", "亭亭倒枯荷，似是浮圖尖。", "出家本不難，貝葉明牙籤。", "但恐遠公社，無酒與陶潛。"]'),
('b9c6eaf6-8afb-4e99-9056-34e153ca72cf','旅舍七首  其四','敖陶孫','宋','宋诗','song-poetry','','[]','齧雪蘇州年，嘿數天再閏。',72,'全唐诗/poet.song.173000.json','["齧雪蘇州年，嘿數天再閏。", "當時賈長頭，霜桐送孤韵。", "今年貧更惡，交友雲散盡。", "收自緗楮林，博閲先後進。", "縱橫略千家，詣處合一印。", "文章何當工，一死差可忍。"]'),
('c5221b20-17af-46f6-95b5-5ed473de357b','旅舍七首  其五','敖陶孫','宋','宋诗','song-poetry','','[]','人言我身長，尺度難爲裁。',72,'全唐诗/poet.song.173000.json','["人言我身長，尺度難爲裁。", "居然一瓠壺，略可當酒杯。", "口交市井談，面涴俗子埃。", "謂予倘不化，未覺逆旅猜。", "但恐醉語誤，積毀能焚骸。", "殷勤王先生，脫襪何賢哉。"]'),
('41cba43e-0499-4446-93fb-cad2c9be60e3','旅舍七首  其六','敖陶孫','宋','宋诗','song-poetry','','[]','少時重意氣，裹劍師白猨。',72,'全唐诗/poet.song.173000.json','["少時重意氣，裹劍師白猨。", "神傷化碧血，淚盡如生元。", "晚修漆園方，孔跖付一尊。", "小山受歲晚，片雲時歸屯。", "客來兩團蒲，坐看茶煙翻。", "淵明真可人，觴至輒忘言。"]'),
('d1c2a232-f7ec-4470-b7c1-0e808d672e28','旅舍七首  其七','敖陶孫','宋','宋诗','song-poetry','','[]','我家碧鸛弟，盡用當執殳。',72,'全唐诗/poet.song.173000.json','["我家碧鸛弟，盡用當執殳。", "摧顔伴老翁，意欲化白鳬。", "娟娟熨帛手，見之感無襦。", "坐念粟布謠，於乎予何誅。", "取求不汝瑕，霸心生斷袪。", "請觀澤中鴈，一一稻粱圖。"]'),
('8d11ce3c-e48b-460b-935e-3616cbdd6d11','寄題龔立道農隠堂','敖陶孫','宋','宋诗','song-poetry','','[]','往聞大龔公，魚艾照靈壽。',204,'全唐诗/poet.song.173000.json','["往聞大龔公，魚艾照靈壽。", "當時從肩輿，門生兒子後。", "詩書開似續，文采補耆舊。", "數椽上茅茨，基結稱廣陋。", "壁間落寶唾，半是經濟手。", "坐令農隠堂，贔屭黄姑藪。", "我來雖未識，名下已奔湊。", "功名何足云，短鍤支宇宙。", "所憂飯吾牛，芻惡毛角瘦。", "木奴擅中州，竹君食千畝。", "連車載長腰，橫網遮巨口。", "人生亦何須，不若巴清婦。", "時來食方丈，時去鮭三九。", "常恐少微芒，深夜切奎斗。", "起家公不難，周漢須佐佑。", "敢請益治田，種秫多釀酒。", "歲晚滄洲期，許結羊仲友。"]'),
('ebf10afb-1231-4343-ba53-66a226547372','和留題寓舍','敖陶孫','宋','宋诗','song-poetry','','[]','無可奈何生午凉，暮年王粲更情傷。',64,'全唐诗/poet.song.173000.json','["無可奈何生午凉，暮年王粲更情傷。", "一川水浄鷗能白，九月秋歸蝶自黄。", "洛下篇章還獨詠，遼東城郭正相忘。", "紛紛后土塗泥甚，小試莊周曳尾方。"]'),
('b308ef5b-f361-4289-9f60-ac1a28045f17','絕句','敖陶孫','宋','宋诗','song-poetry','','[]','霜風欺斷柳，星月愛平蕪。',24,'全唐诗/poet.song.173000.json','["霜風欺斷柳，星月愛平蕪。", "船暖知村近，鐘寒想寺孤。"]'),
('b920b284-2444-4a49-92ee-6f15d32f32e1','廣行路難  其一','敖陶孫','宋','宋诗','song-poetry','','[]','有聲且勿吞，有淚且勿傾。',96,'全唐诗/poet.song.173000.json','["有聲且勿吞，有淚且勿傾。", "聲吞斷人腸，淚傾草不生。", "萬事有反覆，天地終無情。", "斲方以爲輪，平地生九折。", "鍛劍使繞指，青萍化爲血。", "筋骸束未貫，光景電露滅。", "我欲竟此曲，此曲能頹山。", "奉君一巵酒，已矣當何言。"]'),
('9aa9772a-4afb-4ad5-9e33-9155fa69a1b2','廣行路難  其二','敖陶孫','宋','宋诗','song-poetry','','[]','有歌且勿發，有舞且勿盤。',96,'全唐诗/poet.song.173000.json','["有歌且勿發，有舞且勿盤。", "歌發愁雲陰，舞盤促歲年。", "古來妾事主，百悲償一歡。", "勸君莫渡河，河伯欲娶婦。", "采桑急蠶饑，送死藁碪手。", "世故常多門，反覆無不有。", "我欲竟此曲，此曲能摧城。", "奉君一巵酒，假日聊偷生。"]'),
('3c93e753-3982-4f87-9735-698448cef93f','送別史友六首  其一','敖陶孫','宋','宋诗','song-poetry','','[]','中興元老堂堂，諸孫玉質金相。',28,'全唐诗/poet.song.173000.json','["中興元老堂堂，諸孫玉質金相。", "封殖毋忘嘉樹，愛思猶及甘棠。"]'),
('809d93e5-fce2-48fd-9af1-3a633e186f69','送別史友六首  其二','敖陶孫','宋','宋诗','song-poetry','','[]','諸君置膜外論，之子真箇中人。',28,'全唐诗/poet.song.173000.json','["諸君置膜外論，之子真箇中人。", "冀北何限千駟，東市初逢一麟。"]'),
('aa1245ea-4dcc-43bb-afe1-44a453ee3dd1','送別史友六首  其三','敖陶孫','宋','宋诗','song-poetry','','[]','過淮讀二山賦，舉世識三槐家。',28,'全唐诗/poet.song.173000.json','["過淮讀二山賦，舉世識三槐家。", "熊魚等所欲者，兕虎敢歎非耶。"]'),
('dd69556c-f931-4d49-9c00-f0a43684225b','送別史友六首  其四','敖陶孫','宋','宋诗','song-poetry','','[]','煙霏巧濕行李，鐘鼓初分去舟。',28,'全唐诗/poet.song.173000.json','["煙霏巧濕行李，鐘鼓初分去舟。", "中有錦衣尚褧，旁看泥軾垂油。"]'),
('bccc6af5-c9ab-446c-8c67-5e97cb7fe080','送別史友六首  其五','敖陶孫','宋','宋诗','song-poetry','','[]','八堰三江良苦，十洲五嶠能明。',28,'全唐诗/poet.song.173000.json','["八堰三江良苦，十洲五嶠能明。", "歸路未誇海市，還家且饜南烹。"]'),
('2e9396cf-c960-4595-83c9-4d28b8e430bf','送別史友六首  其六','敖陶孫','宋','宋诗','song-poetry','','[]','冶渚餞何彥德，虎谿送陶淵明。',28,'全唐诗/poet.song.173000.json','["冶渚餞何彥德，虎谿送陶淵明。", "諸人卿自卿法，今日吾用吾情。"]'),
('d71e3144-7fba-4768-98de-463eb31b7cc4','送月上人住寶積寺','敖陶孫','宋','宋诗','song-poetry','','[]','天竺應須老辨才，羅浮那得染塵埃。',64,'全唐诗/poet.song.173000.json','["天竺應須老辨才，羅浮那得染塵埃。", "試看出日朱明觀，便是中天積翠臺。", "起廢合歸良匠手，安禪好住白雲堆。", "寄聲舊日黄居士，九鎖丹函請一開。"]'),
('d13ca170-2c3d-49e7-a1ff-10af7e4a07bb','沖虛觀','敖陶孫','宋','宋诗','song-poetry','','[]','青筇相伴到仙壇，身寄虛無縹緲間。',64,'全唐诗/poet.song.173000.json','["青筇相伴到仙壇，身寄虛無縹緲間。", "景物迥殊人世界，煙霞深鎖道家山。", "紛紛盡向紅塵老，寂寂誰知白日閒。", "遣履山中棋一局，幾人於此未應還。"]'),
('00bf0497-ab5b-4eb5-8a86-c0d8a1526abc','句','敖陶孫','宋','宋诗','song-poetry','','[]','當年靈壽杖，止合扶孔光。',12,'全唐诗/poet.song.173000.json','["當年靈壽杖，止合扶孔光。"]'),
('8317baf5-6886-4478-aa19-bab2800e9499','老人生旦','陳文蔚','宋','宋诗','song-poetry','','[]','人生富貴多繁華，每遇誕日張綺羅。',256,'全唐诗/poet.song.173000.json','["人生富貴多繁華，每遇誕日張綺羅。", "高堂賓從擁朱紫，金尊捧歡傾流霞。", "青春未暮神仙醉，舞腰回雪皓齒歌。", "難逢樂事買歡笑，千金不惜如泥沙。", "貧家相去一何遠，自嘆居里非鳴珂。", "平時只甘陋巷味，啜菽飲水之日多。", "不知今朝是生旦，東鄰旋問酒可賒。", "烹鮮擊肥非不願，一室懸磬將如何。", "阿爹從容呼兒語，我有至樂非由他。", "立身亦足顯父母，聲名不必登高科。", "顔色苟能奉親歡，悅口不存旨與嘉。", "滿堂雖無金玉富，六籍諸子幸滿家。", "日率兒曹勤誦讀，行慕顔閔心孔軻。", "但得門庭無外事，竹林足以長婆娑。", "子順親慈有餘樂，自然福至由家和。", "籬邊晚菊知人意，歲歲來薦黄金花。"]'),
('1aacc6a8-9b8a-4f51-b24b-cd96d6d3cc9e','和余方叔題傅材甫筠谷韵','陳文蔚','宋','宋诗','song-poetry','','[]','一區投老將焉卜，揚雄草玄那可續。',128,'全唐诗/poet.song.173000.json','["一區投老將焉卜，揚雄草玄那可續。", "何似山中種修竹，白駒皎皎人如玉。", "山深九夏無炎溽，往來不著市廛足。", "主人心地一泓淥，調高和寡陽春曲。", "時聞樵歌起林麓，趺坐道人方閉目。", "讀書萬里歸妙矚，等閒莫躡巢由躅。", "何妨春酒甕頭熟，便約幽人來卜築。", "伯夷清風千載肅，堪笑荒涼舊金谷。"]'),
('1cd995f5-47ce-4780-90e1-9f52a6dc2b29','火田鄭次山貧士也家有燕坐之處五爲賦之 寓意軒','陳文蔚','宋','宋诗','song-poetry','','[]','山水可吾情，對酒不必醉。',24,'全唐诗/poet.song.173000.json','["山水可吾情，對酒不必醉。", "及其不以酒，何由得翁意。"]'),
('9e52b71d-5c4c-4d1b-b9e8-99ce797ae37a','火田鄭次山貧士也家有燕坐之處五爲賦之 觀省齋','陳文蔚','宋','宋诗','song-poetry','','[]','一息萬里馳，白日天無光。',24,'全唐诗/poet.song.173000.json','["一息萬里馳，白日天無光。", "歸來固吾圉，宇泰生吉祥。"]'),
('e152773f-db51-4da7-b445-2102a282e0a2','火田鄭次山貧士也家有燕坐之處五爲賦之 槁木寮','陳文蔚','宋','宋诗','song-poetry','','[]','夜半一陽動，萬木總皆春。',24,'全唐诗/poet.song.173000.json','["夜半一陽動，萬木總皆春。", "當觀向榮意，從此識吾仁。"]'),
('027c55e6-3f8d-4e50-91ff-dbe905d2e4b2','火田鄭次山貧士也家有燕坐之處五爲賦之 歲寒谷','陳文蔚','宋','宋诗','song-poetry','','[]','中獨抱孤清，外示聊以朴。',24,'全唐诗/poet.song.173000.json','["中獨抱孤清，外示聊以朴。", "不結桃李交，風味良不惡。"]'),
('28d3689b-0233-4248-949c-afa6668af835','火田鄭次山貧士也家有燕坐之處五爲賦之 隠窩','陳文蔚','宋','宋诗','song-poetry','','[]','築室在澗阿，種木清成陰。',24,'全唐诗/poet.song.173000.json','["築室在澗阿，種木清成陰。", "中有聖人書，可以樂吾心。"]'),
('e3be1b06-6064-4eb3-bf82-46dda7287ff4','和賈元永醉楊妃','陳文蔚','宋','宋诗','song-poetry','','[]','當年開元主，得失鑒前迹。',48,'全唐诗/poet.song.173000.json','["當年開元主，得失鑒前迹。", "圖治極焦勞，自謂吾雖瘠。", "自從嬖在妾，乾坤輕一擲。", "妖花恐其魂，宜遠數百驛。"]'),
('571a0f07-3f89-4a57-9d37-a1555f17c51d','題鄭好古松圖和趙國興韵','陳文蔚','宋','宋诗','song-poetry','','[]','筆端老木千歲心，一見洗我塵土襟。',96,'全唐诗/poet.song.173000.json','["筆端老木千歲心，一見洗我塵土襟。", "坐久令人忘慍喜，古今碧澗落寒冰。", "乍濃乍淡陰復晴，晦明變化天所成。", "相畫之法如相士，骨奇肉瘦神必清。", "烟淡雲疏天冪冪，頃刻風雷暗塵壁。", "畫工羞看手如神，十日一水五日石。"]'),
('8666c778-a3cc-4301-8a6d-9e72176cade5','觀物二首  其一','陳文蔚','宋','宋诗','song-poetry','','[]','初見種汝時，微荄極枯槁。',48,'全唐诗/poet.song.173000.json','["初見種汝時，微荄極枯槁。", "今既長枝葉，日復一日好。", "儀刑靜獨秀，精神雨中澡。", "嗟我費耘治，尚媿窗前草。"]'),
('5d8dcec9-3099-4cec-8606-66a32f7bff5a','觀物二首  其二','陳文蔚','宋','宋诗','song-poetry','','[]','牆東一微物，妙意包藏深。',48,'全唐诗/poet.song.173000.json','["牆東一微物，妙意包藏深。", "人皆看枝葉，我獨觀其心。", "萌蘗既綿綿，茂盛亦駸駸。", "從此識天地，生生無古今。"]'),
('eb4ff232-f384-4cb9-be10-d0c87c072e7a','賈元永寄詩有窮愁之歎和韵寬之','陳文蔚','宋','宋诗','song-poetry','','[]','我生抱孤貞，有似窗前竹。',96,'全唐诗/poet.song.173000.json','["我生抱孤貞，有似窗前竹。", "却笑日用功，采綠不盈掬。", "詩書負宿願，發憤處幽獨。", "古人刮目處，論道不隔宿。", "吾計決已久，不疑何待卜。", "一書訊安否，雙魚勤往復。", "丈夫氣相許，雲雨詎翻覆。", "窮通付一醉，東鄰酒方熟。"]'),
('4c6c67fd-cd9f-4088-b865-8b0485253f9a','同彭漫者寄鉛山諸友韵送彭歸武夷','陳文蔚','宋','宋诗','song-poetry','','[]','兀坐誰與鄰，院古槐陰靜。',132,'全唐诗/poet.song.173000.json','["兀坐誰與鄰，院古槐陰靜。", "美人東南來，共此炎夏永。", "危衷慰孤清，羈迹不待屏。", "十載懷願見，一日良獨幸。", "開樽共有酌，當月免對影。", "所講根理致，坦然見心境。", "詮評寖及詩，語我挈裘領。", "云何方浩浩，遽爾中耿耿。", "歸理武夷棹，夢寐江南景。", "吾曹貴晚節，莫辭霜露冷。", "世事如予何，遺編且重整。"]'),
('d98a52a8-3f13-4a0e-ae3a-989d689a427a','辛亥春與陳周佐縣丞會於汭川旅邸從容三日臨別呈周佐','陳文蔚','宋','宋诗','song-poetry','','[]','雪夜訪戴時，未至已先返。',84,'全唐诗/poet.song.173000.json','["雪夜訪戴時，未至已先返。", "潘魏一夜話，興味良亦短。", "三日聆妙語，遠勝十年款。", "嗜欲排喧囂，議論反根本。", "酒罷放懷歌，超然心更遠。", "古人不難到，學力貴自勉。", "花柳况欣欣，游哉春未晚。"]'),
('0499793b-43a1-46a2-b654-94e809e8d071','再過桃花臺','陳文蔚','宋','宋诗','song-poetry','','[]','去年過桃花，心情亂飛絮。',132,'全唐诗/poet.song.173000.json','["去年過桃花，心情亂飛絮。", "今年重來時，烟水已成趣。", "川華動春綠，漁艇自來去。", "况復江上山，玉立美無度。", "徘徊欲吟詩，日暮不成賦。", "但見飛鳥歸，暝色带雲樹。", "我生亦何求，行止隨所寓。", "悠然此時心，但覺狎鷗鷺。", "風定波自平，可玩不可怖。", "堪嗟世間人，險阻起平路。", "茲焉得所圖，萬事不關慮。"]'),
('5debd505-6915-402b-be15-2a5cfdb82c19','寄題吳伯豐所居二首 讀書閣','陳文蔚','宋','宋诗','song-poetry','','[]','書閣高幾尋，其高不可知。',108,'全唐诗/poet.song.173000.json','["書閣高幾尋，其高不可知。", "但見讀書人，心與千古期。", "藉此閒曠地，端坐窮軒羲。", "世塵飛不到，月霽光風吹。", "况復揭扁榜，字畫天下奇。", "妙有指南處，世人那易窺。", "昔聞堂上聲，斲輪嘗笑之。", "而子得深省，不覺糟粕遺。", "終日几案樂，捨此歸其誰。"]'),
('b401e466-9d0d-4f91-8a21-423a9c68efdf','寄題吳伯豐所居二首 亦愛軒','陳文蔚','宋','宋诗','song-poetry','','[]','心兮如太虛，何惡亦何愛。',72,'全唐诗/poet.song.173000.json','["心兮如太虛，何惡亦何愛。", "吾廬寄吾興，妙處端有在。", "於中忘歲時，疇覺屢遷代。", "但知曲肱眠，居然樂其內。", "無事戶不出，此意誰能會。", "更約素心交，携書靜相對。"]'),
('fd253105-9cb2-4827-9576-d3dda7c18cd6','石井偶書呈同來者','陳文蔚','宋','宋诗','song-poetry','','[]','爲君半日留，得與諸賢集。',48,'全唐诗/poet.song.173000.json','["爲君半日留，得與諸賢集。", "人生貴遠游，何苦自維縶。", "好鳥鳴更幽，遠山青欲濕。", "時有午邊風，吹從木陰入。"]'),
('b340971a-5d79-4408-a780-2adccdbba31e','甲寅寒食日訪徐子融子融同出游晚歸誌所歷二十六韵','陳文蔚','宋','宋诗','song-poetry','','[]','至後一百五，春光正韶華。',288,'全唐诗/poet.song.173000.json','["至後一百五，春光正韶華。", "往往天氣少，多與人事差。", "今年特清朗，川原爛紅霞。", "埋頭卷書冊，訪友况不賒。", "盡日俱襄陽，滿城同看花。", "百種鬭紅紫，意氣各雄夸。", "忽焉有招呼，徑醉碧桃家。", "主人意厚甚，更約觀金沙。", "而我方與子，浩蕩興無涯。", "但恐催日馭，所幸未西斜。", "行行復行行，小築逢異葩。", "雜然不知名，品品亦自嘉。", "園翁旋相問，酌酒仍烹茶。", "珍重頗深簡，市井避喧譁。", "子乃若有告，未語先咨嗟。", "願言更出郭，前林路非遐。", "會當有奇遇，始信我不訛。", "果見山下蒙，一泓瑩無瑕。", "淵然蟠蛟龍，不爲藏黽蛙。", "稍稍出奇怪，羅列如髻丫。", "須臾聳嶄絕，煉不經女媧。", "特立如丈夫，匪可干以邪。", "相與發浩歎，題品乃未加。", "因念世沈晦，豈但如爾耶。"]'),
('26393318-8fa6-41e4-8b0e-88286ccfcca1','寒食後一日趙國興携具拉游清風峽登一覽亭分韵賦詩以塵埃已逐雙溪去爲韵得已字','陳文蔚','宋','宋诗','song-poetry','','[]','家家趁寒食，看花雒城裏。',84,'全唐诗/poet.song.173000.json','["家家趁寒食，看花雒城裏。", "孰知我輩人，屐去登山齒。", "千峰據其高，一覽無餘美。", "小溪山下來，青烟林末起。", "俯瞰闤闠居，總在塵埃底。", "灑樽遽移下，詩興良未已。", "因念讀書人，故事爲重紀。"]'),
('d3c0fabf-c752-4f1c-8b27-5de42d4b4f04','回鄭家橋小酌復以臨清流而賦詩爲韵得流字','陳文蔚','宋','宋诗','song-poetry','','[]','愧我困塵冗，因君得清游。',48,'全唐诗/poet.song.173000.json','["愧我困塵冗，因君得清游。", "脫身桃李場，慰彼林壑幽。", "水光晚更碧，山色翠欲流。", "詩情天萬里，浩蕩不可收。"]'),
('4fb926de-b4a2-4ebc-b18a-71e78ab68892','中秋後二夕陪趙連州飲荷香亭次連州韵','陳文蔚','宋','宋诗','song-poetry','','[]','使君今宵有高會，天爲好事收滂沱。',64,'全唐诗/poet.song.173000.json','["使君今宵有高會，天爲好事收滂沱。", "厭將歌舞競時好，只有風月爲詩魔。", "此際主勸客盡醉，何日弟和兄且歌。", "臺高林影散滿地，不飲奈此清光何。"]'),
('18543d54-f07f-4b7b-aea3-f4fc6f5c79a0','以花枝好處安詳折酒盞滿時撋就持爲韵贈徐子融','陳文蔚','宋','宋诗','song-poetry','','[]','春來凡草木，開處總成花。',288,'全唐诗/poet.song.173000.json','["春來凡草木，開處總成花。", "東皇本無心，世人徒爾夸。", "我愛花中王，矯矯出羣姿。", "非不愛桃李，桃李多繁枝。", "寄語折花人，半開花正好。", "折到離披時，翻成被花惱。", "花不在色香，全在精神處。", "不慣識花人，未肯輕分付。", "一夜無風雨，花枝報平安。", "折花須惜枝，容易莫傷殘。", "蘭薰可以佩，幽人擷其芳。", "紅紫時所競，安得細推詳。", "白面誰家郎，逢花便攀折。", "言會折花枝，折花人更別。", "麯糵有工夫，氣味獨醇厚。", "欲釀胸中春，豈可樽無酒。", "座上嘗春風，客來同把盞。", "妙處我獨知，醺然面生暖。", "淺深存斟酌，杯行不須滿。", "既滿須持之，不持懼招損。", "香液噴甕面，紅光浮滿巵。", "此爲最佳處，亦是極難時。", "杯深不可把，俯身爲渠撋。", "淋浪莫沾衣，操縱得其權。"]'),
('096eb39b-e7fc-41fc-82d7-d04ccffd5250','送趙進臣持閩憲節','陳文蔚','宋','宋诗','song-poetry','','[]','任官自古惟賢材，天子耳目寄外臺。',240,'全唐诗/poet.song.173000.json','["任官自古惟賢材，天子耳目寄外臺。", "祥刑所繫切民命，可不於此欽恤哉。", "猗嗟東南俗脆弱，獨有閩嶺高崔嵬。", "山川風氣頗相等，挾剛負險不可摧。", "自來巖谷多嘯聚，屢遣使者殲渠魁。", "今幸田里各安業，畢竟習俗懷陰猜。", "侵陵矯虔或未免，獄訟不平良善災。", "民强官弱亦已久，往往州縣翻低回。", "政須繡斧肅風采，坐使一方公道開。", "秋霜凜烈懲其姦，撲滅不復然死灰。", "陽和寬大布德意，撫摩窮困如嬰孩。", "湘江之水碧悠悠，使君昔日曾徘徊。", "于今八州復延頸，洗冤澤物須公來。", "澄清本是平生志，從此四境無氛埃。", "勿謂故園有松菊，長憶三徑荒莓苔。"]'),
('506e670f-c8dc-4898-8e72-8f8363f05c40','先生跋所藏湯君墨梅約諸人賦詩俾文蔚亦題其後','陳文蔚','宋','宋诗','song-poetry','','[]','皎皎冰雪姿，黯然宜水墨。',48,'全唐诗/poet.song.173000.json','["皎皎冰雪姿，黯然宜水墨。", "却恐施丹素，翻令涴顔色。", "孤山水雲深，庾嶺林月黑。", "晴窗一揮染，想像意俱得。"]'),
('3db47f02-86fe-42b0-a9c3-ff71731908a3','寄題吳子似所居二首 讀書亭','陳文蔚','宋','宋诗','song-poetry','','[]','古人不可見，千卷留遺編。',264,'全唐诗/poet.song.173000.json','["古人不可見，千卷留遺編。", "要非紙上語，至理實參前。", "列聖精微心，舍此將何傳。", "根本會於一，枝葉數萬千。", "博文可約禮，掘井志得泉。", "茲乃讀書旨，涵泳當忘年。", "勿以急迫求，留神嘗靜專。", "亦勿事悠悠，歲月空推遷。", "久而竟純熟，脫落不知然。", "衆理斯旁通，如海會百川。", "又如庖丁刀，體解牛無全。", "超然得我心，枘鑿非方圓。", "書在言語後，用起言語先。", "唐人資綴緝，漢儒拘訓箋。", "記誦日益博，疇知心鑑昏。", "祗足騁馳騖，與道實天淵。", "瑱山名亭意，難與世人言。", "方將屏俗慮，日夕親聖賢。", "見聞豈足道，孰是入德門。", "隠几無別事，真趣在窮研。", "一旦忽冰釋，花柳春無邊。", "此時案上書，始可付蹄筌。"]'),
('b0d96bc1-c561-4bac-a30f-39c89f69814e','寄題吳子似所居二首 經德堂','陳文蔚','宋','宋诗','song-poetry','','[]','上帝降斯民，厥初存秉彝。',240,'全唐诗/poet.song.173000.json','["上帝降斯民，厥初存秉彝。", "古昔世教明，大道行坦夷。", "裘葛順冬夏，飲食充渴饑。", "非有慕于外，夫婦皆與知。", "嶽瀆氣既分，民風日澆漓。", "仁義既榛塞，教化悲陵遲。", "隠然善端著，不勝姦僞滋。", "其至藉吾道，紛紛取世資。", "陽尊若示公，陰叛實濟私。", "孟氏極雄辯，剖晰精毫釐。", "言言七篇在，炳如日星垂。", "千載嗟晦蝕，大義誰復提。", "延陵有佳孫，好學謹操持。", "傳授有所自，源派分江西。", "若爲日用功，義利早辨之。", "細讀象山記，妙意良在茲。", "願言不爲穫，努力但耘耔。", "堂前有松桂，年年長柯枝。", "生意不自已，何心論報施。", "請子對佳木，長哦經德詩。"]'),
('88aaabe4-2eee-488e-b939-c649fcc0c975','送吳子似歸番陽','陳文蔚','宋','宋诗','song-poetry','','[]','憶昔舟泊雲錦溪，溪上故人知爲誰。',64,'全唐诗/poet.song.173000.json','["憶昔舟泊雲錦溪，溪上故人知爲誰。", "讀書亭中不草草，永平人物入深討。", "生平藉甚梅子真，我乃晚遇情相親。", "古人事業貴悠久，歸歟訪我同門友。"]'),
('adef1041-30e9-4a1c-9ef4-0d4f2a4a1840','和葉仲洽喜雨','陳文蔚','宋','宋诗','song-poetry','','[]','一旱不問下與高，風吹日炙同煎熬。',272,'全唐诗/poet.song.173000.json','["一旱不問下與高，風吹日炙同煎熬。", "悲鳴鴻雁不飲啄，向人終日聲嗷嗷。", "千里赤地天不管，毫髮微功矜桔槔。", "乘除自古有成說，霖潦一春多發洩。", "渴苗欲死俟沾溉，到此翻令成澤竭。", "不眠耿耿抱幽恨，離畢中宵起占月。", "仰天浩嘆如何理，引手欲挽天河水。", "鵝湖作鎮縣東隅，山巔忽有雲峰起。", "朝隮何事故要勒，雨未崇朝還又止。", "農家與苗相爲命，情不願蘇惟願死。", "愁腸欲斷成寸寸，頃刻風雷驚動散。", "爲霖三日澤已均，潑墨千山雲不斷。", "騷人賦詩喜欲狂，自寫長牋幾脫腕。", "東西倒懸今少解，歡情隨雨亦滂沛。", "祇愁西北望雲霓，腥羶久矣爲民害。", "請看麟史書伐邢，一日興師當問罪。", "詩成聊寫閔雨志，𤱶畝拳拳有深愛。"]'),
('a700ae4a-de21-406a-9093-77ee0e093481','題傅巖叟悠然閣三章章八句  其一','陳文蔚','宋','宋诗','song-poetry','','[]','悠然君之見，不與凡見同。',48,'全唐诗/poet.song.173000.json','["悠然君之見，不與凡見同。", "正似東籬下，山忽在眼中。", "誰昔夜登閣，歌罷飲亦終。", "恍若有真契，可知不可窮。"]'),
('4716c9c9-6e77-4a64-9df6-bbe28a5f6b27','題傅巖叟悠然閣三章章八句  其二','陳文蔚','宋','宋诗','song-poetry','','[]','悠然閣之名，名從見中起。',48,'全唐诗/poet.song.173000.json','["悠然閣之名，名從見中起。", "長哦好仁詩，高山勤仰止。", "意與口俱到，掘井真得水。", "嗟哉世間人，穿鑿求義理。"]'),
('f9de3f07-f3bf-4a07-8e2f-612501cecd23','題傅巖叟悠然閣三章章八句  其三','陳文蔚','宋','宋诗','song-poetry','','[]','悠然君之心，非古亦非今。',48,'全唐诗/poet.song.173000.json','["悠然君之心，非古亦非今。", "忘言猶有詩，無弦安用琴。", "淵明此時意，千載無知音。", "但見登閣時，山高白雲深。"]'),
('76f6a0e2-c472-4ba9-aae6-d775ffdb9395','廬山雜咏 棲賢三峽橋','陳文蔚','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我來未試烹茶水，且讀石上涪翁詩。',64,'全唐诗/poet.song.173000.json','["我來未試烹茶水，且讀石上涪翁詩。", "上卧百尺晴蝃蝀，下貯一匣青玻璃。", "淵深知是蛟龍宅，風怒似挾熊虎威。", "自古賢棲知幾許，今有精藍藏翠微。"]'),
('e5ee8e70-d295-412d-a6be-aa972955e331','廬山雜咏 天池','陳文蔚','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','朝登天池峰，暮酌天池水。',240,'全唐诗/poet.song.173000.json','["朝登天池峰，暮酌天池水。", "一枕僧榻清，鍾磬半空裏。", "平生此名山，籍籍滿吾耳。", "乘興作遠游，杖策自不已。", "行行到絕頂，塵世知隔幾。", "雲烟出其下，渺視猶萬里。", "山川與人物，往往盡蒙被。", "始疑翻雪濤，混同一彭蠡。", "頃刻開一罅，初見山邐迤。", "仿佛人世界，未可詳目指。", "山中爲予言，此地去天咫。", "風雨晦冥候，與世殊不似。", "霖潦方下作，山頭旋磨蟻。", "雲深此埋屋，山下乃不爾。", "歷驗予所言，其言亦非詭。", "未必隔仙凡，高深實殊軌。", "初夜現佛燈，數星林末起。", "如螢復如炬，或明亦或止。", "昔聞頗甚怪，今見乃如此。", "寄語登山人，仍須細窮理。"]'),
('3d0255a6-22dd-4eae-813a-2245f5cced5d','白鹿洞謁先生祠堂呈李夢開教授是日李入洞講書','陳文蔚','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','先師紫陽翁，雅愛窮幽微。',288,'全唐诗/poet.song.173000.json','["先師紫陽翁，雅愛窮幽微。", "前賢有遺跡，所至皆發揮。", "千古廬山高，白鹿遇亦希。", "何人實經始，閟藏啟天機。", "臨流勘書臺，隠然釣魚磯。", "聖朝始加賁，泉石生光輝。", "榛莽百年中，潛長虎豹威。", "衣冠固不論，樵牧亦寥稀。", "今昔有顯晦，山川無是非。", "先生適剖竹，按圖重歔欷。", "斬荆得遺址，澗繞山合圍。", "買田敞堂塾，豈將終遁肥。", "學子共棲集，相與詠而歸。", "繼聖講絕學，咳唾落珠璣。", "此理忽森著，魚鳶真躍飛。", "小子恨晚遇，講席弔及依。", "升堂拜遺像，泫然涕沾衣。", "幸今主盟人，高識可與幾。", "光風霽月意，端欲賢聖希。", "時來一講訂，諸生佩弦韋。", "超然此會意，規範喜無違。", "徘徊不忍去，暮宿留山扉。", "因極昔游處，恍如身泗沂。", "矧復洞中友，進步方騑騑。"]'),
('5a0ac0b4-798b-42ac-89ea-4d4262537f31','卧龍瀑布','陳文蔚','宋','宋诗','song-poetry','','[]','登陟百險艱，來看雲間瀑。',48,'全唐诗/poet.song.173000.json','["登陟百險艱，來看雲間瀑。", "飛從千仞峰，瀉作一條玉。", "冬夏有盈縮，古今無斷續。", "當日武夷翁，翩然來結屋。"]'),
('3a7131d3-552d-4152-87a6-4ff79c1a68e8','武侯像','陳文蔚','宋','宋诗','song-poetry','','[]','堂堂千載人，遺像凜如生。',48,'全唐诗/poet.song.173000.json','["堂堂千載人，遺像凜如生。", "趨舍同一操，豈無當代英。", "欲喚卧龍起，四海盲聾驚。", "此意無今昨，未應歸杳冥。"]'),
('4287ce23-b589-458d-b165-f82b09eceba1','新居六詠 竹林隠居','陳文蔚','宋','宋诗','song-poetry','','[]','無才濟蒼生，竹林遠棲遁。',24,'全唐诗/poet.song.173000.json','["無才濟蒼生，竹林遠棲遁。", "中有聖人書，飯蔬自無悶。"]'),
('3674568c-0e0e-42f5-a6c4-ed5645875dab','新居六詠 花堤','陳文蔚','宋','宋诗','song-poetry','','[]','築堤環碧沼，種花仍滿堤。',24,'全唐诗/poet.song.173000.json','["築堤環碧沼，種花仍滿堤。", "幽人日往來，非關桃李蹊。"]'),
('ccc7a8dc-5b06-4919-a9c2-041b539104a3','新居六詠 半月池','陳文蔚','宋','宋诗','song-poetry','','[]','池東如月弦，池西如月弓。',24,'全唐诗/poet.song.173000.json','["池東如月弦，池西如月弓。", "池北千丈屏，倒影碧波中。"]'),
('2469c5e3-845d-4ef7-a8fb-e9480e35f1da','新居六詠 曲水','陳文蔚','宋','宋诗','song-poetry','','[]','清溝知幾曲，花落流紅錦。',24,'全唐诗/poet.song.173000.json','["清溝知幾曲，花落流紅錦。", "何須浮羽觴，自可供杯飲。"]'),
('f03f0912-40c2-4bda-bb12-6a5d75222606','新居六詠 克齋','陳文蔚','宋','宋诗','song-poetry','','[]','燕坐焚清香，日永裊烟篆。',24,'全唐诗/poet.song.173000.json','["燕坐焚清香，日永裊烟篆。", "妙處良獨知，功收物欲戰。"]'),
('0644e4e9-b319-4c0e-a8f0-fd8efec78324','新居六詠 梅窗','陳文蔚','宋','宋诗','song-poetry','','[]','綠陰初散地，今有入簷枝。',24,'全唐诗/poet.song.173000.json','["綠陰初散地，今有入簷枝。", "開窗對瀟灑，歲寒惟獨知。"]'),
('6c228a0b-ea34-45bb-b234-6ac601937858','五月十二日閒中偶作','陳文蔚','宋','宋诗','song-poetry','','[]','黄卷與晤對，日日有新聞。',96,'全唐诗/poet.song.173000.json','["黄卷與晤對，日日有新聞。", "青山不世情，時時有佳賓。", "不動利害心，且無將迎勤。", "自得村童樂，何須市朝紛。", "種菊繞庭砌，黄花俟秋芬。", "琴書便當歸，免使思白雲。", "犂鋤理荒穢，菽水娛朝昏。", "此外何所慕，甘作耕桑民。"]'),
('55f78b53-9522-4820-ac8f-ae256ae63229','徐天錫歸自玉山昌甫以三詩送之後二篇有及予與徐子融傅巖叟之意且托其轉寄答其意以謝之  其一','陳文蔚','宋','宋诗','song-poetry','','[]','我聞章泉清，有客日洗耳。',96,'全唐诗/poet.song.173000.json','["我聞章泉清，有客日洗耳。", "而况坦腹眠，滿意得佳士。", "相期忘歲月，飽飯讀書史。", "祇恐翁獨吟，黄鵠舉千里。", "靜言同門友，吾郡差若多。", "相望數舍隔，便如千里賒。", "惟有湖上翁，時時許相過。", "比緣迹萍梗，亦已廢琢磨。"]'),
('0529b52f-aebe-4f34-9bb3-37a6fecade8c','徐天錫歸自玉山昌甫以三詩送之後二篇有及予與徐子融傅巖叟之意且托其轉寄答其意以謝之  其二','陳文蔚','宋','宋诗','song-poetry','','[]','曾共傅巖孫，同坐傅巖石。',48,'全唐诗/poet.song.173000.json','["曾共傅巖孫，同坐傅巖石。", "紀游未抄寄，雙梅解相憶。", "天涯思美人，折花陡岑寂。", "所幸柱上題，如新未陳迹。"]');
